package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.fakeplayer.PathfindingService;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;

import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.phys.AABB;
import net.minecraft.world.phys.EntityHitResult;
import net.minecraft.world.phys.Vec3;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Player;

import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * /fpp attack &lt;bot|all&gt; [--once|--stop]  |  --stop
 *
 * <p>Walks the bot to the command sender's position, then continuously faces where the sender is
 * looking and attacks the entity in that direction — respecting the held item's attack-speed
 * attribute and any active item cooldowns (shields, ender pearls, etc.) for realistic 1.9+ combat.
 */
public final class AttackCommand implements FppCommand {

    private final FakePlayerPlugin plugin;
    private final FakePlayerManager manager;
    private final PathfindingService pathfinding;

    /** Bukkit task IDs for the per-bot attack loops. */
    private final Map<UUID, Integer> attackTasks = new ConcurrentHashMap<>();

    /** Lock location per bot (persisted across restarts). */
    private final Map<UUID, Location> activeAttackLocations = new ConcurrentHashMap<>();

    /** Whether the bot should stop after the first successful hit. */
    private final Map<UUID, Boolean> activeAttackOnceFlags = new ConcurrentHashMap<>();

    /**
     * UUID of the player who started the attack — used to mirror their look direction each tick so
     * the bot always aims where the sender is currently looking.
     */
    private final Map<UUID, UUID> attackSenders = new ConcurrentHashMap<>();

    public AttackCommand(
            FakePlayerPlugin plugin, FakePlayerManager manager, PathfindingService pathfinding) {
        this.plugin = plugin;
        this.manager = manager;
        this.pathfinding = pathfinding;
    }

    // ── FppCommand ────────────────────────────────────────────────────────────

    @Override
    public String getName() {
        return "attack";
    }

    @Override
    public String getUsage() {
        return "<bot|all> [--once|--stop]  |  --stop";
    }

    @Override
    public String getDescription() {
        return "Walk a bot to your position then attack what it's looking at.";
    }

    @Override
    public String getPermission() {
        return Perm.ATTACK;
    }

    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.ATTACK);
    }

    // ── execute ───────────────────────────────────────────────────────────────

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("attack-usage"));
            return true;
        }

        // /fpp attack stop  OR  /fpp attack --stop  → stop all
        if (args.length == 1
                && (args[0].equalsIgnoreCase("stop") || args[0].equalsIgnoreCase("--stop"))) {
            stopAll();
            sender.sendMessage(Lang.get("attack-stopped-all"));
            return true;
        }

        String botName = args[0];
        boolean once =
                args.length >= 2
                        && (args[1].equalsIgnoreCase("once")
                                || args[1].equalsIgnoreCase("--once"));
        boolean stop =
                args.length >= 2
                        && (args[1].equalsIgnoreCase("stop")
                                || args[1].equalsIgnoreCase("--stop"));

        // ── "all" target ──────────────────────────────────────────────────────
        if (botName.equalsIgnoreCase("all")) {
            if (stop) {
                stopAll();
                sender.sendMessage(Lang.get("attack-stopped-all"));
                return true;
            }
            int count = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) continue;
                startForBot(sender, fp, once);
                count++;
            }
            if (count == 0) sender.sendMessage(Lang.get("attack-no-bots"));
            return true;
        }

        // ── single bot ────────────────────────────────────────────────────────
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("attack-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("attack-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        if (stop) {
            cancelAll(fp.getUuid());
            sender.sendMessage(Lang.get("attack-stopped", "name", fp.getDisplayName()));
            return true;
        }

        startForBot(sender, fp, once);

        // feedback depends on whether navigation is needed
        if (sender instanceof Player sp) {
            double xzDist = PathfindingService.xzDist(bot.getLocation(), sp.getLocation());
            if (xzDist <= Config.pathfindingArrivalDistance()) {
                sender.sendMessage(
                        once
                                ? Lang.get("attack-started-once", "name", fp.getDisplayName())
                                : Lang.get("attack-started", "name", fp.getDisplayName()));
            } else {
                sender.sendMessage(Lang.get("attack-walking", "name", fp.getDisplayName()));
            }
        } else {
            sender.sendMessage(
                    once
                            ? Lang.get("attack-started-once", "name", fp.getDisplayName())
                            : Lang.get("attack-started", "name", fp.getDisplayName()));
        }

        return true;
    }

    // ── tabComplete ───────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("--stop".startsWith(prefix)) out.add("--stop");
            if ("stop".startsWith(prefix)) out.add("stop");
            if ("all".startsWith(prefix)) out.add("all");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(prefix)) out.add(fp.getName());
            return out;
        }

        if (args.length == 2
                && !args[0].equalsIgnoreCase("stop")
                && !args[0].equalsIgnoreCase("--stop")) {
            String prefix = args[1].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("--once".startsWith(prefix)) out.add("--once");
            if ("--stop".startsWith(prefix)) out.add("--stop");
            if ("once".startsWith(prefix)) out.add("once");
            if ("stop".startsWith(prefix)) out.add("stop");
            return out;
        }

        return List.of();
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    private void startForBot(CommandSender sender, FakePlayer fp, boolean once) {
        Player bot = fp.getPlayer();
        if (bot == null) return;

        Location dest =
                (sender instanceof Player sp)
                        ? sp.getLocation().clone()
                        : bot.getLocation().clone();

        UUID senderUuid = (sender instanceof Player sp) ? sp.getUniqueId() : null;

        cancelAll(fp.getUuid());

        if (senderUuid != null) attackSenders.put(fp.getUuid(), senderUuid);

        double xzDist = PathfindingService.xzDist(bot.getLocation(), dest);
        if (xzDist <= Config.pathfindingArrivalDistance()) {
            lockAndStartAttacking(fp, once, dest);
        } else {
            startNavigation(fp, once, dest);
        }
    }

    private void startNavigation(FakePlayer fp, boolean once, Location dest) {
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.ATTACK,
                        () -> dest,
                        Config.pathfindingArrivalDistance(),
                        0.0,
                        Integer.MAX_VALUE,
                        () -> lockAndStartAttacking(fp, once, dest),
                        null,
                        null));
    }

    private void lockAndStartAttacking(FakePlayer fp, boolean once, Location lockLoc) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        bot.teleport(lockLoc);
        manager.lockForAction(uuid, lockLoc);

        activeAttackLocations.put(uuid, lockLoc.clone());
        activeAttackOnceFlags.put(uuid, once);

        int taskId =
                Bukkit.getScheduler()
                        .runTaskTimer(
                                plugin,
                                () -> tickAttack(fp, uuid, once),
                                0L,
                                1L)
                        .getTaskId();

        attackTasks.put(uuid, taskId);
    }

    /**
     * Called every tick while the attack loop is active.
     *
     * <ol>
     *   <li>Sanity-check bot is online.
     *   <li>Mirror the sender's look direction so the bot always aims where the player is looking.
     *   <li>Gate on item cooldown (shields, ender pearls, etc.).
     *   <li>Gate on attack-strength scale (weapon attack speed — 0.0 = just hit, 1.0 = fully
     *       charged). Only attack at ≥ 0.9 to feel natural, like a real player.
     *   <li>Ray-trace for the nearest attackable entity in the bot's look direction.
     *   <li>Swing arm + perform attack (which also resets the internal cooldown ticker).
     * </ol>
     */
    private void tickAttack(FakePlayer fp, UUID uuid, boolean once) {
        Player b = fp.getPlayer();
        if (b == null || !b.isOnline()) {
            stopAttacking(uuid);
            return;
        }

        ServerPlayer nms = ((CraftPlayer) b).getHandle();

        // 1. Mirror sender's look direction
        UUID senderUuid = attackSenders.get(uuid);
        if (senderUuid != null) {
            Player senderPlayer = Bukkit.getPlayer(senderUuid);
            if (senderPlayer != null && senderPlayer.isOnline()) {
                ServerPlayer senderNms = ((CraftPlayer) senderPlayer).getHandle();
                nms.setYRot(senderNms.getYRot());
                nms.setXRot(senderNms.getXRot());
                nms.yHeadRot = senderNms.getYHeadRot();
            }
        }

        // 2. Item-specific cooldown check (shields, ender pearls, chorus fruit, etc.)
        var mainHandItem = nms.getItemInHand(InteractionHand.MAIN_HAND);
        if (nms.getCooldowns().isOnCooldown(mainHandItem.getItem())) {
            return;
        }

        // 3. Weapon attack-speed cooldown — only strike when ≥ 90 % charged.
        //    getAttackStrengthScale() reads the internal attackStrengthTicker against
        //    the item's attack_speed attribute, so this is fully dynamic: swords ~12 ticks,
        //    axes ~20 ticks, bare fists ~5 ticks, etc. No hardcoded intervals needed.
        if (nms.getAttackStrengthScale(0f) < 0.9f) {
            return;
        }

        // 4. Ray-trace for an attackable entity in look direction
        EntityHitResult entityHit = rayTraceForEntity(nms);
        if (entityHit == null) {
            // No target in range — do nothing this tick (don't spam swing-at-air)
            return;
        }

        var nmsEntity = entityHit.getEntity();
        org.bukkit.entity.Entity bukkit = nmsEntity.getBukkitEntity();

        // Skip other FPP bots (don't let bots attack each other)
        if (manager.getByUuid(bukkit.getUniqueId()) != null) return;

        // 5. Swing arm first for client-side animation, then attack
        nms.swing(InteractionHand.MAIN_HAND);

        // NmsPlayerSpawner.performAttack calls the NMS ServerPlayer.attack(Entity) method,
        // which handles damage calculation, knockback, crits, enchantments, and — crucially —
        // resets the attackStrengthTicker to 0, so the next swing is naturally delayed.
        NmsPlayerSpawner.performAttack(b, bukkit, 0);

        if (once) {
            stopAttacking(uuid);
        }
    }

    /** Cancel navigation + attack loop for one bot. */
    private void cancelAll(UUID botUuid) {
        pathfinding.cancel(botUuid);
        stopAttacking(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    // ── Public API ────────────────────────────────────────────────────────────

    /** Cancels the attack loop (if any) and releases the action lock for {@code botUuid}. */
    public void stopAttacking(UUID botUuid) {
        Integer taskId = attackTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockAction(botUuid);

        activeAttackLocations.remove(botUuid);
        activeAttackOnceFlags.remove(botUuid);
        attackSenders.remove(botUuid);
    }

    /** Stops all active attack loops and cancels any navigation under {@link PathfindingService.Owner#ATTACK}. */
    public void stopAll() {
        pathfinding.cancelAll(PathfindingService.Owner.ATTACK);
        new HashSet<>(attackTasks.keySet()).forEach(this::cancelAll);
    }

    public boolean isAttacking(UUID botUuid) {
        return attackTasks.containsKey(botUuid);
    }

    public boolean isNavigating(UUID botUuid) {
        return pathfinding.isNavigating(botUuid, PathfindingService.Owner.ATTACK);
    }

    @Nullable
    public Location getActiveAttackLocation(UUID botUuid) {
        return activeAttackLocations.get(botUuid);
    }

    public boolean isActiveAttackOnce(UUID botUuid) {
        Boolean v = activeAttackOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Restores attack mode after a server restart. Navigates to {@code loc} first if needed,
     * then resumes the attack loop. Called by {@code BotPersistence} during the restore chain.
     */
    public void resumeAttacking(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        if (PathfindingService.xzDist(bot.getLocation(), loc) <= Config.pathfindingArrivalDistance()) {
            lockAndStartAttacking(fp, once, loc);
        } else {
            startNavigation(fp, once, loc);
        }
    }

    // ── Ray-trace helper ──────────────────────────────────────────────────────

    /**
     * Performs a ray-trace from the bot's eyes in its look direction and returns the first
     * attackable entity within reach, or {@code null} if the line is clear.
     *
     * <p>Uses {@link net.minecraft.world.entity.Entity#isAttackable()} instead of
     * {@link net.minecraft.world.entity.Entity#isPickable()} so only entities that can actually
     * take damage are targeted (excludes item frames, marker armour stands, etc.).
     */
    @SuppressWarnings("resource")
    @Nullable
    private static EntityHitResult rayTraceForEntity(ServerPlayer player) {
        double reach = player.gameMode.isCreative() ? 5.0 : 4.5;
        Vec3 eyePos  = player.getEyePosition(1.0f);
        Vec3 viewVec = player.getViewVector(1.0f);
        Vec3 endPos  = eyePos.add(viewVec.x * reach, viewVec.y * reach, viewVec.z * reach);

        AABB searchBox =
                player.getBoundingBox().expandTowards(viewVec.scale(reach)).inflate(1.0);

        EntityHitResult best    = null;
        double          bestSq  = reach * reach;

        for (var entity :
                player.level()
                        .getEntities(
                                player,
                                searchBox,
                                e -> !e.isSpectator() && e.isAttackable())) {

            AABB box    = entity.getBoundingBox().inflate(entity.getPickRadius());
            var  hitOpt = box.clip(eyePos, endPos);

            if (box.contains(eyePos)) {
                if (bestSq >= 0) {
                    best   = new EntityHitResult(entity, hitOpt.orElse(eyePos));
                    bestSq = 0;
                }
            } else if (hitOpt.isPresent()) {
                double d = eyePos.distanceToSqr(hitOpt.get());
                if (d < bestSq) {
                    best   = new EntityHitResult(entity, hitOpt.get());
                    bestSq = d;
                }
            }
        }

        return best;
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.fakeplayer.PathfindingService;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;

import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.phys.AABB;
import net.minecraft.world.phys.EntityHitResult;
import net.minecraft.world.phys.Vec3;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Player;

import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * /fpp attack &lt;bot|all&gt; [--once|--stop]  |  --stop
 *
 * <p>Walks the bot to the command sender's position, then continuously faces where the sender is
 * looking and attacks the entity in that direction — respecting the held item's attack-speed
 * attribute and any active item cooldowns (shields, ender pearls, etc.) for realistic 1.9+ combat.
 */
public final class AttackCommand implements FppCommand {

    private final FakePlayerPlugin plugin;
    private final FakePlayerManager manager;
    private final PathfindingService pathfinding;

    /** Bukkit task IDs for the per-bot attack loops. */
    private final Map<UUID, Integer> attackTasks = new ConcurrentHashMap<>();

    /** Lock location per bot (persisted across restarts). */
    private final Map<UUID, Location> activeAttackLocations = new ConcurrentHashMap<>();

    /** Whether the bot should stop after the first successful hit. */
    private final Map<UUID, Boolean> activeAttackOnceFlags = new ConcurrentHashMap<>();

    /**
     * UUID of the player who started the attack — used to mirror their look direction each tick so
     * the bot always aims where the sender is currently looking.
     */
    private final Map<UUID, UUID> attackSenders = new ConcurrentHashMap<>();

    public AttackCommand(
            FakePlayerPlugin plugin, FakePlayerManager manager, PathfindingService pathfinding) {
        this.plugin = plugin;
        this.manager = manager;
        this.pathfinding = pathfinding;
    }

    // ── FppCommand ────────────────────────────────────────────────────────────

    @Override
    public String getName() {
        return "attack";
    }

    @Override
    public String getUsage() {
        return "<bot|all> [--once|--stop]  |  --stop";
    }

    @Override
    public String getDescription() {
        return "Walk a bot to your position then attack what it's looking at.";
    }

    @Override
    public String getPermission() {
        return Perm.ATTACK;
    }

    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.ATTACK);
    }

    // ── execute ───────────────────────────────────────────────────────────────

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("attack-usage"));
            return true;
        }

        // /fpp attack stop  OR  /fpp attack --stop  → stop all
        if (args.length == 1
                && (args[0].equalsIgnoreCase("stop") || args[0].equalsIgnoreCase("--stop"))) {
            stopAll();
            sender.sendMessage(Lang.get("attack-stopped-all"));
            return true;
        }

        String botName = args[0];
        boolean once =
                args.length >= 2
                        && (args[1].equalsIgnoreCase("once")
                                || args[1].equalsIgnoreCase("--once"));
        boolean stop =
                args.length >= 2
                        && (args[1].equalsIgnoreCase("stop")
                                || args[1].equalsIgnoreCase("--stop"));

        // ── "all" target ──────────────────────────────────────────────────────
        if (botName.equalsIgnoreCase("all")) {
            if (stop) {
                stopAll();
                sender.sendMessage(Lang.get("attack-stopped-all"));
                return true;
            }
            int count = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) continue;
                startForBot(sender, fp, once);
                count++;
            }
            if (count == 0) sender.sendMessage(Lang.get("attack-no-bots"));
            return true;
        }

        // ── single bot ────────────────────────────────────────────────────────
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("attack-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("attack-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        if (stop) {
            cancelAll(fp.getUuid());
            sender.sendMessage(Lang.get("attack-stopped", "name", fp.getDisplayName()));
            return true;
        }

        startForBot(sender, fp, once);

        // feedback depends on whether navigation is needed
        if (sender instanceof Player sp) {
            double xzDist = PathfindingService.xzDist(bot.getLocation(), sp.getLocation());
            if (xzDist <= Config.pathfindingArrivalDistance()) {
                sender.sendMessage(
                        once
                                ? Lang.get("attack-started-once", "name", fp.getDisplayName())
                                : Lang.get("attack-started", "name", fp.getDisplayName()));
            } else {
                sender.sendMessage(Lang.get("attack-walking", "name", fp.getDisplayName()));
            }
        } else {
            sender.sendMessage(
                    once
                            ? Lang.get("attack-started-once", "name", fp.getDisplayName())
                            : Lang.get("attack-started", "name", fp.getDisplayName()));
        }

        return true;
    }

    // ── tabComplete ───────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("--stop".startsWith(prefix)) out.add("--stop");
            if ("stop".startsWith(prefix)) out.add("stop");
            if ("all".startsWith(prefix)) out.add("all");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(prefix)) out.add(fp.getName());
            return out;
        }

        if (args.length == 2
                && !args[0].equalsIgnoreCase("stop")
                && !args[0].equalsIgnoreCase("--stop")) {
            String prefix = args[1].toLowerCase();
            List<String> out = new ArrayList<>();
            if ("--once".startsWith(prefix)) out.add("--once");
            if ("--stop".startsWith(prefix)) out.add("--stop");
            if ("once".startsWith(prefix)) out.add("once");
            if ("stop".startsWith(prefix)) out.add("stop");
            return out;
        }

        return List.of();
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    private void startForBot(CommandSender sender, FakePlayer fp, boolean once) {
        Player bot = fp.getPlayer();
        if (bot == null) return;

        Location dest =
                (sender instanceof Player sp)
                        ? sp.getLocation().clone()
                        : bot.getLocation().clone();

        UUID senderUuid = (sender instanceof Player sp) ? sp.getUniqueId() : null;

        cancelAll(fp.getUuid());

        if (senderUuid != null) attackSenders.put(fp.getUuid(), senderUuid);

        double xzDist = PathfindingService.xzDist(bot.getLocation(), dest);
        if (xzDist <= Config.pathfindingArrivalDistance()) {
            lockAndStartAttacking(fp, once, dest);
        } else {
            startNavigation(fp, once, dest);
        }
    }

    private void startNavigation(FakePlayer fp, boolean once, Location dest) {
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.ATTACK,
                        () -> dest,
                        Config.pathfindingArrivalDistance(),
                        0.0,
                        Integer.MAX_VALUE,
                        () -> lockAndStartAttacking(fp, once, dest),
                        null,
                        null));
    }

    private void lockAndStartAttacking(FakePlayer fp, boolean once, Location lockLoc) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        bot.teleport(lockLoc);
        manager.lockForAction(uuid, lockLoc);

        activeAttackLocations.put(uuid, lockLoc.clone());
        activeAttackOnceFlags.put(uuid, once);

        int taskId =
                Bukkit.getScheduler()
                        .runTaskTimer(
                                plugin,
                                () -> tickAttack(fp, uuid, once),
                                0L,
                                1L)
                        .getTaskId();

        attackTasks.put(uuid, taskId);
    }

    /**
     * Called every tick while the attack loop is active.
     *
     * <ol>
     *   <li>Sanity-check bot is online.
     *   <li>Mirror the sender's look direction so the bot always aims where the player is looking.
     *   <li>Gate on item cooldown (shields, ender pearls, etc.).
     *   <li>Gate on attack-strength scale (weapon attack speed — 0.0 = just hit, 1.0 = fully
     *       charged). Only attack at ≥ 0.9 to feel natural, like a real player.
     *   <li>Ray-trace for the nearest attackable entity in the bot's look direction.
     *   <li>Swing arm + perform attack (which also resets the internal cooldown ticker).
     * </ol>
     */
    private void tickAttack(FakePlayer fp, UUID uuid, boolean once) {
        Player b = fp.getPlayer();
        if (b == null || !b.isOnline()) {
            stopAttacking(uuid);
            return;
        }

        ServerPlayer nms = ((CraftPlayer) b).getHandle();

        // 1. Mirror sender's look direction
        UUID senderUuid = attackSenders.get(uuid);
        if (senderUuid != null) {
            Player senderPlayer = Bukkit.getPlayer(senderUuid);
            if (senderPlayer != null && senderPlayer.isOnline()) {
                ServerPlayer senderNms = ((CraftPlayer) senderPlayer).getHandle();
                nms.setYRot(senderNms.getYRot());
                nms.setXRot(senderNms.getXRot());
                nms.yHeadRot = senderNms.getYHeadRot();
            }
        }

        // 2. Item-specific cooldown check (shields, ender pearls, chorus fruit, etc.)
        var mainHandItem = nms.getItemInHand(InteractionHand.MAIN_HAND);
        if (nms.getCooldowns().isOnCooldown(mainHandItem)) {
            return;
        }

        // 3. Weapon attack-speed cooldown — only strike when ≥ 90 % charged.
        //    getAttackStrengthScale() reads the internal attackStrengthTicker against
        //    the item's attack_speed attribute, so this is fully dynamic: swords ~12 ticks,
        //    axes ~20 ticks, bare fists ~5 ticks, etc. No hardcoded intervals needed.
        if (nms.getAttackStrengthScale(0f) < 0.9f) {
            return;
        }

        // 4. Ray-trace for an attackable entity in look direction
        EntityHitResult entityHit = rayTraceForEntity(nms);
        if (entityHit == null) {
            // No target in range — do nothing this tick (don't spam swing-at-air)
            return;
        }

        var nmsEntity = entityHit.getEntity();
        org.bukkit.entity.Entity bukkit = nmsEntity.getBukkitEntity();

        // Skip other FPP bots (don't let bots attack each other)
        if (manager.getByUuid(bukkit.getUniqueId()) != null) return;

        // 5. Swing arm first for client-side animation, then attack
        nms.swing(InteractionHand.MAIN_HAND);

        // NmsPlayerSpawner.performAttack calls the NMS ServerPlayer.attack(Entity) method,
        // which handles damage calculation, knockback, crits, enchantments, and — crucially —
        // resets the attackStrengthTicker to 0, so the next swing is naturally delayed.
        NmsPlayerSpawner.performAttack(b, bukkit, 0);

        if (once) {
            stopAttacking(uuid);
        }
    }

    /** Cancel navigation + attack loop for one bot. */
    private void cancelAll(UUID botUuid) {
        pathfinding.cancel(botUuid);
        stopAttacking(botUuid);

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    // ── Public API ────────────────────────────────────────────────────────────

    /** Cancels the attack loop (if any) and releases the action lock for {@code botUuid}. */
    public void stopAttacking(UUID botUuid) {
        Integer taskId = attackTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockAction(botUuid);

        activeAttackLocations.remove(botUuid);
        activeAttackOnceFlags.remove(botUuid);
        attackSenders.remove(botUuid);
    }

    /** Stops all active attack loops and cancels any navigation under {@link PathfindingService.Owner#ATTACK}. */
    public void stopAll() {
        pathfinding.cancelAll(PathfindingService.Owner.ATTACK);
        new HashSet<>(attackTasks.keySet()).forEach(this::cancelAll);
    }

    public boolean isAttacking(UUID botUuid) {
        return attackTasks.containsKey(botUuid);
    }

    public boolean isNavigating(UUID botUuid) {
        return pathfinding.isNavigating(botUuid, PathfindingService.Owner.ATTACK);
    }

    @Nullable
    public Location getActiveAttackLocation(UUID botUuid) {
        return activeAttackLocations.get(botUuid);
    }

    public boolean isActiveAttackOnce(UUID botUuid) {
        Boolean v = activeAttackOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Restores attack mode after a server restart. Navigates to {@code loc} first if needed,
     * then resumes the attack loop. Called by {@code BotPersistence} during the restore chain.
     */
    public void resumeAttacking(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        if (PathfindingService.xzDist(bot.getLocation(), loc) <= Config.pathfindingArrivalDistance()) {
            lockAndStartAttacking(fp, once, loc);
        } else {
            startNavigation(fp, once, loc);
        }
    }

    // ── Ray-trace helper ──────────────────────────────────────────────────────

    /**
     * Performs a ray-trace from the bot's eyes in its look direction and returns the first
     * attackable entity within reach, or {@code null} if the line is clear.
     *
     * <p>Uses {@link net.minecraft.world.entity.Entity#isAttackable()} instead of
     * {@link net.minecraft.world.entity.Entity#isPickable()} so only entities that can actually
     * take damage are targeted (excludes item frames, marker armour stands, etc.).
     */
    @SuppressWarnings("resource")
    @Nullable
    private static EntityHitResult rayTraceForEntity(ServerPlayer player) {
        double reach = player.gameMode.isCreative() ? 5.0 : 4.5;
        Vec3 eyePos  = player.getEyePosition(1.0f);
        Vec3 viewVec = player.getViewVector(1.0f);
        Vec3 endPos  = eyePos.add(viewVec.x * reach, viewVec.y * reach, viewVec.z * reach);

        AABB searchBox =
                player.getBoundingBox().expandTowards(viewVec.scale(reach)).inflate(1.0);

        EntityHitResult best    = null;
        double          bestSq  = reach * reach;

        for (var entity :
                player.level()
                        .getEntities(
                                player,
                                searchBox,
                                e -> !e.isSpectator() && e.isAttackable())) {

            AABB box    = entity.getBoundingBox().inflate(entity.getPickRadius());
            var  hitOpt = box.clip(eyePos, endPos);

            if (box.contains(eyePos)) {
                if (bestSq >= 0) {
                    best   = new EntityHitResult(entity, hitOpt.orElse(eyePos));
                    bestSq = 0;
                }
            } else if (hitOpt.isPresent()) {
                double d = eyePos.distanceToSqr(hitOpt.get());
                if (d < bestSq) {
                    best   = new EntityHitResult(entity, hitOpt.get());
                    bestSq = d;
                }
            }
        }

        return best;
    }
}

package me.bill.fakePlayerPlugin.util;

import com.google.gson.JsonObject;
import com.google.gson.JsonParser;

import org.bukkit.Bukkit;
import org.bukkit.plugin.Plugin;

import java.io.*;
import java.net.HttpURLConnection;
import java.net.URI;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.security.MessageDigest;
import java.util.HexFormat;

/**
 * Centralized API-based attribution verification for FakePlayerPlugin.
 *
 * <p>On startup, fetches official attribution data from the remote API and
 * compares it against local encoded values. If the API is unreachable,
 * falls back to a locally cached response. If no cache exists, falls back
 * to the built-in encoded data in {@link AttributionManager}.</p>
 *
 * <p>This class is the <b>single</b> owner of the API key and endpoint.
 * All attribution API access goes through this manager.</p>
 */
public final class AttributionApiManager {

    // ── API configuration (encoded to prevent trivial text-search edits) ──

    // endpoint: https://fakeplayerplugin.xyz/api/attribution
    private static final int[] _EP = {
            104,116,116,112,115,58,47,47,102,97,107,101,112,108,97,121,101,114,
            112,108,117,103,105,110,46,120,121,122,47,97,112,105,47,97,116,116,
            114,105,98,117,116,105,111,110};

    // API key: fpp_live_AttrKey_2026
    private static final int[] _AK = {
            102,112,112,95,108,105,118,101,95,65,116,116,114,75,101,121,95,50,
            48,50,54};

    private static String _d(int[] c) {
        char[] r = new char[c.length];
        for (int i = 0; i < c.length; i++) r[i] = (char) c[i];
        return new String(r);
    }

    /** Returns the API endpoint URL. Single source of truth. */
    public static String getEndpoint() { return _d(_EP); }

    /** Returns the API key. Only this class should expose it. */
    static String getApiKey() { return _d(_AK); }

    // ── Cached API response ──

    private static volatile AttributionData apiData;
    private static volatile boolean apiFetched = false;
    private static volatile boolean apiReachable = false;

    private static final String CACHE_FILE = "data/attribution-cache.json";
    private static final long CONNECT_TIMEOUT_MS = 5_000;
    private static final long READ_TIMEOUT_MS = 5_000;

    private AttributionApiManager() {}

    // ── Public API ──────────────────────────────────────────────

    /**
     * Kicks off an async API fetch. Called once during onEnable, after
     * Config and AttributionManager are initialised.
     */
    public static void init(Plugin plugin) {
        Bukkit.getScheduler().runTaskAsynchronously(plugin, () -> {
            AttributionData data = fetchFromApi();
            if (data != null) {
                apiData = data;
                apiFetched = true;
                apiReachable = true;
                saveCache(plugin, data);
                // schedule comparison on main thread
                Bukkit.getScheduler().runTask(plugin, () -> compareAndRestore(data));
            } else {
                // try local cache
                AttributionData cached = loadCache(plugin);
                if (cached != null) {
                    apiData = cached;
                    apiFetched = true;
                    apiReachable = false;
                    FppLogger.warn("Attribution API unreachable — using cached data.");
                    Bukkit.getScheduler().runTask(plugin, () -> compareAndRestore(cached));
                } else {
                    apiFetched = false;
                    apiReachable = false;
                    // fallback to built-in encoded data (AttributionManager)
                    FppLogger.debug("STARTUP", true,
                            "Attribution API unreachable, no cache — using built-in data.");
                }
            }
        });
    }

    /** Whether the last API call succeeded. */
    public static boolean isApiReachable() { return apiReachable; }

    /** Whether any API data (live or cached) was loaded. */
    public static boolean hasData() { return apiFetched && apiData != null; }

    /** Returns the API-sourced author, or falls back to local encoded. */
    public static String getAuthor() {
        if (apiData != null && apiData.author != null && !apiData.author.isBlank()) {
            return apiData.author;
        }
        return AttributionManager.getOriginalAuthor();
    }

    /** Returns the API-sourced message, or falls back to local encoded. */
    public static String getMessage() {
        if (apiData != null && apiData.message != null && !apiData.message.isBlank()) {
            return apiData.message;
        }
        return AttributionManager.getAttributionMessage();
    }

    /** Returns the API-sourced Modrinth link, or falls back to local. */
    public static String getModrinthLink() {
        if (apiData != null && apiData.modrinthLink != null && !apiData.modrinthLink.isBlank()) {
            return apiData.modrinthLink;
        }
        return AttributionManager.getModrinthLink();
    }

    /** Returns the API-sourced GitHub link, or falls back to local. */
    public static String getGithubLink() {
        if (apiData != null && apiData.githubLink != null && !apiData.githubLink.isBlank()) {
            return apiData.githubLink;
        }
        return AttributionManager.getGithubLink();
    }

    /**
     * Quick integrity probe — verifies the API manager's core arrays
     * have not been zeroed or truncated. Called from distributed sites.
     */
    public static boolean quickEndpointCheck() {
        if (_EP.length < 10) return false;
        int sum = 0;
        for (int c : _EP) sum += c;
        return sum == 4452;
    }

    // ── HTTP fetch ──────────────────────────────────────────────

    private static AttributionData fetchFromApi() {
        HttpURLConnection conn = null;
        try {
            String endpoint = getEndpoint();
            conn = (HttpURLConnection) URI.create(endpoint).toURL().openConnection();
            conn.setRequestMethod("GET");
            conn.setRequestProperty("X-Api-Key", getApiKey());
            conn.setRequestProperty("User-Agent", "FakePlayerPlugin");
            conn.setConnectTimeout((int) CONNECT_TIMEOUT_MS);
            conn.setReadTimeout((int) READ_TIMEOUT_MS);
            conn.setInstanceFollowRedirects(true);

            int code = conn.getResponseCode();
            if (code != 200) return null;

            String body;
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(conn.getInputStream(), StandardCharsets.UTF_8))) {
                StringBuilder sb = new StringBuilder();
                String line;
                while ((line = br.readLine()) != null) sb.append(line);
                body = sb.toString();
            }

            return parseResponse(body);
        } catch (Exception e) {
            // Network error, DNS failure, timeout — all expected offline
            return null;
        } finally {
            if (conn != null) conn.disconnect();
        }
    }

    private static AttributionData parseResponse(String json) {
        try {
            JsonObject obj = JsonParser.parseString(json).getAsJsonObject();

            String author = getStr(obj, "author");
            String message = getStr(obj, "message");
            String modrinth = getStr(obj, "modrinth_link");
            String github = getStr(obj, "github_link");
            String signature = getStr(obj, "signature");

            if (author == null || message == null) return null;

            // Verify signature if present: sha256(author + "|" + message)
            if (signature != null && !signature.isBlank()) {
                String payload = author + "|" + message;
                String computed = sha256(payload);
                if (!computed.equalsIgnoreCase(signature)) {
                    FppLogger.warn("Attribution API signature mismatch — response rejected.");
                    return null;
                }
            }

            return new AttributionData(author, message, modrinth, github);
        } catch (Exception e) {
            return null;
        }
    }

    private static String getStr(JsonObject obj, String key) {
        if (obj.has(key) && !obj.get(key).isJsonNull()) {
            return obj.get(key).getAsString();
        }
        return null;
    }

    private static String sha256(String input) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(input.getBytes(StandardCharsets.UTF_8));
            return HexFormat.of().formatHex(hash);
        } catch (Exception e) {
            return "";
        }
    }

    // ── Compare + restore ───────────────────────────────────────

    private static void compareAndRestore(AttributionData data) {
        String localAuthor = AttributionManager.getOriginalAuthor();
        String localMessage = AttributionManager.getAttributionMessage();

        boolean authorMatch = data.author != null && data.author.equalsIgnoreCase(localAuthor);
        boolean messageMatch = data.message != null && data.message.equals(localMessage);

        if (!authorMatch || !messageMatch) {
            FppLogger.warn("Attribution data mismatch detected — restored from API.");
        }
    }

    // ── Local cache ─────────────────────────────────────────────

    private static void saveCache(Plugin plugin, AttributionData data) {
        try {
            File file = new File(plugin.getDataFolder(), CACHE_FILE);
            file.getParentFile().mkdirs();
            JsonObject obj = new JsonObject();
            obj.addProperty("author", data.author);
            obj.addProperty("message", data.message);
            if (data.modrinthLink != null) obj.addProperty("modrinth_link", data.modrinthLink);
            if (data.githubLink != null) obj.addProperty("github_link", data.githubLink);
            obj.addProperty("cached_at", System.currentTimeMillis());
            Files.writeString(file.toPath(), obj.toString(), StandardCharsets.UTF_8);
        } catch (Exception e) {
            // cache write failure is non-critical
        }
    }

    private static AttributionData loadCache(Plugin plugin) {
        try {
            File file = new File(plugin.getDataFolder(), CACHE_FILE);
            if (!file.exists()) return null;
            String json = Files.readString(file.toPath(), StandardCharsets.UTF_8);
            return parseResponse(json);
        } catch (Exception e) {
            return null;
        }
    }

    // ── Data record ─────────────────────────────────────────────

    public record AttributionData(
            String author,
            String message,
            String modrinthLink,
            String githubLink) {}
}

