private static final String CREATE_SKIN_CACHE_SQLITE = "CREATE TABLE IF NOT EXISTS fpp_skin_cache (" + " skin_name VARCHAR(16) NOT NULL PRIMARY KEY," + " texture_value TEXT NOT NULL," + " texture_signature TEXT DEFAULT NULL," + " source VARCHAR(64) DEFAULT NULL," + " cached_at BIGINT NOT NULL" + ")";
private static final String CREATE_SKIN_CACHE_MYSQL = "CREATE TABLE IF NOT EXISTS fpp_skin_cache (" + " skin_name VARCHAR(16) NOT NULL PRIMARY KEY," + " texture_value TEXT NOT NULL," + " texture_signature TEXT DEFAULT NULL," + " source VARCHAR(64) DEFAULT NULL," + " cached_at BIGINT NOT NULL" + ")";
private static final String[][] MIGRATIONS = { { "ALTER TABLE fpp_bot_sessions ADD COLUMN last_yaw FLOAT", "ALTER TABLE fpp_bot_sessions ADD COLUMN last_pitch FLOAT" }, {}, { "ALTER TABLE fpp_bot_sessions ADD COLUMN bot_display VARCHAR(128) DEFAULT NULL", "ALTER TABLE fpp_active_bots ADD COLUMN bot_display VARCHAR(128) DEFAULT NULL", "CREATE INDEX IF NOT EXISTS idx_sessions_bot_name ON fpp_bot_sessions(bot_name)", "CREATE INDEX IF NOT EXISTS idx_sessions_spawned_by ON fpp_bot_sessions(spawned_by)", "CREATE INDEX IF NOT EXISTS idx_sessions_removed_at ON fpp_bot_sessions(removed_at)", "CREATE INDEX IF NOT EXISTS idx_sessions_spawned_at ON fpp_bot_sessions(spawned_at)", "CREATE INDEX IF NOT EXISTS idx_sessions_bot_uuid ON fpp_bot_sessions(bot_uuid)" }, { "ALTER TABLE fpp_bot_sessions ADD COLUMN luckperms_group VARCHAR(64) DEFAULT NULL", "ALTER TABLE fpp_active_bots ADD COLUMN luckperms_group VARCHAR(64) DEFAULT NULL" }, { "ALTER TABLE fpp_bot_sessions ADD COLUMN server_id VARCHAR(64) NOT NULL DEFAULT" + " 'default'", "ALTER TABLE fpp_active_bots ADD COLUMN server_id VARCHAR(64) NOT NULL DEFAULT" + " 'default'", "CREATE INDEX IF NOT EXISTS idx_sessions_server_id ON fpp_bot_sessions(server_id)", "CREATE INDEX IF NOT EXISTS idx_active_server_id ON fpp_active_bots(server_id)" }, { "CREATE TABLE IF NOT EXISTS fpp_sleeping_bots (" + " sleep_order INTEGER NOT NULL," + " bot_name VARCHAR(16) NOT NULL," + " world_name VARCHAR(64) NOT NULL," + " pos_x DOUBLE NOT NULL," + " pos_y DOUBLE NOT NULL," + " pos_z DOUBLE NOT NULL," + " pos_yaw FLOAT NOT NULL DEFAULT 0," + " pos_pitch FLOAT NOT NULL DEFAULT 0," + " server_id VARCHAR(64) NOT NULL DEFAULT 'default'," + " PRIMARY KEY (server_id, sleep_order)" + ")" }, { "CREATE TABLE IF NOT EXISTS fpp_bot_identities (" + " bot_name VARCHAR(16) NOT NULL," + " server_id VARCHAR(64) NOT NULL DEFAULT 'default'," + " bot_uuid VARCHAR(36) NOT NULL," + " created_at BIGINT NOT NULL," + " PRIMARY KEY (bot_name, server_id)" + ")" }, { "ALTER TABLE fpp_active_bots ADD COLUMN frozen BOOLEAN DEFAULT 0", "ALTER TABLE fpp_active_bots ADD COLUMN chat_enabled BOOLEAN DEFAULT 1", "ALTER TABLE fpp_active_bots ADD COLUMN chat_tier VARCHAR(16) DEFAULT NULL", "ALTER TABLE fpp_active_bots ADD COLUMN right_click_cmd VARCHAR(256) DEFAULT NULL" }, {"ALTER TABLE fpp_active_bots ADD COLUMN ai_personality VARCHAR(64) DEFAULT NULL"}, { "ALTER TABLE fpp_active_bots ADD COLUMN pickup_items BOOLEAN DEFAULT 0", "ALTER TABLE fpp_active_bots ADD COLUMN pickup_xp BOOLEAN DEFAULT 1" }, { "ALTER TABLE fpp_active_bots ADD COLUMN head_ai_enabled BOOLEAN DEFAULT 1", "ALTER TABLE fpp_active_bots ADD COLUMN nav_parkour BOOLEAN DEFAULT 0", "ALTER TABLE fpp_active_bots ADD COLUMN nav_break_blocks BOOLEAN DEFAULT 0", "ALTER TABLE fpp_active_bots ADD COLUMN nav_place_blocks BOOLEAN DEFAULT 0" }, { "CREATE TABLE IF NOT EXISTS fpp_bot_tasks (" + " bot_uuid VARCHAR(36) NOT NULL," + " server_id VARCHAR(64) NOT NULL DEFAULT 'default'," + " task_type VARCHAR(16) NOT NULL," + " world_name VARCHAR(64) DEFAULT NULL," + " pos_x DOUBLE DEFAULT 0," + " pos_y DOUBLE DEFAULT 0," + " pos_z DOUBLE DEFAULT 0," + " pos_yaw FLOAT DEFAULT 0," + " pos_pitch FLOAT DEFAULT 0," + " once_flag BOOLEAN DEFAULT 0," + " extra_str VARCHAR(256) DEFAULT NULL," + " extra_bool BOOLEAN DEFAULT 0," + " PRIMARY KEY (bot_uuid, server_id, task_type)" + ")" }, { "ALTER TABLE fpp_active_bots ADD COLUMN swim_ai_enabled BOOLEAN DEFAULT 1", "ALTER TABLE fpp_active_bots ADD COLUMN chunk_load_radius INT DEFAULT -1" }, { "CREATE TABLE IF NOT EXISTS fpp_skin_cache (" + " skin_name VARCHAR(16) NOT NULL PRIMARY KEY," + " texture_value TEXT NOT NULL," + " texture_signature TEXT DEFAULT NULL," + " source VARCHAR(64) DEFAULT NULL," + " cached_at BIGINT NOT NULL" + ")", "CREATE INDEX IF NOT EXISTS idx_skin_cache_cached_at ON fpp_skin_cache(cached_at)" } };
private volatile Connection connection; private boolean isMysql = false; private File dataFolder;
private final ExecutorService writer = Executors.newSingleThreadExecutor( r -> { Thread t = new Thread(r, "FPP-DB-Writer"); t.setDaemon(true); return t; }); private final BlockingQueue<Runnable> writeQueue = new LinkedBlockingQueue<>(); private final AtomicBoolean running = new AtomicBoolean(true);
private final Map<String, BotRecord> activeRecords = new ConcurrentHashMap<>(); private final Map<String, PendingLocation> pendingLocations = new ConcurrentHashMap<>();
public boolean init(File pluginDataFolder) { this.dataFolder = pluginDataFolder; if (!connect()) return false; boolean freshInstall = !tableExists("fpp_bot_sessions"); createTables(); if (freshInstall) {
setSchemaVersion(SCHEMA_VERSION); Config.debugDatabase( "DB: fresh install — schema initialized at v" + SCHEMA_VERSION + "."); } else { migrate(); } backfillIdentities(); startWriteLoop(); startHealthCheck(); return true; }
private boolean connect() { if (Config.mysqlEnabled()) { if (tryMysql()) { isMysql = true; return true; } FppLogger.warn("MySQL connection failed - falling back to SQLite."); } return trySqlite(); }
private boolean tryMysql() { try { Class.forName("com.mysql.cj.jdbc.Driver"); int connTimeout = Config.mysqlConnTimeout(); String url = "jdbc:mysql://" + Config.mysqlHost() + ":" + Config.mysqlPort() + "/" + Config.mysqlDatabase() + "?useSSL=" + Config.mysqlUseSSL() + "&autoReconnect=true&characterEncoding=utf8" + "&connectionTimeout=" + connTimeout + "&socketTimeout=" + (connTimeout * 2); connection = DriverManager.getConnection( url, Config.mysqlUsername(), Config.mysqlPassword()); Config.debug("MySQL pool-size advisory: " + Config.mysqlPoolSize()); FppLogger.debug( "Database connected via MySQL (" + Config.mysqlHost() + ":" + Config.mysqlPort() + "/" + Config.mysqlDatabase() + ")."); return true; } catch (Exception e) { FppLogger.warn("MySQL init error: " + e.getMessage()); return false; } }
private boolean trySqlite() { try { Class.forName("org.sqlite.JDBC"); File dbDir = new File(dataFolder, "data"); dbDir.mkdirs(); File dbFile = new File(dbDir, "fpp.db"); connection = DriverManager.getConnection("jdbc:sqlite:" + dbFile.getAbsolutePath()); try (Statement st = connection.createStatement()) { st.execute("PRAGMA journal_mode=WAL"); st.execute("PRAGMA synchronous=NORMAL"); st.execute("PRAGMA foreign_keys=ON"); st.execute("PRAGMA busy_timeout=5000"); st.execute("PRAGMA cache_size=-8000"); st.execute("PRAGMA temp_store=MEMORY"); } isMysql = false; FppLogger.debug("Database connected via SQLite (" + dbFile.getPath() + ")."); return true; } catch (Exception e) { FppLogger.error("SQLite init error: " + e.getMessage()); return false; } }
private boolean tableExists(String tableName) { try (PreparedStatement ps = connection.prepareStatement( isMysql ? "SELECT 1 FROM information_schema.tables WHERE" + " table_schema=DATABASE() AND table_name=?" : "SELECT 1 FROM sqlite_master WHERE type='table' AND name=?")) { ps.setString(1, tableName); try (java.sql.ResultSet rs = ps.executeQuery()) { return rs.next(); } } catch (Exception e) { return false; } }
private void createTables() { exec(isMysql ? CREATE_SESSIONS_MYSQL : CREATE_SESSIONS_SQLITE); exec(isMysql ? CREATE_ACTIVE_MYSQL : CREATE_ACTIVE_SQLITE); exec(isMysql ? CREATE_SLEEPING_MYSQL : CREATE_SLEEPING_SQLITE); exec(isMysql ? CREATE_IDENTITIES_MYSQL : CREATE_IDENTITIES_SQLITE); exec(isMysql ? CREATE_TASKS_MYSQL : CREATE_TASKS_SQLITE); exec(isMysql ? CREATE_SKIN_CACHE_MYSQL : CREATE_SKIN_CACHE_SQLITE); exec(CREATE_META); }
private void migrate() { int current = getSchemaVersion();
if (current < 1) { FppLogger.warn( "DB schema_version=" + current + " is invalid (expected >= 1). Treating as v1 to avoid a migration" + " crash. All schema steps will be applied."); current = 1; }
if (current >= SCHEMA_VERSION) { Config.debugDatabase("DB schema is current (v" + current + "). No migration needed."); return; }
FppLogger.info( "Applying DB schema migration v" + current + " → v" + SCHEMA_VERSION + " (" + (SCHEMA_VERSION - current) + " step(s))…");
for (int v = current; v < SCHEMA_VERSION; v++) { for (String sql : MIGRATIONS[v - 1]) { if (!sql.isEmpty()) execSilent(sql); } setSchemaVersion(v + 1); FppLogger.info(" DB schema: v" + v + " → v" + (v + 1)); }
FppLogger.info("DB schema migration complete (now at v" + SCHEMA_VERSION + ")."); }
private int getSchemaVersion() { try (PreparedStatement ps = connection.prepareStatement( "SELECT value FROM fpp_meta WHERE key_name='schema_version'"); ResultSet rs = ps.executeQuery()) { if (rs.next()) return Integer.parseInt(rs.getString(1)); } catch (Exception ignored) { } return 1; }
private void setSchemaVersion(int v) { String sql = isMysql ? "INSERT INTO fpp_meta(key_name,value) VALUES('schema_version',?) ON" + " DUPLICATE KEY UPDATE value=?" : "INSERT OR REPLACE INTO fpp_meta(key_name,value)" + " VALUES('schema_version',?)"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, String.valueOf(v)); if (isMysql) ps.setString(2, String.valueOf(v)); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB setSchemaVersion: " + e.getMessage()); } }
private void startWriteLoop() { writer.submit( () -> { while (running.get() || !writeQueue.isEmpty()) { try { Runnable task = writeQueue.poll(100, TimeUnit.MILLISECONDS); if (task != null) task.run(); } catch (InterruptedException e) { Thread.currentThread().interrupt(); break; } catch (Exception e) { FppLogger.error("DB write error: " + e.getMessage()); } } }); }
private void startHealthCheck() { Executors.newSingleThreadScheduledExecutor( r -> { Thread t = new Thread(r, "FPP-DB-Health"); t.setDaemon(true); return t; }) .scheduleAtFixedRate( () -> { if (!isAlive()) { FppLogger.warn("DB connection lost - reconnecting..."); if (connect()) { createTables(); FppLogger.success("DB reconnected."); } else { FppLogger.error("DB reconnect failed."); } } }, 60, 60, TimeUnit.SECONDS); }
private String serverCond() { return Config.isNetworkMode() ? "1=1" : "server_id=?"; }
private int bindServer(PreparedStatement ps, int idx) throws SQLException { if (!Config.isNetworkMode()) ps.setString(idx++, Config.serverId()); return idx; }
private String serverWhere() { if (Config.isNetworkMode()) return ""; return " WHERE server_id='" + Config.serverId().replace("'", "''") + "'"; }
private String serverAnd() { if (Config.isNetworkMode()) return ""; return " AND server_id='" + Config.serverId().replace("'", "''") + "'"; }
public SkinCacheEntry getCachedSkin(String skinName) { String sql = "SELECT texture_value, texture_signature, source, cached_at FROM fpp_skin_cache" + " WHERE skin_name=?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, skinName.toLowerCase(java.util.Locale.ROOT)); try (ResultSet rs = ps.executeQuery()) { if (rs.next()) { long cachedAt = rs.getLong("cached_at"); long age = System.currentTimeMillis() - cachedAt;
if (age > TimeUnit.DAYS.toMillis(7)) { Config.debugSkin( "DB: skin cache for '" + skinName + "' expired (age=" + TimeUnit.MILLISECONDS.toDays(age) + " days)"); return null; } String value = rs.getString("texture_value"); String signature = rs.getString("texture_signature"); String source = rs.getString("source"); Config.debugSkin( "DB: skin cache HIT for '" + skinName + "' (age=" + TimeUnit.MILLISECONDS.toHours(age) + "h, source=" + source + ")"); return new SkinCacheEntry(skinName, value, signature, source, cachedAt); } } } catch (Exception e) { Config.debugSkin( "DB: skin cache lookup error for '" + skinName + "': " + e.getMessage()); } Config.debugSkin("DB: skin cache MISS for '" + skinName + "'"); return null; }
public void cacheSkin( String skinName, String textureValue, String textureSignature, String source) { enqueue( () -> { if (!isAlive()) return; String sql = isMysql ? "INSERT INTO fpp_skin_cache(skin_name, texture_value," + " texture_signature, source, cached_at)" + " VALUES(?,?,?,?,?) ON DUPLICATE KEY UPDATE" + " texture_value=?, texture_signature=?, source=?," + " cached_at=?" : "INSERT OR REPLACE INTO fpp_skin_cache(skin_name," + " texture_value, texture_signature, source, cached_at)" + " VALUES(?,?,?,?,?)";
try (PreparedStatement ps = connection.prepareStatement(sql)) { String lowerName = skinName.toLowerCase(java.util.Locale.ROOT); long now = System.currentTimeMillis();
ps.setString(1, lowerName); ps.setString(2, textureValue); ps.setString(3, textureSignature); ps.setString(4, source); ps.setLong(5, now);
if (isMysql) { ps.setString(6, textureValue); ps.setString(7, textureSignature); ps.setString(8, source); ps.setLong(9, now); }
ps.executeUpdate(); Config.debugSkin( "DB: cached skin for '" + skinName + "' (source=" + source + ")"); } catch (Exception e) { FppLogger.warn( "DB: failed to cache skin for '" + skinName + "': " + e.getMessage()); } }); }
public void cleanExpiredSkinCache() { enqueue( () -> { if (!isAlive()) return; long cutoff = System.currentTimeMillis() - TimeUnit.DAYS.toMillis(7); String sql = "DELETE FROM fpp_skin_cache WHERE cached_at < ?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setLong(1, cutoff); int deleted = ps.executeUpdate(); if (deleted > 0) { Config.debugDatabase( "DB: cleaned " + deleted + " expired skin cache entries"); } } catch (Exception e) { FppLogger.warn("DB: failed to clean expired skin cache: " + e.getMessage()); } }); }
public int getSkinCacheSize() { String sql = "SELECT COUNT(*) FROM fpp_skin_cache"; try (PreparedStatement ps = connection.prepareStatement(sql); ResultSet rs = ps.executeQuery()) { if (rs.next()) { return rs.getInt(1); } } catch (Exception e) { Config.debugDatabase("DB: failed to get skin cache size: " + e.getMessage()); } return 0; }
public void close() { flushPendingLocations(); writer.shutdown(); try { if (!writer.awaitTermination(8, TimeUnit.SECONDS)) writer.shutdownNow(); } catch (InterruptedException ignored) { writer.shutdownNow(); } try { if (connection != null && !connection.isClosed()) connection.close(); FppLogger.info("Database connection closed."); } catch (SQLException e) { FppLogger.error("Error closing DB: " + e.getMessage()); } }
public Connection getConnection() { return connection; }
private boolean isAlive() { try { if (connection == null || connection.isClosed()) return false; if (isMysql) { try (Statement st = connection.createStatement()) { st.execute("SELECT 1"); } } return true; } catch (SQLException e) { return false; } }
public void recordSpawn(BotRecord record) { recordSpawn(record, null); }
public void recordSpawn(BotRecord record, String displayName) { activeRecords.put(record.getBotUuid().toString(), record); final String display = displayName; enqueue( () -> { if (!isAlive()) return;
String sql = "INSERT INTO fpp_bot_sessions " + "(bot_name,bot_display,bot_uuid,spawned_by,spawned_by_uuid,world_name,spawn_x,spawn_y,spawn_z,spawn_yaw,spawn_pitch,entity_type,spawned_at,server_id)" + " VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, record.getBotName()); ps.setString(2, display); ps.setString(3, record.getBotUuid().toString()); ps.setString(4, record.getSpawnedBy()); ps.setString(5, record.getSpawnedByUuid().toString()); ps.setString(6, record.getWorldName()); ps.setDouble(7, record.getSpawnX()); ps.setDouble(8, record.getSpawnY()); ps.setDouble(9, record.getSpawnZ()); ps.setFloat(10, record.getSpawnYaw()); ps.setFloat(11, record.getSpawnPitch()); ps.setString(12, "MANNEQUIN"); ps.setLong(13, record.getSpawnedAt().toEpochMilli()); ps.setString(14, record.getServerId()); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB recordSpawn: " + e.getMessage()); }
upsertActiveBotSync( record.getBotUuid().toString(), record.getBotName(), display, record.getSpawnedBy(), record.getSpawnedByUuid().toString(), record.getWorldName(), record.getSpawnX(), record.getSpawnY(), record.getSpawnZ(), record.getSpawnYaw(), record.getSpawnPitch(), null, false, true, null, null, null, Config.bodyPickUpItems(), Config.bodyPickUpXp(), true, Config.pathfindingParkour(), Config.pathfindingBreakBlocks(), Config.pathfindingPlaceBlocks()); }); }
public void updateLastLocation( UUID botUuid, String world, double x, double y, double z, float yaw, float pitch) { String key = botUuid.toString(); pendingLocations.put(key, new PendingLocation(world, x, y, z, yaw, pitch)); BotRecord rec = activeRecords.get(key); if (rec != null) rec.setLastLocation(world, x, y, z, yaw, pitch); }
public void flushPendingLocations() { if (pendingLocations.isEmpty()) return; Map<String, PendingLocation> snap = new HashMap<>(pendingLocations); pendingLocations.clear(); enqueue(() -> batchUpdateLocationsSync(snap)); }
public void recordRemoval(UUID botUuid, String reason) { Instant now = Instant.now(); String key = botUuid.toString(); BotRecord rec = activeRecords.remove(key); if (rec != null) { rec.setRemovedAt(now); rec.setRemoveReason(reason); } pendingLocations.remove(key); enqueue( () -> { if (!isAlive()) return; long ts = now.toEpochMilli(); try (PreparedStatement ps = connection.prepareStatement( "UPDATE fpp_bot_sessions SET removed_at=?,remove_reason=? WHERE" + " bot_uuid=? AND removed_at IS NULL")) { ps.setLong(1, ts); ps.setString(2, reason); ps.setString(3, key); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB recordRemoval (session): " + e.getMessage()); } try (PreparedStatement ps = connection.prepareStatement( "DELETE FROM fpp_active_bots WHERE bot_uuid=?")) { ps.setString(1, key); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB recordRemoval (active): " + e.getMessage()); } }); }
public void recordAllShutdown() { if (!pendingLocations.isEmpty()) { batchUpdateLocationsSync(new HashMap<>(pendingLocations)); pendingLocations.clear(); } long now = Instant.now().toEpochMilli(); activeRecords.values().forEach(r -> r.setRemovedAt(Instant.ofEpochMilli(now))); activeRecords.clear(); if (!isAlive()) return; try (PreparedStatement ps = connection.prepareStatement( "UPDATE fpp_bot_sessions SET removed_at=?,remove_reason='SHUTDOWN' " + "WHERE removed_at IS NULL AND server_id=?")) { ps.setLong(1, now); ps.setString(2, Config.serverId()); int rows = ps.executeUpdate(); Config.debug("DB shutdown: closed " + rows + " open session(s)."); } catch (SQLException e) { FppLogger.error("DB recordAllShutdown: " + e.getMessage()); } }
public void clearActiveBots() { final String sid = Config.serverId(); enqueue( () -> { if (!isAlive()) return; try (PreparedStatement ps = connection.prepareStatement( "DELETE FROM fpp_active_bots WHERE server_id=?")) { ps.setString(1, sid); int rows = ps.executeUpdate(); Config.debug( "DB cleared " + rows + " active_bot(s) for server='" + sid + "'."); } catch (SQLException e) { FppLogger.error("DB clearActiveBots: " + e.getMessage()); } }); }
public List<ActiveBotRow> getActiveBots() { List<ActiveBotRow> list = new ArrayList<>(); if (!isAlive()) return list; String sql = "SELECT * FROM fpp_active_bots WHERE " + serverCond() + " ORDER BY updated_at ASC"; try (PreparedStatement ps = connection.prepareStatement(sql)) { bindServer(ps, 1); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapActiveBotRow(rs)); } } catch (SQLException e) { FppLogger.error("DB getActiveBots: " + e.getMessage()); } return list; }
public List<ActiveBotRow> getActiveBotsForThisServer() { List<ActiveBotRow> list = new ArrayList<>(); if (!isAlive()) return list;
String sql = "SELECT * FROM fpp_active_bots WHERE server_id=? ORDER BY updated_at ASC"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, Config.serverId()); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapActiveBotRow(rs)); } } catch (SQLException e) { FppLogger.error("DB getActiveBotsForThisServer: " + e.getMessage()); } return list; }
public List<ActiveBotRow> getActiveBotsFromOtherServers() { List<ActiveBotRow> list = new ArrayList<>(); if (!Config.isNetworkMode() || !isAlive()) return list; String sql = "SELECT * FROM fpp_active_bots WHERE server_id != ? ORDER BY updated_at ASC"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, Config.serverId()); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapActiveBotRow(rs)); } } catch (SQLException e) { FppLogger.error("DB getActiveBotsFromOtherServers: " + e.getMessage()); } return list; }
private ActiveBotRow mapActiveBotRow(ResultSet rs) throws SQLException { String lpGroup = null; try { lpGroup = rs.getString("luckperms_group"); } catch (SQLException ignored) { } String sid = null; try { sid = rs.getString("server_id"); } catch (SQLException ignored) { } if (sid == null || sid.isBlank()) sid = Config.serverId(); String aiPers = null; try { aiPers = rs.getString("ai_personality"); } catch (SQLException ignored) { } boolean pickUpItems = Config.bodyPickUpItems(); try { pickUpItems = rs.getBoolean("pickup_items"); } catch (SQLException ignored) { } boolean pickUpXp = Config.bodyPickUpXp(); try { pickUpXp = rs.getBoolean("pickup_xp"); } catch (SQLException ignored) { } boolean frozen = false; try { frozen = rs.getBoolean("frozen"); } catch (SQLException ignored) { } boolean chatEnabled = true; try { chatEnabled = rs.getBoolean("chat_enabled"); } catch (SQLException ignored) { } String chatTier = null; try { chatTier = rs.getString("chat_tier"); } catch (SQLException ignored) { } String rightClickCmd = null; try { rightClickCmd = rs.getString("right_click_cmd"); } catch (SQLException ignored) { } boolean headAiEnabled = true; try { headAiEnabled = rs.getBoolean("head_ai_enabled"); } catch (SQLException ignored) { } boolean navParkour = Config.pathfindingParkour(); try { navParkour = rs.getBoolean("nav_parkour"); } catch (SQLException ignored) { } boolean navBreakBlocks = Config.pathfindingBreakBlocks(); try { navBreakBlocks = rs.getBoolean("nav_break_blocks"); } catch (SQLException ignored) { } boolean navPlaceBlocks = Config.pathfindingPlaceBlocks(); try { navPlaceBlocks = rs.getBoolean("nav_place_blocks"); } catch (SQLException ignored) { } boolean swimAiEnabled = Config.swimAiEnabled(); try { swimAiEnabled = rs.getBoolean("swim_ai_enabled"); } catch (SQLException ignored) { } int chunkLoadRadius = -1; try { chunkLoadRadius = rs.getInt("chunk_load_radius"); } catch (SQLException ignored) { } return new ActiveBotRow( rs.getString("bot_uuid"), rs.getString("bot_name"), rs.getString("bot_display"), rs.getString("spawned_by"), rs.getString("spawned_by_uuid"), rs.getString("world_name"), rs.getDouble("pos_x"), rs.getDouble("pos_y"), rs.getDouble("pos_z"), rs.getFloat("pos_yaw"), rs.getFloat("pos_pitch"), lpGroup, sid, aiPers, pickUpItems, pickUpXp, frozen, chatEnabled, chatTier, rightClickCmd, headAiEnabled, navParkour, navBreakBlocks, navPlaceBlocks, swimAiEnabled, chunkLoadRadius); }
public List<BotRecord> getActiveSessions() { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list;
try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE removed_at IS NULL AND " + serverCond())) { bindServer(ps, 1); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getActiveSessions: " + e.getMessage()); } return list; }
public List<BotRecord> getRecentSessions(int limit) { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list; try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE " + serverCond() + " ORDER BY spawned_at DESC LIMIT ?")) { int next = bindServer(ps, 1); ps.setInt(next, limit); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getRecentSessions: " + e.getMessage()); } return list; }
public List<BotRecord> getSessionsBySpawner(String playerName) { return getSessionsBySpawner(playerName, Integer.MAX_VALUE); }
public List<BotRecord> getSessionsBySpawner(String playerName, int limit) { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list;
try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE spawned_by=?" + serverAnd() + " ORDER BY spawned_at DESC LIMIT ?")) { ps.setString(1, playerName); ps.setInt(2, limit); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getSessionsBySpawner: " + e.getMessage()); } return list; }
public List<BotRecord> getSessionsByBot(String botName) { return getSessionsByBot(botName, Integer.MAX_VALUE); }
public List<BotRecord> getSessionsByBot(String botName, int limit) { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list;
try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE bot_name=?" + serverAnd() + " ORDER BY spawned_at DESC LIMIT ?")) { ps.setString(1, botName); ps.setInt(2, limit); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getSessionsByBot: " + e.getMessage()); } return list; }
public List<BotRecord> getSessionsByUuid(UUID botUuid) { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list;
try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE bot_uuid=?" + serverAnd() + " ORDER BY spawned_at DESC")) { ps.setString(1, botUuid.toString()); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getSessionsByUuid: " + e.getMessage()); } return list; }
public List<BotRecord> getSessionsByReason(String reason, int limit) { List<BotRecord> list = new ArrayList<>(); if (!isAlive()) return list;
try (PreparedStatement ps = connection.prepareStatement( "SELECT * FROM fpp_bot_sessions WHERE remove_reason=?" + serverAnd() + " ORDER BY removed_at DESC LIMIT ?")) { ps.setString(1, reason); ps.setInt(2, limit); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapSession(rs)); } } catch (SQLException e) { FppLogger.error("DB getSessionsByReason: " + e.getMessage()); } return list; }
public int getTotalSessionCount() { if (!isAlive()) return 0; try (Statement st = connection.createStatement(); ResultSet rs = st.executeQuery("SELECT COUNT(*) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) return rs.getInt(1); } catch (SQLException e) { FppLogger.error("DB getTotalSessionCount: " + e.getMessage()); } return 0; }
public int getActiveSessionCount() { if (!isAlive()) return 0; try (Statement st = connection.createStatement(); ResultSet rs = st.executeQuery( "SELECT COUNT(*) FROM fpp_bot_sessions WHERE removed_at IS NULL" + serverAnd())) { if (rs.next()) return rs.getInt(1); } catch (SQLException e) { FppLogger.error("DB getActiveSessionCount: " + e.getMessage()); } return 0; }
public int getUniqueBotCount() { if (!isAlive()) return 0; try (Statement st = connection.createStatement(); ResultSet rs = st.executeQuery( "SELECT COUNT(DISTINCT bot_name) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) return rs.getInt(1); } catch (SQLException e) { FppLogger.error("DB getUniqueBotCount: " + e.getMessage()); } return 0; }
public int getUniqueSpawnerCount() { if (!isAlive()) return 0; try (Statement st = connection.createStatement(); ResultSet rs = st.executeQuery( "SELECT COUNT(DISTINCT spawned_by) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) return rs.getInt(1); } catch (SQLException e) { FppLogger.error("DB getUniqueSpawnerCount: " + e.getMessage()); } return 0; }
public Map<String, Integer> getTopSpawners(int limit) { Map<String, Integer> result = new LinkedHashMap<>(); if (!isAlive()) return result; try (PreparedStatement ps = connection.prepareStatement( "SELECT spawned_by, COUNT(*) AS cnt FROM fpp_bot_sessions WHERE " + serverCond() + " GROUP BY spawned_by ORDER BY cnt DESC LIMIT ?")) { int next = bindServer(ps, 1); ps.setInt(next, limit); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) result.put(rs.getString("spawned_by"), rs.getInt("cnt")); } } catch (SQLException e) { FppLogger.error("DB getTopSpawners: " + e.getMessage()); } return result; }
public DbStats getStats() { if (!isAlive()) return new DbStats(0, 0, 0, 0, 0L, isMysql ? "MySQL" : "SQLite"); int total = 0, active = 0, unique = 0, uniqueSpawners = 0; long totalUptimeMs = 0L; try (Statement st = connection.createStatement()) { try (ResultSet rs = st.executeQuery("SELECT COUNT(*) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) total = rs.getInt(1); } try (ResultSet rs = st.executeQuery( "SELECT COUNT(*) FROM fpp_bot_sessions WHERE removed_at IS NULL" + serverAnd())) { if (rs.next()) active = rs.getInt(1); } try (ResultSet rs = st.executeQuery( "SELECT COUNT(DISTINCT bot_name) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) unique = rs.getInt(1); } try (ResultSet rs = st.executeQuery( "SELECT COUNT(DISTINCT spawned_by) FROM fpp_bot_sessions" + serverWhere())) { if (rs.next()) uniqueSpawners = rs.getInt(1); } try (ResultSet rs = st.executeQuery( "SELECT SUM(removed_at - spawned_at) FROM fpp_bot_sessions " + "WHERE removed_at IS NOT NULL" + serverAnd())) { if (rs.next()) totalUptimeMs = rs.getLong(1); } } catch (SQLException e) { FppLogger.error("DB getStats: " + e.getMessage()); } return new DbStats( total, active, unique, uniqueSpawners, totalUptimeMs, isMysql ? "MySQL" : "SQLite"); }
private void upsertActiveBotSync( String uuid, String name, String display, String spawnedBy, String spawnedByUuid, String world, double x, double y, double z, float yaw, float pitch, String luckpermsGroup, boolean frozen, boolean chatEnabled, String chatTier, String rightClickCmd, String aiPersonality, boolean pickUpItems, boolean pickUpXp, boolean headAiEnabled, boolean navParkour, boolean navBreakBlocks, boolean navPlaceBlocks) { long now = Instant.now().toEpochMilli(); String serverId = Config.serverId(); String sql = isMysql ? "INSERT INTO" + " fpp_active_bots(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," + "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,luckperms_group,server_id," + "frozen,chat_enabled,chat_tier,right_click_cmd,ai_personality,pickup_items,pickup_xp,head_ai_enabled,nav_parkour,nav_break_blocks,nav_place_blocks)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?) ON" + " DUPLICATE KEY UPDATE" + " bot_name=VALUES(bot_name),bot_display=VALUES(bot_display)," + "spawned_by=VALUES(spawned_by),spawned_by_uuid=VALUES(spawned_by_uuid)," + "world_name=VALUES(world_name),pos_x=VALUES(pos_x),pos_y=VALUES(pos_y)," + "pos_z=VALUES(pos_z),pos_yaw=VALUES(pos_yaw),pos_pitch=VALUES(pos_pitch)," + "updated_at=VALUES(updated_at),luckperms_group=VALUES(luckperms_group)," + "server_id=VALUES(server_id),frozen=VALUES(frozen),chat_enabled=VALUES(chat_enabled)," + "chat_tier=VALUES(chat_tier),right_click_cmd=VALUES(right_click_cmd)," + "ai_personality=VALUES(ai_personality)," + "pickup_items=VALUES(pickup_items),pickup_xp=VALUES(pickup_xp)," + "head_ai_enabled=VALUES(head_ai_enabled),nav_parkour=VALUES(nav_parkour)," + "nav_break_blocks=VALUES(nav_break_blocks),nav_place_blocks=VALUES(nav_place_blocks)" : "INSERT OR REPLACE INTO" + " fpp_active_bots(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid," + "world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,luckperms_group,server_id," + "frozen,chat_enabled,chat_tier,right_click_cmd,ai_personality,pickup_items,pickup_xp,head_ai_enabled,nav_parkour,nav_break_blocks,nav_place_blocks)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, uuid); ps.setString(2, name); ps.setString(3, display); ps.setString(4, spawnedBy); ps.setString(5, spawnedByUuid); ps.setString(6, world); ps.setDouble(7, x); ps.setDouble(8, y); ps.setDouble(9, z); ps.setFloat(10, yaw); ps.setFloat(11, pitch); ps.setLong(12, now); if (luckpermsGroup != null) ps.setString(13, luckpermsGroup); else ps.setNull(13, java.sql.Types.VARCHAR); ps.setString(14, serverId); ps.setBoolean(15, frozen); ps.setBoolean(16, chatEnabled); if (chatTier != null) ps.setString(17, chatTier); else ps.setNull(17, java.sql.Types.VARCHAR); if (rightClickCmd != null) ps.setString(18, rightClickCmd); else ps.setNull(18, java.sql.Types.VARCHAR); if (aiPersonality != null) ps.setString(19, aiPersonality); else ps.setNull(19, java.sql.Types.VARCHAR); ps.setBoolean(20, pickUpItems); ps.setBoolean(21, pickUpXp); ps.setBoolean(22, headAiEnabled); ps.setBoolean(23, navParkour); ps.setBoolean(24, navBreakBlocks); ps.setBoolean(25, navPlaceBlocks); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB upsertActiveBot: " + e.getMessage()); } }
private void batchUpdateLocationsSync(Map<String, PendingLocation> snapshot) { if (!isAlive() || snapshot.isEmpty()) return; long now = Instant.now().toEpochMilli(); String s1 = "UPDATE fpp_bot_sessions SET" + " last_world=?,last_x=?,last_y=?,last_z=?,last_yaw=?,last_pitch=? WHERE" + " bot_uuid=? AND removed_at IS NULL"; String s2 = "UPDATE fpp_active_bots SET" + " world_name=?,pos_x=?,pos_y=?,pos_z=?,pos_yaw=?,pos_pitch=?,updated_at=?" + " WHERE bot_uuid=?"; try (PreparedStatement ps1 = connection.prepareStatement(s1); PreparedStatement ps2 = connection.prepareStatement(s2)) { for (Map.Entry<String, PendingLocation> e : snapshot.entrySet()) { PendingLocation l = e.getValue(); ps1.setString(1, l.world); ps1.setDouble(2, l.x); ps1.setDouble(3, l.y); ps1.setDouble(4, l.z); ps1.setFloat(5, l.yaw); ps1.setFloat(6, l.pitch); ps1.setString(7, e.getKey()); ps1.addBatch(); ps2.setString(1, l.world); ps2.setDouble(2, l.x); ps2.setDouble(3, l.y); ps2.setDouble(4, l.z); ps2.setFloat(5, l.yaw); ps2.setFloat(6, l.pitch); ps2.setLong(7, now); ps2.setString(8, e.getKey()); ps2.addBatch(); } ps1.executeBatch(); ps2.executeBatch(); Config.debug("DB flushed " + snapshot.size() + " location(s)."); } catch (SQLException e) { FppLogger.error("DB batchUpdateLocations: " + e.getMessage()); } }
private void exec(String sql) { try (Statement st = connection.createStatement()) { st.execute(sql); } catch (SQLException e) { FppLogger.error("DB exec: " + e.getMessage()); } }
private void execSilent(String sql) { try (Statement st = connection.createStatement()) { st.execute(sql); } catch (SQLException ignored) { } }
private void enqueue(Runnable task) { if (running.get()) writeQueue.offer(task); }
private BotRecord mapSession(ResultSet rs) throws SQLException { long rm = rs.getLong("removed_at"); Instant removedAt = rs.wasNull() ? null : Instant.ofEpochMilli(rm);
double lx = rs.getDouble("last_x"); if (rs.wasNull()) lx = rs.getDouble("spawn_x"); double ly = rs.getDouble("last_y"); if (rs.wasNull()) ly = rs.getDouble("spawn_y"); double lz = rs.getDouble("last_z"); if (rs.wasNull()) lz = rs.getDouble("spawn_z"); String lw = rs.getString("last_world"); if (lw == null) lw = rs.getString("world_name"); float lyaw, lpitch; try { lyaw = rs.getFloat("last_yaw"); if (rs.wasNull()) lyaw = rs.getFloat("spawn_yaw"); } catch (SQLException ignored) { lyaw = 0f; } try { lpitch = rs.getFloat("last_pitch"); if (rs.wasNull()) lpitch = rs.getFloat("spawn_pitch"); } catch (SQLException ignored) { lpitch = 0f; }
String sid = null; try { sid = rs.getString("server_id"); } catch (SQLException ignored) { } if (sid == null || sid.isBlank()) sid = Config.serverId();
return new BotRecord( rs.getLong("id"), rs.getString("bot_name"), UUID.fromString(rs.getString("bot_uuid")), rs.getString("spawned_by"), UUID.fromString(rs.getString("spawned_by_uuid")), rs.getString("world_name"), rs.getDouble("spawn_x"), rs.getDouble("spawn_y"), rs.getDouble("spawn_z"), rs.getFloat("spawn_yaw"), rs.getFloat("spawn_pitch"), lw, lx, ly, lz, lyaw, lpitch, Instant.ofEpochMilli(rs.getLong("spawned_at")), removedAt, rs.getString("remove_reason"), sid); }
private void backfillIdentities() { if (!isAlive()) return; String sql = isMysql ? "INSERT IGNORE INTO" + " fpp_bot_identities(bot_name,server_id,bot_uuid,created_at) SELECT" + " bot_name, server_id, (SELECT s2.bot_uuid FROM fpp_bot_sessions s2" + " WHERE s2.bot_name=s1.bot_name AND s2.server_id=s1.server_id " + " ORDER BY s2.spawned_at ASC LIMIT 1), MIN(spawned_at) FROM" + " fpp_bot_sessions s1 GROUP BY bot_name, server_id" : "INSERT OR IGNORE INTO" + " fpp_bot_identities(bot_name,server_id,bot_uuid,created_at) SELECT" + " bot_name, server_id, (SELECT s2.bot_uuid FROM fpp_bot_sessions s2" + " WHERE s2.bot_name=s1.bot_name AND s2.server_id=s1.server_id " + " ORDER BY s2.spawned_at ASC LIMIT 1), MIN(spawned_at) FROM" + " fpp_bot_sessions s1 GROUP BY bot_name, server_id"; try (Statement st = connection.createStatement()) { int rows = st.executeUpdate(sql); if (rows > 0) { FppLogger.info( "Bot identity registry: backfilled " + rows + " identit" + (rows == 1 ? "y" : "ies") + " from session history."); } } catch (SQLException e) {
FppLogger.debug( "Bot identity backfill skipped (no session history yet): " + e.getMessage()); } }
public UUID lookupBotUuid(String botName, String serverId) { if (!isAlive()) return null; try (PreparedStatement ps = connection.prepareStatement( "SELECT bot_uuid FROM fpp_bot_identities WHERE bot_name=? AND" + " server_id=?")) { ps.setString(1, botName); ps.setString(2, serverId); try (ResultSet rs = ps.executeQuery()) { if (rs.next()) { String raw = rs.getString(1); if (raw != null && !raw.isBlank()) return UUID.fromString(raw); } } } catch (SQLException e) { FppLogger.error("DB lookupBotUuid(" + botName + "): " + e.getMessage()); } return null; }
public void registerBotUuid(String botName, UUID uuid, String serverId) { final String sid = serverId; final long now = Instant.now().toEpochMilli(); enqueue( () -> { if (!isAlive()) return; String sql = isMysql ? "INSERT IGNORE INTO" + " fpp_bot_identities(bot_name,server_id,bot_uuid,created_at)" + " VALUES(?,?,?,?)" : "INSERT OR IGNORE INTO" + " fpp_bot_identities(bot_name,server_id,bot_uuid,created_at)" + " VALUES(?,?,?,?)"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, botName); ps.setString(2, sid); ps.setString(3, uuid.toString()); ps.setLong(4, now); ps.executeUpdate(); Config.debug( "DB registered identity: " + botName + " → " + uuid + " (server=" + sid + ")"); } catch (SQLException e) { FppLogger.error("DB registerBotUuid(" + botName + "): " + e.getMessage()); } }); }
public void saveSleepingBots(List<SleepingBotRow> bots) { final List<SleepingBotRow> snap = new ArrayList<>(bots); final String sid = Config.serverId(); enqueue( () -> { if (!isAlive()) return;
try (PreparedStatement del = connection.prepareStatement( "DELETE FROM fpp_sleeping_bots WHERE server_id=?")) { del.setString(1, sid); del.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB saveSleepingBots (delete): " + e.getMessage()); return; } if (snap.isEmpty()) return; String sql = "INSERT INTO fpp_sleeping_bots" + "(sleep_order,bot_name,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,server_id)" + " VALUES(?,?,?,?,?,?,?,?,?)"; try (PreparedStatement ps = connection.prepareStatement(sql)) { for (SleepingBotRow row : snap) { ps.setInt(1, row.sleepOrder()); ps.setString(2, row.botName()); ps.setString(3, row.world()); ps.setDouble(4, row.x()); ps.setDouble(5, row.y()); ps.setDouble(6, row.z()); ps.setFloat(7, row.yaw()); ps.setFloat(8, row.pitch()); ps.setString(9, sid); ps.addBatch(); } ps.executeBatch(); Config.debug( "DB saved " + snap.size() + " sleeping bot(s) for server='" + sid + "'."); } catch (SQLException e) { FppLogger.error("DB saveSleepingBots (insert): " + e.getMessage()); } }); }
public List<SleepingBotRow> loadSleepingBots() { List<SleepingBotRow> list = new ArrayList<>(); if (!isAlive()) return list; String sql = "SELECT * FROM fpp_sleeping_bots WHERE server_id=? ORDER BY sleep_order ASC"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, Config.serverId()); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) { list.add( new SleepingBotRow( rs.getInt("sleep_order"), rs.getString("bot_name"), rs.getString("world_name"), rs.getDouble("pos_x"), rs.getDouble("pos_y"), rs.getDouble("pos_z"), rs.getFloat("pos_yaw"), rs.getFloat("pos_pitch"))); } } } catch (SQLException e) { FppLogger.error("DB loadSleepingBots: " + e.getMessage()); } return list; }
public void clearSleepingBots() { final String sid = Config.serverId(); enqueue( () -> { if (!isAlive()) return; try (PreparedStatement ps = connection.prepareStatement( "DELETE FROM fpp_sleeping_bots WHERE server_id=?")) { ps.setString(1, sid); int rows = ps.executeUpdate(); Config.debug( "DB cleared " + rows + " sleeping bot(s) for server='" + sid + "'."); } catch (SQLException e) { FppLogger.error("DB clearSleepingBots: " + e.getMessage()); } }); }
public void mergeSessionRow( String botName, String botDisplay, String botUuid, String spawnedBy, String spawnedByUuid, String worldName, double spawnX, double spawnY, double spawnZ, float spawnYaw, float spawnPitch, String lastWorld, double lastX, double lastY, double lastZ, float lastYaw, float lastPitch, String entityType, long spawnedAtMs, Long removedAtMs, String removeReason, String serverId) {
if (!isAlive()) return;
if (lastWorld == null) lastWorld = worldName; if (entityType == null) entityType = "MANNEQUIN"; if (serverId == null || serverId.isBlank()) serverId = Config.serverId();
String sql = isMysql ? "INSERT IGNORE INTO fpp_bot_sessions" + "(bot_name,bot_display,bot_uuid,spawned_by,spawned_by_uuid,world_name," + "spawn_x,spawn_y,spawn_z,spawn_yaw,spawn_pitch," + "last_world,last_x,last_y,last_z,last_yaw,last_pitch,entity_type,spawned_at,removed_at,remove_reason,server_id)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)" : "INSERT OR IGNORE INTO fpp_bot_sessions" + "(bot_name,bot_display,bot_uuid,spawned_by,spawned_by_uuid,world_name," + "spawn_x,spawn_y,spawn_z,spawn_yaw,spawn_pitch," + "last_world,last_x,last_y,last_z,last_yaw,last_pitch,entity_type,spawned_at,removed_at,remove_reason,server_id)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)";
try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, botName); ps.setString(2, botDisplay); ps.setString(3, botUuid); ps.setString(4, spawnedBy); ps.setString(5, spawnedByUuid); ps.setString(6, worldName); ps.setDouble(7, spawnX); ps.setDouble(8, spawnY); ps.setDouble(9, spawnZ); ps.setFloat(10, spawnYaw); ps.setFloat(11, spawnPitch); ps.setString(12, lastWorld); ps.setDouble(13, lastX); ps.setDouble(14, lastY); ps.setDouble(15, lastZ); ps.setFloat(16, lastYaw); ps.setFloat(17, lastPitch); ps.setString(18, entityType); ps.setLong(19, spawnedAtMs); if (removedAtMs != null) ps.setLong(20, removedAtMs); else ps.setNull(20, java.sql.Types.BIGINT); ps.setString(21, removeReason); ps.setString(22, serverId); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB mergeSessionRow: " + e.getMessage()); } }
public void mergeActiveBotRow( String botUuid, String botName, String botDisplay, String spawnedBy, String spawnedByUuid, String worldName, double posX, double posY, double posZ, float posYaw, float posPitch, long updatedAt, String serverId) {
if (!isAlive()) return; if (serverId == null || serverId.isBlank()) serverId = Config.serverId();
String sql = isMysql ? "INSERT IGNORE INTO fpp_active_bots" + "(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,server_id)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)" : "INSERT OR IGNORE INTO fpp_active_bots" + "(bot_uuid,bot_name,bot_display,spawned_by,spawned_by_uuid,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,updated_at,server_id)" + " VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)";
try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, botUuid); ps.setString(2, botName); ps.setString(3, botDisplay); ps.setString(4, spawnedBy); ps.setString(5, spawnedByUuid); ps.setString(6, worldName); ps.setDouble(7, posX); ps.setDouble(8, posY); ps.setDouble(9, posZ); ps.setFloat(10, posYaw); ps.setFloat(11, posPitch); ps.setLong(12, updatedAt); ps.setString(13, serverId); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB mergeActiveBotRow: " + e.getMessage()); } }
