public void updateBotHeadAiEnabled(String uuid, boolean enabled) { if (!isAlive()) return; enqueue( () -> { if (!isAlive()) return; String sql = "UPDATE fpp_active_bots SET head_ai_enabled=? WHERE bot_uuid=?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setBoolean(1, enabled); ps.setString(2, uuid); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB updateBotHeadAiEnabled: " + e.getMessage()); } }); }
public void updateBotNavSettings( String uuid, boolean navParkour, boolean navBreakBlocks, boolean navPlaceBlocks) { if (!isAlive()) return; enqueue( () -> { if (!isAlive()) return; String sql = "UPDATE fpp_active_bots SET nav_parkour=?, nav_break_blocks=?," + " nav_place_blocks=? WHERE bot_uuid=?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setBoolean(1, navParkour); ps.setBoolean(2, navBreakBlocks); ps.setBoolean(3, navPlaceBlocks); ps.setString(4, uuid); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB updateBotNavSettings: " + e.getMessage()); } }); }
public void updateBotAllSettings( String uuid, boolean frozen, boolean chatEnabled, String chatTier, String rightClickCmd, String aiPersonality, boolean pickUpItems, boolean pickUpXp, boolean headAiEnabled, boolean navParkour, boolean navBreakBlocks, boolean navPlaceBlocks, boolean swimAiEnabled, int chunkLoadRadius) { if (!isAlive()) return; final String tier = chatTier, rcc = rightClickCmd, pers = aiPersonality; enqueue( () -> { if (!isAlive()) return; String sql = "UPDATE fpp_active_bots SET" + " frozen=?,chat_enabled=?,chat_tier=?,right_click_cmd=?," + "ai_personality=?,pickup_items=?,pickup_xp=?,head_ai_enabled=?," + "nav_parkour=?,nav_break_blocks=?,nav_place_blocks=?,swim_ai_enabled=?,chunk_load_radius=?" + " WHERE bot_uuid=?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setBoolean(1, frozen); ps.setBoolean(2, chatEnabled); if (tier != null) ps.setString(3, tier); else ps.setNull(3, java.sql.Types.VARCHAR); if (rcc != null) ps.setString(4, rcc); else ps.setNull(4, java.sql.Types.VARCHAR); if (pers != null) ps.setString(5, pers); else ps.setNull(5, java.sql.Types.VARCHAR); ps.setBoolean(6, pickUpItems); ps.setBoolean(7, pickUpXp); ps.setBoolean(8, headAiEnabled); ps.setBoolean(9, navParkour); ps.setBoolean(10, navBreakBlocks); ps.setBoolean(11, navPlaceBlocks); ps.setBoolean(12, swimAiEnabled); ps.setInt(13, chunkLoadRadius); ps.setString(14, uuid); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB updateBotAllSettings: " + e.getMessage()); } }); }
public boolean isMysql() { return isMysql; }
public Map<String, BotRecord> getActiveRecords() { return Collections.unmodifiableMap(activeRecords); }
public void saveBotTasks(List<BotTaskRow> rows) { if (!isAlive()) return; final List<BotTaskRow> snap = new ArrayList<>(rows); final String sid = Config.serverId(); enqueue( () -> { if (!isAlive()) return;
try (PreparedStatement ps = connection.prepareStatement( "DELETE FROM fpp_bot_tasks WHERE server_id=?")) { ps.setString(1, sid); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error("DB saveBotTasks (clear): " + e.getMessage()); return; } if (snap.isEmpty()) return;
String sql = isMysql ? "INSERT INTO fpp_bot_tasks" + " (bot_uuid,server_id,task_type,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,once_flag,extra_str,extra_bool)" + " VALUES (?,?,?,?,?,?,?,?,?,?,?,?) ON DUPLICATE KEY" + " UPDATE" + " world_name=VALUES(world_name),pos_x=VALUES(pos_x)," + "pos_y=VALUES(pos_y),pos_z=VALUES(pos_z),pos_yaw=VALUES(pos_yaw)," + "pos_pitch=VALUES(pos_pitch),once_flag=VALUES(once_flag)," + "extra_str=VALUES(extra_str),extra_bool=VALUES(extra_bool)" : "INSERT OR REPLACE INTO fpp_bot_tasks" + " (bot_uuid,server_id,task_type,world_name,pos_x,pos_y,pos_z,pos_yaw,pos_pitch,once_flag,extra_str,extra_bool)" + " VALUES (?,?,?,?,?,?,?,?,?,?,?,?)"; for (BotTaskRow row : snap) { try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, row.botUuid()); ps.setString(2, row.serverId()); ps.setString(3, row.taskType()); if (row.worldName() != null) ps.setString(4, row.worldName()); else ps.setNull(4, java.sql.Types.VARCHAR); ps.setDouble(5, row.posX()); ps.setDouble(6, row.posY()); ps.setDouble(7, row.posZ()); ps.setFloat(8, row.posYaw()); ps.setFloat(9, row.posPitch()); ps.setBoolean(10, row.onceFlag()); if (row.extraStr() != null) ps.setString(11, row.extraStr()); else ps.setNull(11, java.sql.Types.VARCHAR); ps.setBoolean(12, row.extraBool()); ps.executeUpdate(); } catch (SQLException e) { FppLogger.error( "DB saveBotTask(" + row.taskType() + "): " + e.getMessage()); } } Config.debug( "DB saved " + snap.size() + " bot task row(s) for server='" + sid + "'."); }); }
public List<BotTaskRow> loadBotTasksForThisServer() { List<BotTaskRow> list = new ArrayList<>(); if (!isAlive()) return list; String sql = "SELECT * FROM fpp_bot_tasks WHERE server_id=?"; try (PreparedStatement ps = connection.prepareStatement(sql)) { ps.setString(1, Config.serverId()); try (ResultSet rs = ps.executeQuery()) { while (rs.next()) list.add(mapBotTaskRow(rs)); } } catch (SQLException e) { FppLogger.error("DB loadBotTasksForThisServer: " + e.getMessage()); } return list; }
public void clearBotTasks() { final String sid = Config.serverId(); enqueue( () -> { if (!isAlive()) return; try (PreparedStatement ps = connection.prepareStatement( "DELETE FROM fpp_bot_tasks WHERE server_id=?")) { ps.setString(1, sid); int rows = ps.executeUpdate(); Config.debug( "DB cleared " + rows + " bot task row(s) for server='" + sid + "'."); } catch (SQLException e) { FppLogger.error("DB clearBotTasks: " + e.getMessage()); } }); }
private BotTaskRow mapBotTaskRow(ResultSet rs) throws SQLException { String worldName = null; try { worldName = rs.getString("world_name"); } catch (SQLException ignored) { } String extraStr = null; try { extraStr = rs.getString("extra_str"); } catch (SQLException ignored) { } boolean extraBool = false; try { extraBool = rs.getBoolean("extra_bool"); } catch (SQLException ignored) { } return new BotTaskRow( rs.getString("bot_uuid"), rs.getString("server_id"), rs.getString("task_type"), worldName, rs.getDouble("pos_x"), rs.getDouble("pos_y"), rs.getDouble("pos_z"), rs.getFloat("pos_yaw"), rs.getFloat("pos_pitch"), rs.getBoolean("once_flag"), extraStr, extraBool); }
private record PendingLocation( String world, double x, double y, double z, float yaw, float pitch) {}
public record ActiveBotRow( String botUuid, String botName, String botDisplay, String spawnedBy, String spawnedByUuid, String world, double x, double y, double z, float yaw, float pitch, String luckpermsGroup, String serverId, String aiPersonality, boolean pickUpItems, boolean pickUpXp, boolean frozen, boolean chatEnabled, String chatTier, String rightClickCmd, boolean headAiEnabled, boolean navParkour, boolean navBreakBlocks, boolean navPlaceBlocks, boolean swimAiEnabled, int chunkLoadRadius) {}
public record SleepingBotRow( int sleepOrder, String botName, String world, double x, double y, double z, float yaw, float pitch) {}
public record BotTaskRow( String botUuid, String serverId, String taskType, String worldName, double posX, double posY, double posZ, float posYaw, float posPitch, boolean onceFlag, String extraStr, boolean extraBool) {}
public record DbStats( int totalSessions, int activeSessions, int uniqueBots, int uniqueSpawners, long totalUptimeMs, String backend) {
public String formattedUptime() { long secs = totalUptimeMs / 1000; long days = secs / 86400; long hours = (secs % 86400) / 3600; long mins = (secs % 3600) / 60; if (days > 0) return days + "d " + hours + "h " + mins + "m"; if (hours > 0) return hours + "h " + mins + "m"; return mins + "m"; } }
public record SkinCacheEntry( String skinName, String textureValue, String textureSignature, String source, long cachedAt) {
public boolean isValid() { return textureValue != null && !textureValue.isEmpty(); }
public long getAgeMillis() { return System.currentTimeMillis() - cachedAt; } } }

