  }

  public static void debug(String topic, boolean enabled, String message) {
    if (!enabled) return;
    String label = (topic == null || topic.isBlank()) ? "DEBUG" : topic.trim().toUpperCase();
    logger.info(
        TAG + " " + GRAY + "[" + YELLOW + "DEBUG" + GRAY + "/" + CYAN + label + GRAY + "] " + YELLOW
            + message + RESET);
  }

  public static void highlight(String message) {
    logger.info(TAG + " " + BOLD + CYAN + message + RESET);
  }

  public static void rule() {
    logger.info(TAG + " " + DARK + "─".repeat(RULE_WIDTH) + RESET);
  }

  public static void boldRule() {
    logger.info(TAG + " " + GRAY + BOLD + "═".repeat(RULE_WIDTH) + RESET);
  }

  public static void section(String label) {
    String dashes = "─".repeat(Math.max(0, RULE_WIDTH - label.length() - 4));
    logger.info(
        TAG + " " + DARK + "── " + RESET + BOLD + WHITE + label + " " + DARK + dashes + RESET);
  }

  public static void kv(String key, Object value) {
    int dots = Math.max(1, KEY_WIDTH - key.length());
    String dotStr = DARK + ".".repeat(dots) + RESET;
    logger.info(TAG + " " + GRAY + "  " + WHITE + key + " " + dotStr + " " + BLUE + value + RESET);
  }

  public static void statusRow(boolean ok, String label, String detail) {
    String badge = ok ? GREEN + "[+]" + RESET : RED + "[✘]" + RESET;
    int dots = Math.max(1, KEY_WIDTH - label.length());
    String dotStr = DARK + ".".repeat(dots) + RESET;
    String valueColor = ok ? GREEN : GRAY;
    logger.info(
        TAG
            + " "
            + GRAY
            + "  "
            + badge
            + " "
            + WHITE
            + label
            + " "
            + dotStr
            + " "
            + valueColor
            + detail
            + RESET);
  }

  private static void stateRow(RowState state, String label, String detail) {
    String badge;
    String valueColor;
    switch (state) {
      case OK -> {
        badge = GREEN + "[+]" + RESET;
        valueColor = GREEN;
      }
      case WARN -> {
        badge = YELLOW + "[!]" + RESET;
        valueColor = YELLOW;
      }
      default -> {
        badge = GRAY + "[-]" + RESET;
        valueColor = GRAY;
      }
    }

    int dots = Math.max(1, KEY_WIDTH - label.length());
    String dotStr = DARK + ".".repeat(dots) + RESET;
    logger.info(
        TAG
            + " "
            + GRAY
            + "  "
            + badge
            + " "
            + WHITE
            + label
            + " "
            + dotStr
            + " "
            + valueColor
            + detail
            + RESET);
  }

  @SuppressWarnings("unused")
  public static void blank() {
    logger.info("");
  }

  public static void printStartupBanner(
      String version,
      String authors,
      int namePoolSize,
      int msgPoolSize,
      String dbState,
      int dbSchemaVersion,
      String skinMode,
      boolean bodyEnabled,
      boolean persistEnabled,
      boolean taskPersistEnabled,
      boolean luckPermsFound,
      boolean worldGuardFound,
      boolean nameTagFound,
      boolean fakeChatEnable,
      boolean aiConversationsEnabled,
      String aiProviderName,
      boolean swapEnable,
      boolean peakHoursEnable,
      boolean chunkLoading,
      int maxBots,
      boolean metricsActive,
      String configVersion,
      int backupCount,
      long startupMs) {
    boldRule();
    info("  " + BOLD + BLUE + "FakePlayerPlugin" + RESET + WHITE + " v" + version + RESET);
    rule();

    section("Runtime");
    String dbDisplay =
        dbSchemaVersion > 0 ? dbState + "  (schema v" + dbSchemaVersion + ")" : dbState;
    stateRow(resolveDbState(dbState), "Database", dbDisplay);
    kv("Config version", configVersion);
    kv("Backups", backupCount);
    kv("Startup time", startupMs + "ms");

    section("Features");
    stateRow(bodyEnabled ? RowState.OK : RowState.OFF, "Physical bodies", onOff(bodyEnabled));
    stateRow(persistEnabled ? RowState.OK : RowState.OFF, "Persistence", onOff(persistEnabled));
    stateRow(
        taskPersistEnabled ? RowState.OK : RowState.OFF,
        "Task persistence",
        taskPersistEnabled ? "db + yaml" : onOff(false));
    stateRow(chunkLoading ? RowState.OK : RowState.OFF, "Chunk loading", onOff(chunkLoading));
    stateRow(fakeChatEnable ? RowState.OK : RowState.OFF, "Fake chat", onOff(fakeChatEnable));
    stateRow(
        aiConversationsEnabled ? RowState.OK : RowState.OFF,
        "AI converse",
        aiConversationsEnabled ? "enabled  (" + aiProviderName + ")" : "disabled");
    stateRow(swapEnable ? RowState.OK : RowState.OFF, "Bot swap", onOff(swapEnable));
    stateRow(peakHoursEnable ? RowState.OK : RowState.OFF, "Peak hours", onOff(peakHoursEnable));

    section("Integrations");
    stateRow(luckPermsFound ? RowState.OK : RowState.OFF, "LuckPerms", onOff(luckPermsFound));
    stateRow(worldGuardFound ? RowState.OK : RowState.OFF, "WorldGuard", onOff(worldGuardFound));
    stateRow(nameTagFound ? RowState.OK : RowState.OFF, "NameTag", onOff(nameTagFound));
    stateRow(metricsActive ? RowState.OK : RowState.OFF, "Metrics", onOff(metricsActive));

    section("Pools & Limits");
    kv("Name pool", namePoolSize);
    kv("Message pool", msgPoolSize);
    kv("Skin mode", skinMode);
    kv("Max bots", maxBots == 0 ? "unlimited" : maxBots);

    if (Config.isDebug()) {
      section("Debug");
      kv("Authors", authors);
    }

    rule();
    success("  Ready: /fpp help");
    boldRule();
  }

  public static void printShutdownBanner(
      int botsRemoved, boolean dbFlushed, boolean tasksPersisted, int botsSaved, long uptimeMs) {
    boldRule();
    highlight("  ꜰᴀᴋᴇ ᴘʟᴀʏᴇʀ ᴘʟᴜɢɪɴ  -  shutting down");
    rule();
    kv("Bots removed", botsRemoved);
    kv("Bots saved", botsSaved > 0 ? botsSaved + " ✔" : "none");
    kv("Tasks persisted", tasksPersisted ? "db + yaml ✔" : "yaml only");
    kv("DB sessions", dbFlushed ? "flushed ✔" : "skipped (no DB)");
    kv("Session uptime", formatUptime(uptimeMs));
    boldRule();
    info("  Goodbye! ꜰᴀᴋᴇ ᴘʟᴀʏᴇʀ ᴘʟᴜɢɪɴ has been disabled.");
    boldRule();
  }

  private static String formatUptime(long ms) {
    long totalSec = ms / 1_000;
    long hours = totalSec / 3600;
    long minutes = (totalSec % 3600) / 60;
    long seconds = totalSec % 60;
    if (hours > 0) return hours + "h " + minutes + "m " + seconds + "s";
    if (minutes > 0) return minutes + "m " + seconds + "s";
    return seconds + "s";
  }

  private static String onOff(boolean enabled) {
    return enabled ? "enabled" : "disabled";
  }

  private static RowState resolveDbState(String dbState) {
    if (dbState == null) return RowState.WARN;
    String s = dbState.toLowerCase();
    if (s.contains("failed")) return RowState.WARN;
    if (s.contains("disabled") || s.contains("none")) return RowState.OFF;
    return RowState.OK;
  }

  private enum RowState {
    OK,
    WARN,
    OFF
  }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import org.bukkit.Bukkit;

import java.io.*;
import java.lang.reflect.Method;
import java.net.URL;
import java.net.URLClassLoader;
import java.util.concurrent.Callable;

/**
 * FastStats anonymous usage metrics — developer-only, not user-configurable.
 *
 * <p>FastStats is loaded at runtime via a dedicated {@link URLClassLoader} pointing
 * to jars bundled inside the plugin jar as resources (src/main/resources/faststats/).
 * This sidesteps all Maven shade-plugin relocation issues: the shade plugin does NOT
 * update references in the project's own class files, causing NoClassDefFoundError.
 * With URLClassLoader the classes are found directly — no relocation needed.
 *
 * <p>No personal data, player names, or server addresses are ever collected.
 */
public final class FppMetrics {

    // ── Developer constant — NOT in config.yml ────────────────────────────────
    private static final String TOKEN = "376511af6c97b56954ff2abed24dfaea";

    // ─────────────────────────────────────────────────────────────────────────

    private URLClassLoader fsLoader;   // isolated classloader for FastStats jars
    private Object         metrics;    // dev.faststats.bukkit.BukkitMetrics (held as Object)
    private boolean        initialised = false;

    // ── Lifecycle ─────────────────────────────────────────────────────────────

    public void init(FakePlayerPlugin plugin, FakePlayerManager botManager) {
        if (TOKEN.isBlank()) {
            FppLogger.warn("Metrics: TOKEN is blank — FastStats disabled.");
            return;
        }

        FppLogger.info("Metrics: Initialising FastStats (token=" + TOKEN.substring(0, 8) + "...)");

        ClassLoader prevCtx = Thread.currentThread().getContextClassLoader();
        try {
            // ── 1. Extract FastStats jars from plugin resources ───────────────
            File libsDir = new File(plugin.getDataFolder(), ".faststats-libs");
            libsDir.mkdirs();

            File coreJar   = extractResource(plugin, "faststats/faststats-core.jar",   libsDir);
            File bukkitJar = extractResource(plugin, "faststats/faststats-bukkit.jar",  libsDir);

            // ── 2. Dedicated URLClassLoader ───────────────────────────────────
            // Parent = plugin's own classloader so FastStats can see Paper API,
            // java.util.concurrent.Callable, org.bukkit.plugin.Plugin, etc.
            fsLoader = new URLClassLoader(
                    new URL[]{ coreJar.toURI().toURL(), bukkitJar.toURI().toURL() },
                    plugin.getClass().getClassLoader()
            );
            // Give FastStats's SPI/ServiceLoader its own loader as context
            Thread.currentThread().setContextClassLoader(fsLoader);

            // ── 3. ErrorTracker ───────────────────────────────────────────────
            FppLogger.info("Metrics: [1/3] Creating ErrorTracker...");
            Class<?> etClass      = fsLoader.loadClass("dev.faststats.core.ErrorTracker");
            Object   errorTracker = etClass.getMethod("contextAware").invoke(null);
            FppLogger.info("Metrics:       ErrorTracker ✔");

            // ── 4. BukkitMetrics fluent factory ───────────────────────────────
            FppLogger.info("Metrics: [2/3] Building BukkitMetrics...");
            Class<?> bmClass = fsLoader.loadClass("dev.faststats.bukkit.BukkitMetrics");
            Class<?> mClass  = fsLoader.loadClass("dev.faststats.core.data.Metric");

            Method numberMethod = findMethod(mClass, "number", 2);
            Method stringMethod = findMethod(mClass, "string", 2);

            Object factory = bmClass.getMethod("factory").invoke(null);
            factory = chain(factory, "token",        TOKEN);

            factory = addMetric(factory, numberMethod.invoke(null, "active_bots",
                    (Callable<Long>) () -> (long) (botManager == null ? 0 : botManager.getCount())));
            factory = addMetric(factory, numberMethod.invoke(null, "online_players",
                    (Callable<Long>) () -> (long) Bukkit.getOnlinePlayers().size()));
            factory = addMetric(factory, stringMethod.invoke(null, "skin_mode",
                    (Callable<String>) Config::skinMode));
            factory = addMetric(factory, numberMethod.invoke(null, "persistence_enabled",
                    (Callable<Long>) () -> Config.persistOnRestart() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "body_enabled",
                    (Callable<Long>) () -> Config.spawnBody() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "fake_chat_enabled",
                    (Callable<Long>) () -> Config.fakeChatEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "swap_enabled",
                    (Callable<Long>) () -> Config.swapEnabled() ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "chunk_loading_enabled",
                    (Callable<Long>) () -> Config.chunkLoadingEnabled() ? 1L : 0L));
            factory = addMetric(factory, stringMethod.invoke(null, "database_type",
                    (Callable<String>) () -> Config.mysqlEnabled() ? "mysql" : "sqlite"));
            factory = addMetric(factory, numberMethod.invoke(null, "luckperms_prefix_enabled",
                    (Callable<Long>) () -> (Bukkit.getPluginManager().getPlugin("LuckPerms") != null
                            && Config.luckpermsUsePrefix()) ? 1L : 0L));
            factory = addMetric(factory, numberMethod.invoke(null, "max_bots_config",
                    (Callable<Long>) () -> (long) Config.maxBots()));

            factory = chain(factory, "errorTracker", errorTracker);
            factory = chain(factory, "debug",        false);
            FppLogger.info("Metrics:       BukkitMetrics built ✔");

            // ── 5. Create and arm ─────────────────────────────────────────────
            FppLogger.info("Metrics: [3/3] Calling ready()...");
            metrics = chain(factory, "create", plugin);
            findMethod(metrics.getClass(), "ready", 0).invoke(metrics);
            initialised = true;
            FppLogger.success("Metrics: FastStats connected and reporting ✔");

        } catch (Throwable t) {
            FppLogger.error("╔══════════════════════════════════════════════════");
            FppLogger.error("║  Metrics: FastStats init FAILED");
            FppLogger.error("║  " + t.getClass().getName() + ": " + t.getMessage());
            Throwable c = t; int d = 0;
            while (c.getCause() != null && d++ < 6) {
                c = c.getCause();
                FppLogger.error("║  Caused by: " + c.getClass().getName() + ": " + c.getMessage());
            }
            FppLogger.error("║  Stack (top 10):");
            StackTraceElement[] st = t.getStackTrace();
            for (int i = 0; i < Math.min(10, st.length); i++) FppLogger.error("║    at " + st[i]);
            FppLogger.error("╚══════════════════════════════════════════════════");
            metrics = null;
            closeLoader();
        } finally {
            Thread.currentThread().setContextClassLoader(prevCtx);
        }
    }

    public void shutdown() {
        if (metrics != null && initialised) {
            try { findMethod(metrics.getClass(), "shutdown", 0).invoke(metrics); } catch (Throwable ignored) {}
            metrics = null;
        }
        initialised = false;
        closeLoader();
    }

    public boolean isActive() { return initialised && metrics != null; }

    // ── Reflection helpers ────────────────────────────────────────────────────

    /** Invoke the first method named {@code name} with {@code args.length} params on {@code obj}. */
    private static Object chain(Object obj, String name, Object... args) throws ReflectiveOperationException {
        for (Method m : obj.getClass().getMethods()) {
            if (m.getName().equals(name) && m.getParameterCount() == args.length) {
                try { return m.invoke(obj, args); } catch (IllegalArgumentException ignored) {}
            }
        }
        throw new NoSuchMethodException(obj.getClass().getSimpleName() + "." + name + "/" + args.length);
    }

    /** Find the first public method named {@code name} with exactly {@code paramCount} params. */
    private static Method findMethod(Class<?> cls, String name, int paramCount) throws NoSuchMethodException {
        for (Method m : cls.getMethods()) {
            if (m.getName().equals(name) && m.getParameterCount() == paramCount) return m;
        }
        throw new NoSuchMethodException(cls.getSimpleName() + "." + name + "/" + paramCount);
    }

    /** Call {@code addMetric(metric)} on the factory and return the updated factory. */
    private static Object addMetric(Object factory, Object metric) throws ReflectiveOperationException {
        for (Method m : factory.getClass().getMethods()) {
            if (m.getName().equals("addMetric") && m.getParameterCount() == 1) {
                try { return m.invoke(factory, metric); } catch (IllegalArgumentException ignored) {}
            }
        }
        throw new NoSuchMethodException("addMetric");
    }

    // ── Resource extraction ───────────────────────────────────────────────────

    private static File extractResource(FakePlayerPlugin plugin, String resourcePath, File destDir)
            throws IOException {
        String fileName = resourcePath.substring(resourcePath.lastIndexOf('/') + 1);
        File   dest     = new File(destDir, fileName);
        try (InputStream in = plugin.getResource(resourcePath)) {
            if (in == null) throw new IOException("Bundled resource not found: " + resourcePath);
            byte[] data = in.readAllBytes();
            if (!dest.exists() || dest.length() != data.length) {
                try (OutputStream out = new FileOutputStream(dest)) { out.write(data); }
                FppLogger.info("Metrics: extracted " + fileName + " (" + data.length / 1024 + " KB)");
            }
        }
        return dest;
    }

    private void closeLoader() {
        if (fsLoader != null) {
            try { fsLoader.close(); } catch (IOException ignored) {}
            fsLoader = null;
        }
    }
}

