package me.bill.fakePlayerPlugin.gui;

import me.bill.fakePlayerPlugin.command.CommandManager;
import me.bill.fakePlayerPlugin.command.FppCommand;

import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;

import org.bukkit.Bukkit;
import org.bukkit.Material;
import org.bukkit.Sound;
import org.bukkit.SoundCategory;
import org.bukkit.enchantments.Enchantment;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerQuitEvent;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemFlag;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.plugin.Plugin;

import java.util.*;

public final class HelpGui implements Listener {

    // ── Palette ───────────────────────────────────────────────────────────────
    private static final TextColor ACCENT    = TextColor.fromHexString("#0079FF");
    private static final TextColor ON_GREEN  = TextColor.fromHexString("#66CC66");
    private static final TextColor ORANGE    = TextColor.fromHexString("#FFA500");
    private static final TextColor DARK_GRAY = NamedTextColor.DARK_GRAY;
    private static final TextColor GRAY      = NamedTextColor.GRAY;
    private static final TextColor WHITE     = NamedTextColor.WHITE;
    private static final TextColor YELLOW    = NamedTextColor.YELLOW;

    // Usage token colours
    private static final TextColor ARG_REQUIRED = TextColor.fromHexString("#FF8C00");
    private static final TextColor ARG_OPTIONAL = TextColor.fromHexString("#AAAAAA");
    private static final TextColor ARG_FLAG     = TextColor.fromHexString("#00CFFF");
    private static final TextColor ARG_CHOICE   = TextColor.fromHexString("#FFDD57");

    // Category colours
    private static final TextColor CAT_ALL    = TextColor.fromHexString("#FFFFFF");
    private static final TextColor CAT_CORE   = TextColor.fromHexString("#5B9BD5");
    private static final TextColor CAT_BOT    = TextColor.fromHexString("#70AD47");
    private static final TextColor CAT_ACTION = TextColor.fromHexString("#ED7D31");
    private static final TextColor CAT_CHAT   = TextColor.fromHexString("#9E7FD4");
    private static final TextColor CAT_ADMIN  = TextColor.fromHexString("#C0504D");

    // ── Categories ────────────────────────────────────────────────────────────
    private enum Category {
        ALL    ("ᴀʟʟ",     CAT_ALL,    Material.COMPASS,                  Material.COMPASS,                  "ꜱʜᴏᴡꜱ ᴇᴠᴇʀʏ ᴀᴠᴀɪʟᴀʙʟᴇ ᴄᴏᴍᴍᴀɴᴅ."),
        CORE   ("ᴄᴏʀᴇ",   CAT_CORE,   Material.NETHER_STAR,              Material.GRAY_DYE,                 "ꜱᴘᴀᴡɴ, ᴅᴇꜱᴘᴀᴡɴ, ʟɪꜱᴛ, ɪɴꜰᴏ & ᴍᴏʀᴇ."),
        BOTS   ("ʙᴏᴛꜱ",   CAT_BOT,    Material.PLAYER_HEAD,              Material.SKELETON_SKULL,           "ᴘᴇʀ-ʙᴏᴛ ᴍᴀɴᴀɢᴇᴍᴇɴᴛ ᴄᴏᴍᴍᴀɴᴅꜱ."),
        ACTIONS("ᴀᴄᴛɪᴏɴꜱ",CAT_ACTION, Material.DIAMOND_PICKAXE,          Material.IRON_PICKAXE,             "ɴᴀᴠ, ᴍɪɴɪɴɢ, ᴘʟᴀᴄɪɴɢ & ᴜꜱᴇ."),
        CHAT   ("ᴄʜᴀᴛ",   CAT_CHAT,   Material.WRITABLE_BOOK,            Material.BOOK,                     "ᴄʜᴀᴛ, ᴀɪ & ꜰɪʟᴛᴇʀꜱ."),
        ADMIN  ("ᴀᴅᴍɪɴ",  CAT_ADMIN,  Material.COMMAND_BLOCK,            Material.REPEATING_COMMAND_BLOCK,  "ꜱᴡᴀᴘ, ᴘᴇᴀᴋꜱ, ꜱʏɴᴄ & ᴀᴅᴍɪɴ.");

        final String label;
        final TextColor color;
        final Material activeMat;
        final Material inactiveMat;
        final String tooltip;

        Category(String label, TextColor color,
                 Material activeMat, Material inactiveMat, String tooltip) {
            this.label       = label;
            this.color       = color;
            this.activeMat   = activeMat;
            this.inactiveMat = inactiveMat;
            this.tooltip     = tooltip;
        }
    }

    // Ordered array so we can reference by index
    private static final Category[] CATEGORIES = Category.values();

    // ── Layout — mirrors BotSettingGui ────────────────────────────────────────
    private static final int SIZE          = 54;
    private static final int CMDS_PER_PAGE = 45;

    // Bottom row (slots 45-53):
    // 45=PagePrev  46=filler  47-52=CategoryTabs  53=PageNext
    private static final int SLOT_PAGE_PREV  = 45;
    private static final int CAT_SLOT_START  = 47;   // tabs at 47,48,49,50,51,52
    private static final int SLOT_PAGE_NEXT  = 53;

    // ── Session state ─────────────────────────────────────────────────────────
    private record Session(int page, int catIdx, String alias) {
        Session withPage(int p)   { return new Session(p, catIdx, alias); }
        Session withCat(int c)    { return new Session(0, c, alias); }
        Category category()       { return CATEGORIES[catIdx]; }
    }

    private final Plugin plugin;
    private final CommandManager commandManager;
    private final Map<UUID, Session> sessions     = new HashMap<>();
    private final Set<UUID>          pendingRebuild = new HashSet<>();  // mirrors BotSettingGui

    public HelpGui(Plugin plugin, CommandManager commandManager) {
        this.plugin = plugin;
        this.commandManager = commandManager;
    }

    // ── Public API ────────────────────────────────────────────────────────────

    /** Opens the help GUI, honouring the root alias the player typed (e.g. "fpp" or "fp"). */
    public void open(Player player, String alias) {
        sessions.put(player.getUniqueId(), new Session(0, 0, alias));
        build(player);
    }

    /** Convenience overload — defaults to "fpp". */
    public void open(Player player) { open(player, "fpp"); }

    // ── Events ────────────────────────────────────────────────────────────────

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder holder)) return;
        event.setCancelled(true);
        if (!(event.getWhoClicked() instanceof Player player)) return;
        if (event.getClickedInventory() == null
                || !event.getClickedInventory().equals(event.getInventory())) return;

        UUID uuid = player.getUniqueId();
        Session session = sessions.get(uuid);
        if (session == null) return;

        int slot       = event.getSlot();
        int totalPages = totalPages(player, session.category());

        if (slot == SLOT_PAGE_PREV) {
            if (session.page() > 0) {
                sessions.put(uuid, session.withPage(session.page() - 1));
                playClick(player, 1.0f);
                build(player);
            }
        } else if (slot == SLOT_PAGE_NEXT) {
            if (session.page() < totalPages - 1) {
                sessions.put(uuid, session.withPage(session.page() + 1));
                playClick(player, 1.0f);
                build(player);
            }
        } else if (slot >= CAT_SLOT_START && slot < CAT_SLOT_START + CATEGORIES.length) {
            int ci = slot - CAT_SLOT_START;
            if (ci != session.catIdx()) {
                playClick(player, 1.3f);
            }
            sessions.put(uuid, session.withCat(ci));
            build(player);
        } else if (slot < CMDS_PER_PAGE) {
            int idx = session.page() * CMDS_PER_PAGE + slot;
            if (idx < filteredCommands(player, session.category()).size())
                playClick(player, 1.3f);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder)) return;
        UUID uuid = event.getPlayer().getUniqueId();
        if (pendingRebuild.contains(uuid)) return;   // ← critical: mirrors BotSettingGui
        sessions.remove(uuid);
    }

    @EventHandler
    public void onPlayerQuit(PlayerQuitEvent event) {
        sessions.remove(event.getPlayer().getUniqueId());
    }

    // ── Build ─────────────────────────────────────────────────────────────────

    private void build(Player player) {
        UUID uuid = player.getUniqueId();
        Session raw = sessions.get(uuid);
        if (raw == null) return;

        List<FppCommand> visible  = filteredCommands(player, raw.category());
        int totalPages            = Math.max(1, (int) Math.ceil(visible.size() / (double) CMDS_PER_PAGE));
        int page                  = Math.min(raw.page(), totalPages - 1);
        Session session           = raw.withPage(page);
        sessions.put(uuid, session);

        Holder holder = new Holder(uuid);

        // Title — [ꜰᴘᴘ] ᴄᴏᴍᴍᴀɴᴅꜱ  ·  category  (matches BotSettingGui title style)
        String catLabel = session.category() == Category.ALL
                ? "ᴄᴏᴍᴍᴀɴᴅꜱ"
                : session.category().label + " ᴄᴏᴍᴍᴀɴᴅꜱ";
        Component title = Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("[").color(DARK_GRAY))
                .append(Component.text("ꜰᴘᴘ").color(ACCENT))
                .append(Component.text("] ").color(DARK_GRAY))
                .append(Component.text(catLabel).color(DARK_GRAY));

        Inventory inv = Bukkit.createInventory(holder, SIZE, title);

        // Command items (rows 1-5, slots 0-44)
        int start = page * CMDS_PER_PAGE;
        int end   = Math.min(start + CMDS_PER_PAGE, visible.size());
        for (int i = start; i < end; i++) {
            inv.setItem(i - start, buildCommandItem(visible.get(i), session.alias()));
        }

        // Bottom bar — fill all 9 first, then place controls
        ItemStack filler = glassFiller(Material.GRAY_STAINED_GLASS_PANE);
        for (int s = 45; s <= 53; s++) inv.setItem(s, filler);

        // Page prev (slot 45) — matches BotSettingGui SLOT_CAT_PREV position
        inv.setItem(SLOT_PAGE_PREV,
                page > 0
                        ? buildNavArrow(false, page)
                        : filler);

        // Page indicator (slot 46)
        inv.setItem(SLOT_PAGE_IND, buildPageIndicator(page + 1, totalPages));

        // Category tabs (slots 47-52, one per category)
        for (int i = 0; i < CATEGORIES.length; i++) {
            inv.setItem(CAT_SLOT_START + i,
                    buildCategoryTab(CATEGORIES[i], i == session.catIdx()));
        }

        // Page next (slot 53) — matches BotSettingGui SLOT_CLOSE position
        inv.setItem(SLOT_PAGE_NEXT,
                page < totalPages - 1
                        ? buildNavArrow(true, page + 2)
                        : glassFiller(Material.GRAY_STAINED_GLASS_PANE));

        // Guard against InventoryCloseEvent wiping the session during openInventory
        pendingRebuild.add(uuid);
        player.openInventory(inv);
        pendingRebuild.remove(uuid);

        sessions.put(uuid, session);
    }

    // ── Filtering ─────────────────────────────────────────────────────────────

    private List<FppCommand> filteredCommands(Player player, Category cat) {
        return commandManager.getCommands().stream()
                .filter(cmd -> cmd.canUse(player))
                .filter(cmd -> cat == Category.ALL || categoryFor(cmd.getName()) == cat)
                .toList();
    }

    private int totalPages(Player player, Category cat) {
        return Math.max(1, (int) Math.ceil(
                filteredCommands(player, cat).size() / (double) CMDS_PER_PAGE));
    }

    // ── Category tab — identical approach to BotSettingGui.buildCategoryTab ──

    private static ItemStack buildCategoryTab(Category cat, boolean active) {
        ItemStack item = new ItemStack(active ? cat.activeMat : cat.inactiveMat);
        ItemMeta  meta = item.getItemMeta();

        if (active) {
            meta.addEnchant(Enchantment.UNBREAKING, 1, true);
            meta.addItemFlags(ItemFlag.HIDE_ENCHANTS);
        }

        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(cat.label)
                                .color(ACCENT)
                                .decoration(TextDecoration.BOLD, active)));

        meta.lore(List.of(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(active ? "◈  ᴄᴜʀʀᴇɴᴛʟʏ ᴠɪᴇᴡɪɴɢ" : "ᴄʟɪᴄᴋ ᴛᴏ ꜱᴡɪᴛᴄʜ")
                                .color(active ? ON_GREEN : DARK_GRAY))));

        item.setItemMeta(meta);
        return item;
    }

    // ── Command item ──────────────────────────────────────────────────────────

    private static ItemStack buildCommandItem(FppCommand cmd, String alias) {
        String name   = cmd.getName();
        String prefix = "/" + alias + " ";

        ItemStack item = new ItemStack(iconFor(name));
        ItemMeta  meta = item.getItemMeta();

        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(prefix).color(DARK_GRAY)
                                .decoration(TextDecoration.BOLD, true))
                        .append(Component.text(name).color(ACCENT)
                                .decoration(TextDecoration.BOLD, true)));

        List<Component> lore = new ArrayList<>();
        lore.add(Component.empty());

        // Category badge
        Category cat = categoryFor(name);
        lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(cat.label).color(cat.color)
                        .decoration(TextDecoration.BOLD, true)));
        lore.add(divider());

        // Description
        String desc = cmd.getDescription();
        if (desc != null && !desc.isBlank()) {
            for (String line : wrapText(desc, 36)) {
                lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(line).color(GRAY)));
            }
        }

        // Usage
        String usage = cmd.getUsage();
        if (usage != null && !usage.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴜꜱᴀɢᴇ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true)));
            for (String mode : splitModes(usage)) {
                lore.add(buildUsageLine(name, mode, alias));
            }
        }

        // Aliases
        List<String> aliases = cmd.getAliases();
        if (!aliases.isEmpty()) {
            lore.add(Component.empty());
            Component row = Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴀʟɪᴀꜱ  ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true));
            for (int i = 0; i < aliases.size(); i++) {
                row = row.append(Component.text(aliases.get(i)).color(ACCENT));
                if (i < aliases.size() - 1)
                    row = row.append(Component.text(", ").color(DARK_GRAY));
            }
            lore.add(row);
        }

        // Permission
        String perm = cmd.getPermission();
        if (perm != null && !perm.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴘᴇʀᴍ  ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true))
                    .append(Component.text(perm).color(YELLOW)));
        }

        lore.add(Component.empty());
        lore.add(hint("◈ ", "ᴄʟɪᴄᴋ ᴛᴏ ᴠɪᴇᴡ ᴅᴇᴛᴀɪʟꜱ"));

        meta.lore(lore);
        item.setItemMeta(meta);
        return item;
    }

    private static Component buildUsageLine(String cmdName, String mode, String alias) {
        Component line = Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("  ▸ ").color(DARK_GRAY))
                .append(Component.text("/" + alias + " " + cmdName + " ").color(DARK_GRAY));

        for (String t : mode.split(" ")) {
            TextColor col;
            if      (t.startsWith("<") && t.endsWith(">"))  col = ARG_REQUIRED;
            else if (t.startsWith("[") && t.endsWith("]"))  col = ARG_OPTIONAL;
            else if (t.startsWith("--"))                    col = ARG_FLAG;
            else if (t.contains("|"))                       col = ARG_CHOICE;
            else                                            col = WHITE;
            line = line.append(Component.text(t + " ").color(col));
        }
        return line;
    }

    /**
     * Splits usage on bare {@code |} only — pipes INSIDE {@code <...>}/{@code [...]} are kept.
     * e.g. {@code "[all|config|lang]"} → single mode; {@code "<bot> | stop"} → two modes.
     */
    private static List<String> splitModes(String usage) {
        List<String> modes = new ArrayList<>();
        int depth = 0;
        StringBuilder sb = new StringBuilder();
        for (char c : usage.toCharArray()) {
            if      (c == '<' || c == '[') { depth++;                               sb.append(c); }
            else if (c == '>' || c == ']') { depth = Math.max(0, depth - 1);       sb.append(c); }
            else if (c == '|' && depth == 0) {
                String part = sb.toString().trim();
                if (!part.isEmpty()) modes.add(part);
                sb.setLength(0);
            } else { sb.append(c); }
        }
        String last = sb.toString().trim();
        if (!last.isEmpty()) modes.add(last);
        return modes.isEmpty() ? List.of(usage) : modes;
    }

    // ── Category mapping ──────────────────────────────────────────────────────

    private static Category categoryFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn", "despawn", "list", "info", "help",
                 "stats", "reload", "settings", "migrate"    -> Category.CORE;
            case "tp", "tph", "freeze", "rename", "ping",
                 "inventory", "inv", "cmd", "xp"             -> Category.BOTS;
            case "move", "mine", "place", "use",
                 "storage", "waypoint", "wp"                 -> Category.ACTIONS;
            case "chat", "personality", "persona", "badword" -> Category.CHAT;
            default                                           -> Category.ADMIN;
        };
    }

    // ── Icons ─────────────────────────────────────────────────────────────────

    private static Material iconFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn"                    -> Material.PLAYER_HEAD;
            case "despawn", "delete"        -> Material.BONE;
            case "list"                     -> Material.BOOK;
            case "help"                     -> Material.KNOWLEDGE_BOOK;
            case "info"                     -> Material.MAP;
            case "chat"                     -> Material.PAPER;
            case "reload"                   -> Material.NETHER_STAR;
            case "freeze"                   -> Material.PACKED_ICE;
            case "stats"                    -> Material.CLOCK;
            case "tp"                       -> Material.ENDER_PEARL;
            case "tph"                      -> Material.ENDER_EYE;
            case "rank"                     -> Material.GOLDEN_CHESTPLATE;
            case "lpinfo"                   -> Material.GOLDEN_HELMET;
            case "move"                     -> Material.COMPASS;
            case "inventory", "inv"         -> Material.CHEST;
            case "cmd"                      -> Material.COMMAND_BLOCK;
            case "mine"                     -> Material.DIAMOND_PICKAXE;
            case "use"                      -> Material.WOODEN_AXE;
            case "swap"                     -> Material.RECOVERY_COMPASS;
            case "peaks"                    -> Material.SUNFLOWER;
            case "settings"                 -> Material.COMPARATOR;
            case "migrate"                  -> Material.ANVIL;
            case "sync"                     -> Material.OBSERVER;
            case "alert"                    -> Material.BELL;
            case "xp"                       -> Material.EXPERIENCE_BOTTLE;
            case "ping"                     -> Material.LIME_DYE;
            case "badword"                  -> Material.BARRIER;
            case "rename"                   -> Material.NAME_TAG;
            case "personality", "persona"   -> Material.WRITABLE_BOOK;
            case "waypoint", "wp"           -> Material.LODESTONE;
            case "storage"                  -> Material.BARREL;
            case "place"                    -> Material.OAK_PLANKS;
            default                         -> Material.PAPER;
        };
    }

    // ── Navigation items ──────────────────────────────────────────────────────

    /** Matches BotSettingGui.buildCatArrow */
    private static ItemStack buildNavArrow(boolean isNext, int targetPage) {
        Material mat = isNext ? Material.LIME_STAINED_GLASS_PANE
                               : Material.MAGENTA_STAINED_GLASS_PANE;
        TextColor col = isNext ? ON_GREEN : ORANGE;
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(isNext ? "▶" : "◄")
                                .color(col)
                                .decoration(TextDecoration.BOLD, true)));
        meta.lore(List.of(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(
                                (isNext ? "ɴᴇxᴛ ᴘᴀɢᴇ" : "ᴘʀᴇᴠ ᴘᴀɢᴇ") + " (" + targetPage + ")")
                                .color(DARK_GRAY))));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildPageIndicator(int page, int total) {
        ItemStack item = new ItemStack(Material.LIGHT_BLUE_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text("ᴘᴀɢᴇ ").color(GRAY))
                        .append(Component.text(page).color(WHITE)
                                .decoration(TextDecoration.BOLD, true))
                        .append(Component.text(" / ").color(DARK_GRAY))
                        .append(Component.text(total).color(WHITE)
                                .decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack glassFiller(Material mat) {
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false));
        meta.lore(List.of());
        item.setItemMeta(meta);
        return item;
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private static Component divider() {
        return Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("  ─────────────────────")
                        .color(TextColor.fromHexString("#2A2A2A")));
    }

    private static Component hint(String icon, String text) {
        return Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(icon).color(ACCENT))
                .append(Component.text(text).color(DARK_GRAY));
    }

    private static void playClick(Player player, float pitch) {
        player.playSound(player.getLocation(),
                Sound.UI_BUTTON_CLICK, SoundCategory.MASTER, 0.5f, pitch);
    }

    private static List<String> wrapText(String text, int maxLen) {
        if (text.length() <= maxLen) return List.of(text);
        List<String> lines = new ArrayList<>();
        String[] words = text.split(" ");
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            if (!sb.isEmpty() && sb.length() + 1 + word.length() > maxLen) {
                lines.add(sb.toString());
                sb.setLength(0);
            }
            if (!sb.isEmpty()) sb.append(' ');
            sb.append(word);
        }
        if (!sb.isEmpty()) lines.add(sb.toString());
        return lines;
    }

    // ── Holder ────────────────────────────────────────────────────────────────

    public static final class Holder implements InventoryHolder {
        public final UUID uuid;
        Holder(UUID uuid) { this.uuid = uuid; }

        @SuppressWarnings("NullableProblems")
        @Override public Inventory getInventory() { return null; }
    }
}

package me.bill.fakePlayerPlugin.gui;

import me.bill.fakePlayerPlugin.command.CommandManager;
import me.bill.fakePlayerPlugin.command.FppCommand;

import net.kyori.adventure.text.Component;
import net.kyori.adventure.text.format.NamedTextColor;
import net.kyori.adventure.text.format.TextColor;
import net.kyori.adventure.text.format.TextDecoration;

import org.bukkit.Bukkit;
import org.bukkit.Material;
import org.bukkit.Sound;
import org.bukkit.SoundCategory;
import org.bukkit.enchantments.Enchantment;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.inventory.InventoryClickEvent;
import org.bukkit.event.inventory.InventoryCloseEvent;
import org.bukkit.event.player.PlayerQuitEvent;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemFlag;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.meta.ItemMeta;
import org.bukkit.plugin.Plugin;

import java.util.*;

public final class HelpGui implements Listener {

    // ── Palette ───────────────────────────────────────────────────────────────
    private static final TextColor ACCENT    = TextColor.fromHexString("#0079FF");
    private static final TextColor ON_GREEN  = TextColor.fromHexString("#66CC66");
    private static final TextColor ORANGE    = TextColor.fromHexString("#FFA500");
    private static final TextColor DARK_GRAY = NamedTextColor.DARK_GRAY;
    private static final TextColor GRAY      = NamedTextColor.GRAY;
    private static final TextColor WHITE     = NamedTextColor.WHITE;
    private static final TextColor YELLOW    = NamedTextColor.YELLOW;

    // Usage token colours
    private static final TextColor ARG_REQUIRED = TextColor.fromHexString("#FF8C00");
    private static final TextColor ARG_OPTIONAL = TextColor.fromHexString("#AAAAAA");
    private static final TextColor ARG_FLAG     = TextColor.fromHexString("#00CFFF");
    private static final TextColor ARG_CHOICE   = TextColor.fromHexString("#FFDD57");

    // Category colours
    private static final TextColor CAT_ALL    = TextColor.fromHexString("#FFFFFF");
    private static final TextColor CAT_CORE   = TextColor.fromHexString("#5B9BD5");
    private static final TextColor CAT_BOT    = TextColor.fromHexString("#70AD47");
    private static final TextColor CAT_ACTION = TextColor.fromHexString("#ED7D31");
    private static final TextColor CAT_CHAT   = TextColor.fromHexString("#9E7FD4");
    private static final TextColor CAT_ADMIN  = TextColor.fromHexString("#C0504D");

    // ── Categories ────────────────────────────────────────────────────────────
    private enum Category {
        ALL    ("ᴀʟʟ",     CAT_ALL,    Material.COMPASS,                  Material.COMPASS,                  "ꜱʜᴏᴡꜱ ᴇᴠᴇʀʏ ᴀᴠᴀɪʟᴀʙʟᴇ ᴄᴏᴍᴍᴀɴᴅ."),
        CORE   ("ᴄᴏʀᴇ",   CAT_CORE,   Material.NETHER_STAR,              Material.GRAY_DYE,                 "ꜱᴘᴀᴡɴ, ᴅᴇꜱᴘᴀᴡɴ, ʟɪꜱᴛ, ɪɴꜰᴏ & ᴍᴏʀᴇ."),
        BOTS   ("ʙᴏᴛꜱ",   CAT_BOT,    Material.PLAYER_HEAD,              Material.SKELETON_SKULL,           "ᴘᴇʀ-ʙᴏᴛ ᴍᴀɴᴀɢᴇᴍᴇɴᴛ ᴄᴏᴍᴍᴀɴᴅꜱ."),
        ACTIONS("ᴀᴄᴛɪᴏɴꜱ",CAT_ACTION, Material.DIAMOND_PICKAXE,          Material.IRON_PICKAXE,             "ɴᴀᴠ, ᴍɪɴɪɴɢ, ᴘʟᴀᴄɪɴɢ & ᴜꜱᴇ."),
        CHAT   ("ᴄʜᴀᴛ",   CAT_CHAT,   Material.WRITABLE_BOOK,            Material.BOOK,                     "ᴄʜᴀᴛ, ᴀɪ & ꜰɪʟᴛᴇʀꜱ."),
        ADMIN  ("ᴀᴅᴍɪɴ",  CAT_ADMIN,  Material.COMMAND_BLOCK,            Material.REPEATING_COMMAND_BLOCK,  "ꜱᴡᴀᴘ, ᴘᴇᴀᴋꜱ, ꜱʏɴᴄ & ᴀᴅᴍɪɴ.");

        final String label;
        final TextColor color;
        final Material activeMat;
        final Material inactiveMat;
        final String tooltip;

        Category(String label, TextColor color,
                 Material activeMat, Material inactiveMat, String tooltip) {
            this.label       = label;
            this.color       = color;
            this.activeMat   = activeMat;
            this.inactiveMat = inactiveMat;
            this.tooltip     = tooltip;
        }
    }

    // Ordered array so we can reference by index
    private static final Category[] CATEGORIES = Category.values();

    // ── Layout — mirrors BotSettingGui ────────────────────────────────────────
    private static final int SIZE          = 54;
    private static final int CMDS_PER_PAGE = 45;

    // Bottom row (slots 45-53):
    // 45=PagePrev  46=filler  47-52=CategoryTabs  53=PageNext
    private static final int SLOT_PAGE_PREV  = 45;
    private static final int CAT_SLOT_START  = 47;   // tabs at 47,48,49,50,51,52
    private static final int SLOT_PAGE_NEXT  = 53;

    // ── Session state ─────────────────────────────────────────────────────────
    private record Session(int page, int catIdx, String alias) {
        Session withPage(int p)   { return new Session(p, catIdx, alias); }
        Session withCat(int c)    { return new Session(0, c, alias); }
        Category category()       { return CATEGORIES[catIdx]; }
    }

    private final Plugin plugin;
    private final CommandManager commandManager;
    private final Map<UUID, Session> sessions     = new HashMap<>();
    private final Set<UUID>          pendingRebuild = new HashSet<>();  // mirrors BotSettingGui

    public HelpGui(Plugin plugin, CommandManager commandManager) {
        this.plugin = plugin;
        this.commandManager = commandManager;
    }

    // ── Public API ────────────────────────────────────────────────────────────

    /** Opens the help GUI, honouring the root alias the player typed (e.g. "fpp" or "fp"). */
    public void open(Player player, String alias) {
        sessions.put(player.getUniqueId(), new Session(0, 0, alias));
        build(player);
    }

    /** Convenience overload — defaults to "fpp". */
    public void open(Player player) { open(player, "fpp"); }

    // ── Events ────────────────────────────────────────────────────────────────

    @EventHandler
    public void onInventoryClick(InventoryClickEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder holder)) return;
        event.setCancelled(true);
        if (!(event.getWhoClicked() instanceof Player player)) return;
        if (event.getClickedInventory() == null
                || !event.getClickedInventory().equals(event.getInventory())) return;

        UUID uuid = player.getUniqueId();
        Session session = sessions.get(uuid);
        if (session == null) return;

        int slot       = event.getSlot();
        int totalPages = totalPages(player, session.category());

        if (slot == SLOT_PAGE_PREV) {
            if (session.page() > 0) {
                sessions.put(uuid, session.withPage(session.page() - 1));
                playClick(player, 1.0f);
                build(player);
            }
        } else if (slot == SLOT_PAGE_NEXT) {
            if (session.page() < totalPages - 1) {
                sessions.put(uuid, session.withPage(session.page() + 1));
                playClick(player, 1.0f);
                build(player);
            }
        } else if (slot >= CAT_SLOT_START && slot < CAT_SLOT_START + CATEGORIES.length) {
            int ci = slot - CAT_SLOT_START;
            if (ci != session.catIdx()) {
                playClick(player, 1.3f);
            }
            sessions.put(uuid, session.withCat(ci));
            build(player);
        } else if (slot < CMDS_PER_PAGE) {
            int idx = session.page() * CMDS_PER_PAGE + slot;
            if (idx < filteredCommands(player, session.category()).size())
                playClick(player, 1.3f);
        }
    }

    @EventHandler
    public void onInventoryClose(InventoryCloseEvent event) {
        if (!(event.getInventory().getHolder() instanceof Holder)) return;
        UUID uuid = event.getPlayer().getUniqueId();
        if (pendingRebuild.contains(uuid)) return;   // ← critical: mirrors BotSettingGui
        sessions.remove(uuid);
    }

    @EventHandler
    public void onPlayerQuit(PlayerQuitEvent event) {
        sessions.remove(event.getPlayer().getUniqueId());
    }

    // ── Build ─────────────────────────────────────────────────────────────────

    private void build(Player player) {
        UUID uuid = player.getUniqueId();
        Session raw = sessions.get(uuid);
        if (raw == null) return;

        List<FppCommand> visible  = filteredCommands(player, raw.category());
        int totalPages            = Math.max(1, (int) Math.ceil(visible.size() / (double) CMDS_PER_PAGE));
        int page                  = Math.min(raw.page(), totalPages - 1);
        Session session           = raw.withPage(page);
        sessions.put(uuid, session);

        Holder holder = new Holder(uuid);

        // Title — [ꜰᴘᴘ] ᴄᴏᴍᴍᴀɴᴅꜱ  ·  category  (matches BotSettingGui title style)
        String catLabel = session.category() == Category.ALL
                ? "ᴄᴏᴍᴍᴀɴᴅꜱ"
                : session.category().label + " ᴄᴏᴍᴍᴀɴᴅꜱ";
        Component title = Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("[").color(DARK_GRAY))
                .append(Component.text("ꜰᴘᴘ").color(ACCENT))
                .append(Component.text("] ").color(DARK_GRAY))
                .append(Component.text(catLabel).color(DARK_GRAY));

        Inventory inv = Bukkit.createInventory(holder, SIZE, title);

        // Command items (rows 1-5, slots 0-44)
        int start = page * CMDS_PER_PAGE;
        int end   = Math.min(start + CMDS_PER_PAGE, visible.size());
        for (int i = start; i < end; i++) {
            inv.setItem(i - start, buildCommandItem(visible.get(i), session.alias()));
        }

        // Bottom bar — fill all 9 first, then place controls
        ItemStack filler = glassFiller(Material.GRAY_STAINED_GLASS_PANE);
        for (int s = 45; s <= 53; s++) inv.setItem(s, filler);

        // Page prev (slot 45)
        inv.setItem(SLOT_PAGE_PREV,
                page > 0 ? buildNavArrow(false, page) : filler);

        // slot 46 — filler separator

        // Category tabs (slots 47-52)
        for (int i = 0; i < CATEGORIES.length; i++) {
            inv.setItem(CAT_SLOT_START + i,
                    buildCategoryTab(CATEGORIES[i], i == session.catIdx()));
        }

        // Page next (slot 53) — matches BotSettingGui SLOT_CLOSE position
        inv.setItem(SLOT_PAGE_NEXT,
                page < totalPages - 1
                        ? buildNavArrow(true, page + 2)
                        : glassFiller(Material.GRAY_STAINED_GLASS_PANE));

        // Guard against InventoryCloseEvent wiping the session during openInventory
        pendingRebuild.add(uuid);
        player.openInventory(inv);
        pendingRebuild.remove(uuid);

        sessions.put(uuid, session);
    }

    // ── Filtering ─────────────────────────────────────────────────────────────

    private List<FppCommand> filteredCommands(Player player, Category cat) {
        return commandManager.getCommands().stream()
                .filter(cmd -> cmd.canUse(player))
                .filter(cmd -> cat == Category.ALL || categoryFor(cmd.getName()) == cat)
                .toList();
    }

    private int totalPages(Player player, Category cat) {
        return Math.max(1, (int) Math.ceil(
                filteredCommands(player, cat).size() / (double) CMDS_PER_PAGE));
    }

    // ── Category tab — identical approach to BotSettingGui.buildCategoryTab ──

    private static ItemStack buildCategoryTab(Category cat, boolean active) {
        ItemStack item = new ItemStack(active ? cat.activeMat : cat.inactiveMat);
        ItemMeta  meta = item.getItemMeta();

        if (active) {
            meta.addEnchant(Enchantment.UNBREAKING, 1, true);
            meta.addItemFlags(ItemFlag.HIDE_ENCHANTS);
        }

        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(cat.label)
                                .color(ACCENT)
                                .decoration(TextDecoration.BOLD, active)));

        meta.lore(List.of(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(active ? "◈  ᴄᴜʀʀᴇɴᴛʟʏ ᴠɪᴇᴡɪɴɢ" : "ᴄʟɪᴄᴋ ᴛᴏ ꜱᴡɪᴛᴄʜ")
                                .color(active ? ON_GREEN : DARK_GRAY))));

        item.setItemMeta(meta);
        return item;
    }

    // ── Command item ──────────────────────────────────────────────────────────

    private static ItemStack buildCommandItem(FppCommand cmd, String alias) {
        String name   = cmd.getName();
        String prefix = "/" + alias + " ";

        ItemStack item = new ItemStack(iconFor(name));
        ItemMeta  meta = item.getItemMeta();

        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(prefix).color(DARK_GRAY)
                                .decoration(TextDecoration.BOLD, true))
                        .append(Component.text(name).color(ACCENT)
                                .decoration(TextDecoration.BOLD, true)));

        List<Component> lore = new ArrayList<>();
        lore.add(Component.empty());

        // Category badge
        Category cat = categoryFor(name);
        lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(cat.label).color(cat.color)
                        .decoration(TextDecoration.BOLD, true)));
        lore.add(divider());

        // Description
        String desc = cmd.getDescription();
        if (desc != null && !desc.isBlank()) {
            for (String line : wrapText(desc, 36)) {
                lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(line).color(GRAY)));
            }
        }

        // Usage
        String usage = cmd.getUsage();
        if (usage != null && !usage.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴜꜱᴀɢᴇ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true)));
            for (String mode : splitModes(usage)) {
                lore.add(buildUsageLine(name, mode, alias));
            }
        }

        // Aliases
        List<String> aliases = cmd.getAliases();
        if (!aliases.isEmpty()) {
            lore.add(Component.empty());
            Component row = Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴀʟɪᴀꜱ  ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true));
            for (int i = 0; i < aliases.size(); i++) {
                row = row.append(Component.text(aliases.get(i)).color(ACCENT));
                if (i < aliases.size() - 1)
                    row = row.append(Component.text(", ").color(DARK_GRAY));
            }
            lore.add(row);
        }

        // Permission
        String perm = cmd.getPermission();
        if (perm != null && !perm.isBlank()) {
            lore.add(Component.empty());
            lore.add(Component.empty().decoration(TextDecoration.ITALIC, false)
                    .append(Component.text("ᴘᴇʀᴍ  ").color(DARK_GRAY)
                            .decoration(TextDecoration.BOLD, true))
                    .append(Component.text(perm).color(YELLOW)));
        }

        lore.add(Component.empty());
        lore.add(hint("◈ ", "ᴄʟɪᴄᴋ ᴛᴏ ᴠɪᴇᴡ ᴅᴇᴛᴀɪʟꜱ"));

        meta.lore(lore);
        item.setItemMeta(meta);
        return item;
    }

    private static Component buildUsageLine(String cmdName, String mode, String alias) {
        Component line = Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("  ▸ ").color(DARK_GRAY))
                .append(Component.text("/" + alias + " " + cmdName + " ").color(DARK_GRAY));

        for (String t : mode.split(" ")) {
            TextColor col;
            if      (t.startsWith("<") && t.endsWith(">"))  col = ARG_REQUIRED;
            else if (t.startsWith("[") && t.endsWith("]"))  col = ARG_OPTIONAL;
            else if (t.startsWith("--"))                    col = ARG_FLAG;
            else if (t.contains("|"))                       col = ARG_CHOICE;
            else                                            col = WHITE;
            line = line.append(Component.text(t + " ").color(col));
        }
        return line;
    }

    /**
     * Splits usage on bare {@code |} only — pipes INSIDE {@code <...>}/{@code [...]} are kept.
     * e.g. {@code "[all|config|lang]"} → single mode; {@code "<bot> | stop"} → two modes.
     */
    private static List<String> splitModes(String usage) {
        List<String> modes = new ArrayList<>();
        int depth = 0;
        StringBuilder sb = new StringBuilder();
        for (char c : usage.toCharArray()) {
            if      (c == '<' || c == '[') { depth++;                               sb.append(c); }
            else if (c == '>' || c == ']') { depth = Math.max(0, depth - 1);       sb.append(c); }
            else if (c == '|' && depth == 0) {
                String part = sb.toString().trim();
                if (!part.isEmpty()) modes.add(part);
                sb.setLength(0);
            } else { sb.append(c); }
        }
        String last = sb.toString().trim();
        if (!last.isEmpty()) modes.add(last);
        return modes.isEmpty() ? List.of(usage) : modes;
    }

    // ── Category mapping ──────────────────────────────────────────────────────

    private static Category categoryFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn", "despawn", "list", "info", "help",
                 "stats", "reload", "settings", "migrate"    -> Category.CORE;
            case "tp", "tph", "freeze", "rename", "ping",
                 "inventory", "inv", "cmd", "xp"             -> Category.BOTS;
            case "move", "mine", "place", "use",
                 "storage", "waypoint", "wp"                 -> Category.ACTIONS;
            case "chat", "personality", "persona", "badword" -> Category.CHAT;
            default                                           -> Category.ADMIN;
        };
    }

    // ── Icons ─────────────────────────────────────────────────────────────────

    private static Material iconFor(String name) {
        return switch (name.toLowerCase()) {
            case "spawn"                    -> Material.PLAYER_HEAD;
            case "despawn", "delete"        -> Material.BONE;
            case "list"                     -> Material.BOOK;
            case "help"                     -> Material.KNOWLEDGE_BOOK;
            case "info"                     -> Material.MAP;
            case "chat"                     -> Material.PAPER;
            case "reload"                   -> Material.NETHER_STAR;
            case "freeze"                   -> Material.PACKED_ICE;
            case "stats"                    -> Material.CLOCK;
            case "tp"                       -> Material.ENDER_PEARL;
            case "tph"                      -> Material.ENDER_EYE;
            case "rank"                     -> Material.GOLDEN_CHESTPLATE;
            case "lpinfo"                   -> Material.GOLDEN_HELMET;
            case "move"                     -> Material.COMPASS;
            case "inventory", "inv"         -> Material.CHEST;
            case "cmd"                      -> Material.COMMAND_BLOCK;
            case "mine"                     -> Material.DIAMOND_PICKAXE;
            case "use"                      -> Material.WOODEN_AXE;
            case "swap"                     -> Material.RECOVERY_COMPASS;
            case "peaks"                    -> Material.SUNFLOWER;
            case "settings"                 -> Material.COMPARATOR;
            case "migrate"                  -> Material.ANVIL;
            case "sync"                     -> Material.OBSERVER;
            case "alert"                    -> Material.BELL;
            case "xp"                       -> Material.EXPERIENCE_BOTTLE;
            case "ping"                     -> Material.LIME_DYE;
            case "badword"                  -> Material.BARRIER;
            case "rename"                   -> Material.NAME_TAG;
            case "personality", "persona"   -> Material.WRITABLE_BOOK;
            case "waypoint", "wp"           -> Material.LODESTONE;
            case "storage"                  -> Material.BARREL;
            case "place"                    -> Material.OAK_PLANKS;
            default                         -> Material.PAPER;
        };
    }

    // ── Navigation items ──────────────────────────────────────────────────────

    /** Matches BotSettingGui.buildCatArrow */
    private static ItemStack buildNavArrow(boolean isNext, int targetPage) {
        Material mat = isNext ? Material.LIME_STAINED_GLASS_PANE
                               : Material.MAGENTA_STAINED_GLASS_PANE;
        TextColor col = isNext ? ON_GREEN : ORANGE;
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(isNext ? "▶" : "◄")
                                .color(col)
                                .decoration(TextDecoration.BOLD, true)));
        meta.lore(List.of(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text(
                                (isNext ? "ɴᴇxᴛ ᴘᴀɢᴇ" : "ᴘʀᴇᴠ ᴘᴀɢᴇ") + " (" + targetPage + ")")
                                .color(DARK_GRAY))));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack buildPageIndicator(int page, int total) {
        ItemStack item = new ItemStack(Material.LIGHT_BLUE_STAINED_GLASS_PANE);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(
                Component.empty().decoration(TextDecoration.ITALIC, false)
                        .append(Component.text("ᴘᴀɢᴇ ").color(GRAY))
                        .append(Component.text(page).color(WHITE)
                                .decoration(TextDecoration.BOLD, true))
                        .append(Component.text(" / ").color(DARK_GRAY))
                        .append(Component.text(total).color(WHITE)
                                .decoration(TextDecoration.BOLD, true)));
        item.setItemMeta(meta);
        return item;
    }

    private static ItemStack glassFiller(Material mat) {
        ItemStack item = new ItemStack(mat);
        ItemMeta  meta = item.getItemMeta();
        meta.displayName(Component.empty().decoration(TextDecoration.ITALIC, false));
        meta.lore(List.of());
        item.setItemMeta(meta);
        return item;
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private static Component divider() {
        return Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text("  ─────────────────────")
                        .color(TextColor.fromHexString("#2A2A2A")));
    }

    private static Component hint(String icon, String text) {
        return Component.empty().decoration(TextDecoration.ITALIC, false)
                .append(Component.text(icon).color(ACCENT))
                .append(Component.text(text).color(DARK_GRAY));
    }

    private static void playClick(Player player, float pitch) {
        player.playSound(player.getLocation(),
                Sound.UI_BUTTON_CLICK, SoundCategory.MASTER, 0.5f, pitch);
    }

    private static List<String> wrapText(String text, int maxLen) {
        if (text.length() <= maxLen) return List.of(text);
        List<String> lines = new ArrayList<>();
        String[] words = text.split(" ");
        StringBuilder sb = new StringBuilder();
        for (String word : words) {
            if (!sb.isEmpty() && sb.length() + 1 + word.length() > maxLen) {
                lines.add(sb.toString());
                sb.setLength(0);
            }
            if (!sb.isEmpty()) sb.append(' ');
            sb.append(word);
        }
        if (!sb.isEmpty()) lines.add(sb.toString());
        return lines;
    }

    // ── Holder ────────────────────────────────────────────────────────────────

    public static final class Holder implements InventoryHolder {
        public final UUID uuid;
        Holder(UUID uuid) { this.uuid = uuid; }

        @SuppressWarnings("NullableProblems")
        @Override public Inventory getInventory() { return null; }
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import net.luckperms.api.LuckPerms;
import net.luckperms.api.LuckPermsProvider;
import net.luckperms.api.event.EventSubscription;
import net.luckperms.api.event.user.UserDataRecalculateEvent;
import net.luckperms.api.model.group.Group;
import net.luckperms.api.model.user.User;
import net.luckperms.api.node.NodeType;
import net.luckperms.api.node.types.InheritanceNode;
import org.bukkit.Bukkit;
import org.bukkit.plugin.Plugin;

import java.util.*;
import java.util.concurrent.CompletableFuture;

/**
 * LuckPerms integration helper for FakePlayerPlugin.
 *
 * <h3>Architecture</h3>
 * <p>Bots are real NMS {@code ServerPlayer} entities. LP detects them as genuine
 * online players automatically. This class:
 * <ul>
 *   <li>Pre-assigns a group in LP storage <em>before</em> the NMS body spawns so
 *       that {@code PlayerJoinEvent} listeners (TAB, LP itself) see the correct group
 *       immediately at join time.</li>
 *   <li>Preserves a bot's previously-assigned group across restarts — restored bots
 *       keep their {@code /fpp rank} group without being reset to the default.</li>
 *   <li>Subscribes to LP's {@code UserDataRecalculateEvent} so display names update
 *       automatically when an admin changes a bot's group via LP commands.</li>
 *   <li>Reads resolved prefix/suffix from LP's in-memory {@code CachedMetaData} for
 *       tab-list display name rebuilding.</li>
 * </ul>
 */
public final class LuckPermsHelper {

    /** Active LP event subscription — closed in {@link #unsubscribeLpEvents()}. */
    private static EventSubscription<UserDataRecalculateEvent> eventSub;

    private LuckPermsHelper() {}

    // ── Availability ──────────────────────────────────────────────────────────

    /** @return {@code true} when LuckPerms is installed and enabled on this server. */
    public static boolean isAvailable() {
        Plugin p = Bukkit.getPluginManager().getPlugin("LuckPerms");
        return p != null && p.isEnabled();
    }

    /** Safe LP API accessor — returns {@code null} when LP is not available. */
    private static LuckPerms lp() {
        if (!isAvailable()) return null;
        try { return LuckPermsProvider.get(); }
        catch (IllegalStateException e) { return null; }
    }

    // ── Event bus ─────────────────────────────────────────────────────────────

    /**
     * Subscribes to LP's {@code UserDataRecalculateEvent} so that whenever a bot's
     * LP permissions are recalculated (group change via LP command, API, etc.) the
     * plugin automatically rebuilds its tab-list display name with the new prefix.
     *
     * <p>Must be called on the main thread after both LP and {@link FakePlayerManager}
     * are initialised.
     *
     * @param plugin  plugin instance (used to schedule Bukkit tasks)
     * @param manager fake-player manager (used to look up and refresh bots)
     */
    public static void subscribeLpEvents(FakePlayerPlugin plugin, FakePlayerManager manager) {
        LuckPerms api = lp();
        if (api == null) return;
        // Prevent double-subscription (e.g. on reload)
        if (eventSub != null) {
            eventSub.close();
            eventSub = null;
        }
        try {
            eventSub = api.getEventBus().subscribe(
                    plugin,
                    UserDataRecalculateEvent.class,
                    event -> {
                        UUID uuid = event.getUser().getUniqueId();
                        FakePlayer fp = manager.getByUuid(uuid);
                        if (fp == null) return; // not one of our bots
                        // Sync the group field and refresh display on main thread
                        String newGroup = event.getUser().getPrimaryGroup();
                        fp.setLuckpermsGroup(newGroup);
                        Bukkit.getScheduler().runTask(plugin,
                                () -> manager.refreshLpDisplayName(fp));
                        Config.debugLuckPerms("UserDataRecalculate for bot '" + fp.getName()
                                + "' — new group='" + newGroup + "', refreshing display name.");
                    });
            Config.debugLuckPerms("Subscribed to UserDataRecalculateEvent — bot display names will auto-update when LP groups change.");
        } catch (Exception e) {
            FppLogger.warn("[LP] Failed to subscribe to LP events: " + e.getMessage());
        }
    }

    /**
     * Unsubscribes from LP events. Call in {@code onDisable} to prevent memory leaks.
     */
    public static void unsubscribeLpEvents() {
        if (eventSub != null) {
            try { eventSub.close(); } catch (Exception ignored) {}
            eventSub = null;
        }
    }

    // ── Pre-spawn group setup ─────────────────────────────────────────────────

    /**
     * Ensures the bot has the correct LP group in storage <em>before</em> their NMS
     * body is spawned. Called from {@code finishSpawn} to guarantee that LP and
     * tab-list plugins (e.g. TAB) see the correct group when {@code PlayerJoinEvent}
     * fires.
     *
     * <h3>Resolution logic</h3>
     * <ol>
     *   <li>Load the bot's LP user from storage (async).</li>
     *   <li>If the bot already has a non-{@code default} primary group (i.e. a group
     *       explicitly assigned by a previous {@code /fpp rank}) <em>and</em> no
     *       {@code luckperms.default-group} is configured in FPP config, keep the
     *       existing group — this preserves rank across server restarts.</li>
     *   <li>Otherwise assign the configured {@code configGroup}, or {@code "default"}
     *       if the config is blank, and call {@link User#setPrimaryGroup(String)} so
     *       LP reports the correct primary group immediately at join time.</li>
     * </ol>
     *
     * @param botUuid     UUID of the bot
     * @param configGroup value of {@code Config.luckpermsDefaultGroup()} (may be blank)
     * @return future that resolves with the group name that was applied or kept
     */
    public static CompletableFuture<String> ensureGroupBeforeSpawn(UUID botUuid, String configGroup) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");

        // Fallback target: use the configured group or "default" as baseline
        String targetGroup = (configGroup != null && !configGroup.trim().isEmpty())
                ? configGroup.trim() : "default";

        return api.getUserManager().loadUser(botUuid)
                .thenCompose(user -> {
                    if (user == null) return CompletableFuture.completedFuture(targetGroup);

                    String storedPrimary = user.getPrimaryGroup();
                    // A bot "has a real group" when LP already has an explicit, non-default
                    // primary group recorded (set by a previous /fpp rank assignment).
                    boolean hasExplicitGroup = storedPrimary != null
                            && !storedPrimary.equalsIgnoreCase("default")
                            && !storedPrimary.isBlank();
                    boolean configForcesGroup = configGroup != null && !configGroup.trim().isEmpty();

                    if (hasExplicitGroup && !configForcesGroup) {
                        // Restore path: keep the previously-assigned rank
                        Config.debugLuckPerms("ensureGroupBeforeSpawn: keeping stored group '"
                                + storedPrimary + "' for " + botUuid);
                        return CompletableFuture.completedFuture(storedPrimary);
                    }

                    // New bot path (or config override): assign targetGroup
                    user.data().clear(NodeType.INHERITANCE::matches);
                    user.data().add(InheritanceNode.builder(targetGroup).build());
                    user.setPrimaryGroup(targetGroup);

                    // Force LP to recalculate cached metadata immediately
                    user.getCachedData().invalidate();

                    return api.getUserManager().saveUser(user)
                            .thenApply(v -> {
                                Config.debugLuckPerms("ensureGroupBeforeSpawn: set group '"
                                        + targetGroup + "' for " + botUuid);
                                // Invalidate again after save to ensure fresh calculation
                                user.getCachedData().invalidate();
                                return targetGroup;
                            });
                })
                .exceptionally(ex -> {
                    FppLogger.warn("[LP] ensureGroupBeforeSpawn error for " + botUuid
                            + ": " + ex.getMessage());
                    return targetGroup;
                });
    }


    // ── Runtime group changes ─────────────────────────────────────────────────

    /**
     * Applies an LP group to an <em>online</em> bot by writing directly to the live
     * {@link User} instance that LuckPerms loaded at {@code PlayerJoinEvent}, then
     * calling {@code saveUser()}.
     *
     * <p>This is the key fix for prefix not showing on first spawn. LP keeps one
     * authoritative {@code User} object per online player. {@code saveUser()} on that
     * object fires {@code UserDataRecalculateEvent}, which our event subscriber
     * already handles to rebuild the tab-list display name.</p>
     *
     * <p>Falls back to {@link #setPlayerGroup(UUID, String)} when the user isn't
     * loaded yet (shouldn't happen 5 ticks after spawn, but safe).</p>
     *
     * @param botUuid   the bot's UUID
     * @param groupName LP group to apply
     * @return future that completes after the save (or immediately on fallback)
     */
    public static CompletableFuture<Void> applyGroupToOnlineUser(UUID botUuid, String groupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture(null);

        // getUser() returns the LIVE online User instance LP loaded at PlayerJoinEvent.
        // Modifying it and calling saveUser() fires UserDataRecalculateEvent.
        User onlineUser = api.getUserManager().getUser(botUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(groupName).build());
            onlineUser.setPrimaryGroup(groupName);
            Config.debugLuckPerms("applyGroupToOnlineUser: applying '" + groupName + "' to online user " + botUuid);
            // saveUser() on an online User triggers UserDataRecalculateEvent → prefix updates
            return api.getUserManager().saveUser(onlineUser);
        }

        // Fallback: user not in online cache yet — load from storage and set
        Config.debugLuckPerms("applyGroupToOnlineUser: user not online yet, falling back to setPlayerGroup for " + botUuid);
        return setPlayerGroup(botUuid, groupName);
    }

    /**
     * Sets a bot's LP group at runtime (used by {@code /fpp rank}).
     * Prefers the live online {@link User} instance so the save fires
     * {@code UserDataRecalculateEvent} immediately. Falls back to {@code loadUser()}
     * for offline users.
     *
     * @param playerUuid   the bot's UUID
     * @param newGroupName the LP group name to assign
     * @return future that completes when the assignment is saved
     */
    public static CompletableFuture<Void> setPlayerGroup(UUID playerUuid, String newGroupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.failedFuture(
                new IllegalStateException("LuckPerms not available"));

        // Prefer the live online instance — saveUser() on it fires UserDataRecalculateEvent
        User onlineUser = api.getUserManager().getUser(playerUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(newGroupName).build());
            onlineUser.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(onlineUser).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (online): " + playerUuid + " → '" + newGroupName + "'"));
        }

        // User not online — fall back to loadUser (offline / pre-spawn use)
        return api.getUserManager().loadUser(playerUuid).thenCompose(user -> {
            if (user == null) return CompletableFuture.failedFuture(
                    new IllegalStateException("LP user not found for " + playerUuid));
            user.data().clear(NodeType.INHERITANCE::matches);
            user.data().add(InheritanceNode.builder(newGroupName).build());
            user.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(user).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (offline): " + playerUuid + " → '" + newGroupName + "'"));
        });
    }

    // ── Meta / prefix resolution ──────────────────────────────────────────────

    /**
     * Synchronously reads the resolved prefix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved prefix string, or {@code ""} if LP unavailable / no prefix
     */
    public static String getResolvedPrefix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String prefix = user.getCachedData().getMetaData().getPrefix();
            return prefix != null ? prefix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedPrefix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Synchronously reads the resolved suffix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved suffix string, or {@code ""} if LP unavailable / no suffix
     */
    public static String getResolvedSuffix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String suffix = user.getCachedData().getMetaData().getSuffix();
            return suffix != null ? suffix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedSuffix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Forces LuckPerms to refresh the cached metadata for a user.
     * Useful when LP hasn't finished calculating metadata after a group assignment.
     *
     * @param uuid the UUID of the user to refresh
     */
    public static void refreshUserCache(UUID uuid) {
        LuckPerms api = lp();
        if (api == null) return;
        try {
            User user = api.getUserManager().getUser(uuid);
            if (user == null) {
                // User not loaded yet, try loading them first
                api.getUserManager().loadUser(uuid).thenAccept(loadedUser -> {
                    if (loadedUser != null) {
                        loadedUser.getCachedData().invalidate();
                        Config.debugLuckPerms("Forced cache refresh for " + uuid + " (loaded first)");
                    }
                });
            } else {
                // User already loaded, just invalidate their cache
                user.getCachedData().invalidate();
                Config.debugLuckPerms("Forced cache refresh for " + uuid);
            }
        } catch (Exception e) {
            Config.debugLuckPerms("refreshUserCache error for " + uuid + ": " + e.getMessage());
        }
    }

    /**
     * Synchronously reads the primary group for a bot from LP's in-memory cache.
     * Only works when the bot is online.
     *
     * @param botUuid the bot's UUID
     * @return primary group name, or {@code "default"} as fallback
     */
    public static String getPrimaryGroup(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "default";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "default";
            return user.getPrimaryGroup();
        } catch (Exception e) {
            return "default";
        }
    }

    /**
     * Asynchronously reads the primary group for a player UUID from LP storage.
     * Works even when the player is offline. Used by diagnostics and {@code /fpp rank list}.
     *
     * @param playerUuid the UUID to query
     * @return future containing the primary group name, or {@code "default"} on failure
     */
    public static CompletableFuture<String> getStoredPrimaryGroup(UUID playerUuid) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");
        return api.getUserManager().loadUser(playerUuid)
                .thenApply(user -> user != null ? user.getPrimaryGroup() : "default")
                .exceptionally(ex -> "default");
    }


    // ── Group info / queries ──────────────────────────────────────────────────

    /**
     * Checks if the specified LP group exists (case-insensitive).
     *
     * @param name group name to check
     * @return {@code true} when LP is available and the group is loaded
     */
    public static boolean groupExists(String name) {
        LuckPerms api = lp();
        if (api == null || name == null || name.isBlank()) return false;
        return api.getGroupManager().getGroup(name.toLowerCase()) != null;
    }

    /**
     * Returns a sorted list of all LP group names currently loaded in memory.
     * Used for tab completion in {@code /fpp rank}.
     */
    public static List<String> getAllGroupNames() {
        LuckPerms api = lp();
        if (api == null) return Collections.emptyList();
        return api.getGroupManager().getLoadedGroups()
                .stream()
                .map(Group::getName)
                .sorted()
                .toList();
    }

    /**
     * Returns a human-readable summary of loaded LP groups and their weights.
     * Format: {@code name(w=N), ...} — used by {@code /fpp lpinfo}.
     */
    public static String buildGroupSummary() {
        LuckPerms api = lp();
        if (api == null) return "(LP unavailable)";
        try {
            StringBuilder sb = new StringBuilder();
            api.getGroupManager().getLoadedGroups().stream()
                    .sorted(Comparator.comparing(Group::getName))
                    .forEach(g -> {
                        int w = g.getWeight().orElse(0);
                        if (!sb.isEmpty()) sb.append(", ");
                        sb.append(g.getName()).append("(w=").append(w).append(')');
                    });
            return sb.isEmpty() ? "(none)" : sb.toString();
        } catch (Exception e) {
            return "(error: " + e.getMessage() + ")";
        }
    }

    // ── Deprecated aliases for backwards compatibility ────────────────────────

    /** @deprecated No-op — LP handles caching natively for NMS ServerPlayer entities. */
    @Deprecated
    public static void invalidateCache() {}

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} instead. */
    @Deprecated
    public static CompletableFuture<Void> addPlayerToGroup(UUID playerUuid, String groupName) {
        return setPlayerGroup(playerUuid, groupName);
    }

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} with "default" instead. */
    @Deprecated
    public static CompletableFuture<Void> cleanupBotUser(UUID playerUuid) {
        return setPlayerGroup(playerUuid, "default");
    }

    /** @deprecated Use {@link #getStoredPrimaryGroup(UUID)} instead. */
    @Deprecated
    public static CompletableFuture<String> getPlayerPrimaryGroup(UUID playerUuid) {
        return getStoredPrimaryGroup(playerUuid);
    }
}

package me.bill.fakePlayerPlugin.util;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import net.luckperms.api.LuckPerms;
import net.luckperms.api.LuckPermsProvider;
import net.luckperms.api.event.EventSubscription;
import net.luckperms.api.event.user.UserDataRecalculateEvent;
import net.luckperms.api.model.group.Group;
import net.luckperms.api.model.user.User;
import net.luckperms.api.node.NodeType;
import net.luckperms.api.node.types.InheritanceNode;
import org.bukkit.Bukkit;
import org.bukkit.plugin.Plugin;

import java.util.*;
import java.util.concurrent.CompletableFuture;

/**
 * LuckPerms integration helper for FakePlayerPlugin.
 *
 * <h3>Architecture</h3>
 * <p>Bots are real NMS {@code ServerPlayer} entities. LP detects them as genuine
 * online players automatically. This class:
 * <ul>
 *   <li>Pre-assigns a group in LP storage <em>before</em> the NMS body spawns so
 *       that {@code PlayerJoinEvent} listeners (TAB, LP itself) see the correct group
 *       immediately at join time.</li>
 *   <li>Preserves a bot's previously-assigned group across restarts — restored bots
 *       keep their {@code /fpp rank} group without being reset to the default.</li>
 *   <li>Subscribes to LP's {@code UserDataRecalculateEvent} so display names update
 *       automatically when an admin changes a bot's group via LP commands.</li>
 *   <li>Reads resolved prefix/suffix from LP's in-memory {@code CachedMetaData} for
 *       tab-list display name rebuilding.</li>
 * </ul>
 */
public final class LuckPermsHelper {

    /** Active LP event subscription — closed in {@link #unsubscribeLpEvents()}. */
    private static EventSubscription<UserDataRecalculateEvent> eventSub;

    private LuckPermsHelper() {}

    // ── Availability ──────────────────────────────────────────────────────────

    /** @return {@code true} when LuckPerms is installed and enabled on this server. */
    public static boolean isAvailable() {
        Plugin p = Bukkit.getPluginManager().getPlugin("LuckPerms");
        return p != null && p.isEnabled();
    }

    /** Safe LP API accessor — returns {@code null} when LP is not available. */
    private static LuckPerms lp() {
        if (!isAvailable()) return null;
        try { return LuckPermsProvider.get(); }
        catch (IllegalStateException e) { return null; }
    }

    // ── Event bus ─────────────────────────────────────────────────────────────

    /**
     * Subscribes to LP's {@code UserDataRecalculateEvent} so that whenever a bot's
     * LP permissions are recalculated (group change via LP command, API, etc.) the
     * plugin automatically rebuilds its tab-list display name with the new prefix.
     *
     * <p>Must be called on the main thread after both LP and {@link FakePlayerManager}
     * are initialised.
     *
     * @param plugin  plugin instance (used to schedule Bukkit tasks)
     * @param manager fake-player manager (used to look up and refresh bots)
     */
    public static void subscribeLpEvents(FakePlayerPlugin plugin, FakePlayerManager manager) {
        LuckPerms api = lp();
        if (api == null) return;
        // Prevent double-subscription (e.g. on reload)
        if (eventSub != null) {
            eventSub.close();
            eventSub = null;
        }
        try {
            eventSub = api.getEventBus().subscribe(
                    plugin,
                    UserDataRecalculateEvent.class,
                    event -> {
                        UUID uuid = event.getUser().getUniqueId();
                        FakePlayer fp = manager.getByUuid(uuid);
                        if (fp == null) return; // not one of our bots
                        // getPrimaryGroup() throws NPE internally when LP hasn't assigned
                        // a primary group yet (brand-new user with no nodes).
                        String newGroup;
                        try {
                            newGroup = event.getUser().getPrimaryGroup();
                        } catch (NullPointerException ignored) {
                            newGroup = null;
                        }
                        if (newGroup == null) newGroup = "default";
                        fp.setLuckpermsGroup(newGroup);
                        Bukkit.getScheduler().runTask(plugin,
                                () -> manager.refreshLpDisplayName(fp));
                        Config.debugLuckPerms("UserDataRecalculate for bot '" + fp.getName()
                                + "' — new group='" + newGroup + "', refreshing display name.");
                    });
            Config.debugLuckPerms("Subscribed to UserDataRecalculateEvent — bot display names will auto-update when LP groups change.");
        } catch (Exception e) {
            FppLogger.warn("[LP] Failed to subscribe to LP events: " + e.getMessage());
        }
    }

    /**
     * Unsubscribes from LP events. Call in {@code onDisable} to prevent memory leaks.
     */
    public static void unsubscribeLpEvents() {
        if (eventSub != null) {
            try { eventSub.close(); } catch (Exception ignored) {}
            eventSub = null;
        }
    }

    // ── Pre-spawn group setup ─────────────────────────────────────────────────

    /**
     * Ensures the bot has the correct LP group in storage <em>before</em> their NMS
     * body is spawned. Called from {@code finishSpawn} to guarantee that LP and
     * tab-list plugins (e.g. TAB) see the correct group when {@code PlayerJoinEvent}
     * fires.
     *
     * <h3>Resolution logic</h3>
     * <ol>
     *   <li>Load the bot's LP user from storage (async).</li>
     *   <li>If the bot already has a non-{@code default} primary group (i.e. a group
     *       explicitly assigned by a previous {@code /fpp rank}) <em>and</em> no
     *       {@code luckperms.default-group} is configured in FPP config, keep the
     *       existing group — this preserves rank across server restarts.</li>
     *   <li>Otherwise assign the configured {@code configGroup}, or {@code "default"}
     *       if the config is blank, and call {@link User#setPrimaryGroup(String)} so
     *       LP reports the correct primary group immediately at join time.</li>
     * </ol>
     *
     * @param botUuid     UUID of the bot
     * @param configGroup value of {@code Config.luckpermsDefaultGroup()} (may be blank)
     * @return future that resolves with the group name that was applied or kept
     */
    public static CompletableFuture<String> ensureGroupBeforeSpawn(UUID botUuid, String configGroup) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");

        // Fallback target: use the configured group or "default" as baseline
        String targetGroup = (configGroup != null && !configGroup.trim().isEmpty())
                ? configGroup.trim() : "default";

        return api.getUserManager().loadUser(botUuid)
                .thenCompose(user -> {
                    if (user == null) return CompletableFuture.completedFuture(targetGroup);

                    String storedPrimary = user.getPrimaryGroup();
                    // A bot "has a real group" when LP already has an explicit, non-default
                    // primary group recorded (set by a previous /fpp rank assignment).
                    boolean hasExplicitGroup = storedPrimary != null
                            && !storedPrimary.equalsIgnoreCase("default")
                            && !storedPrimary.isBlank();
                    boolean configForcesGroup = configGroup != null && !configGroup.trim().isEmpty();

                    if (hasExplicitGroup && !configForcesGroup) {
                        // Restore path: keep the previously-assigned rank
                        Config.debugLuckPerms("ensureGroupBeforeSpawn: keeping stored group '"
                                + storedPrimary + "' for " + botUuid);
                        return CompletableFuture.completedFuture(storedPrimary);
                    }

                    // New bot path (or config override): assign targetGroup
                    user.data().clear(NodeType.INHERITANCE::matches);
                    user.data().add(InheritanceNode.builder(targetGroup).build());
                    user.setPrimaryGroup(targetGroup);
                    
                    // Force LP to recalculate cached metadata immediately
                    user.getCachedData().invalidate();
                    
                    return api.getUserManager().saveUser(user)
                            .thenApply(v -> {
                                Config.debugLuckPerms("ensureGroupBeforeSpawn: set group '"
                                        + targetGroup + "' for " + botUuid);
                                // Invalidate again after save to ensure fresh calculation
                                user.getCachedData().invalidate();
                                return targetGroup;
                            });
                })
                .exceptionally(ex -> {
                    FppLogger.warn("[LP] ensureGroupBeforeSpawn error for " + botUuid
                            + ": " + ex.getMessage());
                    return targetGroup;
                });
    }


    // ── Runtime group changes ─────────────────────────────────────────────────

    /**
     * Applies an LP group to an <em>online</em> bot by writing directly to the live
     * {@link User} instance that LuckPerms loaded at {@code PlayerJoinEvent}, then
     * calling {@code saveUser()}.
     *
     * <p>This is the key fix for prefix not showing on first spawn. LP keeps one
     * authoritative {@code User} object per online player. {@code saveUser()} on that
     * object fires {@code UserDataRecalculateEvent}, which our event subscriber
     * already handles to rebuild the tab-list display name.</p>
     *
     * <p>Falls back to {@link #setPlayerGroup(UUID, String)} when the user isn't
     * loaded yet (shouldn't happen 5 ticks after spawn, but safe).</p>
     *
     * @param botUuid   the bot's UUID
     * @param groupName LP group to apply
     * @return future that completes after the save (or immediately on fallback)
     */
    public static CompletableFuture<Void> applyGroupToOnlineUser(UUID botUuid, String groupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture(null);

        // getUser() returns the LIVE online User instance LP loaded at PlayerJoinEvent.
        // Modifying it and calling saveUser() fires UserDataRecalculateEvent.
        User onlineUser = api.getUserManager().getUser(botUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(groupName).build());
            onlineUser.setPrimaryGroup(groupName);
            Config.debugLuckPerms("applyGroupToOnlineUser: applying '" + groupName + "' to online user " + botUuid);
            // saveUser() on an online User triggers UserDataRecalculateEvent → prefix updates
            return api.getUserManager().saveUser(onlineUser);
        }

        // Fallback: user not in online cache yet — load from storage and set
        Config.debugLuckPerms("applyGroupToOnlineUser: user not online yet, falling back to setPlayerGroup for " + botUuid);
        return setPlayerGroup(botUuid, groupName);
    }

    /**
     * Sets a bot's LP group at runtime (used by {@code /fpp rank}).
     * Prefers the live online {@link User} instance so the save fires
     * {@code UserDataRecalculateEvent} immediately. Falls back to {@code loadUser()}
     * for offline users.
     *
     * @param playerUuid   the bot's UUID
     * @param newGroupName the LP group name to assign
     * @return future that completes when the assignment is saved
     */
    public static CompletableFuture<Void> setPlayerGroup(UUID playerUuid, String newGroupName) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.failedFuture(
                new IllegalStateException("LuckPerms not available"));

        // Prefer the live online instance — saveUser() on it fires UserDataRecalculateEvent
        User onlineUser = api.getUserManager().getUser(playerUuid);
        if (onlineUser != null) {
            onlineUser.data().clear(NodeType.INHERITANCE::matches);
            onlineUser.data().add(InheritanceNode.builder(newGroupName).build());
            onlineUser.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(onlineUser).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (online): " + playerUuid + " → '" + newGroupName + "'"));
        }

        // User not online — fall back to loadUser (offline / pre-spawn use)
        return api.getUserManager().loadUser(playerUuid).thenCompose(user -> {
            if (user == null) return CompletableFuture.failedFuture(
                    new IllegalStateException("LP user not found for " + playerUuid));
            user.data().clear(NodeType.INHERITANCE::matches);
            user.data().add(InheritanceNode.builder(newGroupName).build());
            user.setPrimaryGroup(newGroupName);
            return api.getUserManager().saveUser(user).thenRun(() ->
                    Config.debugLuckPerms("setPlayerGroup (offline): " + playerUuid + " → '" + newGroupName + "'"));
        });
    }

    // ── Meta / prefix resolution ──────────────────────────────────────────────

    /**
     * Synchronously reads the resolved prefix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved prefix string, or {@code ""} if LP unavailable / no prefix
     */
    public static String getResolvedPrefix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String prefix = user.getCachedData().getMetaData().getPrefix();
            return prefix != null ? prefix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedPrefix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Synchronously reads the resolved suffix for a bot from LP's in-memory meta
     * cache. Only works when the bot is online (LP has their {@code User} loaded).
     *
     * @param botUuid the bot's UUID
     * @return resolved suffix string, or {@code ""} if LP unavailable / no suffix
     */
    public static String getResolvedSuffix(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "";
            String suffix = user.getCachedData().getMetaData().getSuffix();
            return suffix != null ? suffix : "";
        } catch (Exception e) {
            Config.debugLuckPerms("getResolvedSuffix error for " + botUuid + ": " + e.getMessage());
            return "";
        }
    }

    /**
     * Forces LuckPerms to refresh the cached metadata for a user.
     * Useful when LP hasn't finished calculating metadata after a group assignment.
     *
     * @param uuid the UUID of the user to refresh
     */
    public static void refreshUserCache(UUID uuid) {
        LuckPerms api = lp();
        if (api == null) return;
        try {
            User user = api.getUserManager().getUser(uuid);
            if (user == null) {
                // User not loaded yet, try loading them first
                api.getUserManager().loadUser(uuid).thenAccept(loadedUser -> {
                    if (loadedUser != null) {
                        loadedUser.getCachedData().invalidate();
                        Config.debugLuckPerms("Forced cache refresh for " + uuid + " (loaded first)");
                    }
                });
            } else {
                // User already loaded, just invalidate their cache
                user.getCachedData().invalidate();
                Config.debugLuckPerms("Forced cache refresh for " + uuid);
            }
        } catch (Exception e) {
            Config.debugLuckPerms("refreshUserCache error for " + uuid + ": " + e.getMessage());
        }
    }

    /**
     * Synchronously reads the primary group for a bot from LP's in-memory cache.
     * Only works when the bot is online.
     *
     * @param botUuid the bot's UUID
     * @return primary group name, or {@code "default"} as fallback
     */
    public static String getPrimaryGroup(UUID botUuid) {
        LuckPerms api = lp();
        if (api == null) return "default";
        try {
            User user = api.getUserManager().getUser(botUuid);
            if (user == null) return "default";
            return user.getPrimaryGroup();
        } catch (Exception e) {
            return "default";
        }
    }

    /**
     * Asynchronously reads the primary group for a player UUID from LP storage.
     * Works even when the player is offline. Used by diagnostics and {@code /fpp rank list}.
     *
     * @param playerUuid the UUID to query
     * @return future containing the primary group name, or {@code "default"} on failure
     */
    public static CompletableFuture<String> getStoredPrimaryGroup(UUID playerUuid) {
        LuckPerms api = lp();
        if (api == null) return CompletableFuture.completedFuture("default");
        return api.getUserManager().loadUser(playerUuid)
                .thenApply(user -> user != null ? user.getPrimaryGroup() : "default")
                .exceptionally(ex -> "default");
    }


    // ── Group info / queries ──────────────────────────────────────────────────

    /**
     * Checks if the specified LP group exists (case-insensitive).
     *
     * @param name group name to check
     * @return {@code true} when LP is available and the group is loaded
     */
    public static boolean groupExists(String name) {
        LuckPerms api = lp();
        if (api == null || name == null || name.isBlank()) return false;
        return api.getGroupManager().getGroup(name.toLowerCase()) != null;
    }

    /**
     * Returns a sorted list of all LP group names currently loaded in memory.
     * Used for tab completion in {@code /fpp rank}.
     */
    public static List<String> getAllGroupNames() {
        LuckPerms api = lp();
        if (api == null) return Collections.emptyList();
        return api.getGroupManager().getLoadedGroups()
                .stream()
                .map(Group::getName)
                .sorted()
                .toList();
    }

    /**
     * Returns a human-readable summary of loaded LP groups and their weights.
     * Format: {@code name(w=N), ...} — used by {@code /fpp lpinfo}.
     */
    public static String buildGroupSummary() {
        LuckPerms api = lp();
        if (api == null) return "(LP unavailable)";
        try {
            StringBuilder sb = new StringBuilder();
            api.getGroupManager().getLoadedGroups().stream()
                    .sorted(Comparator.comparing(Group::getName))
                    .forEach(g -> {
                        int w = g.getWeight().orElse(0);
                        if (!sb.isEmpty()) sb.append(", ");
                        sb.append(g.getName()).append("(w=").append(w).append(')');
                    });
            return sb.isEmpty() ? "(none)" : sb.toString();
        } catch (Exception e) {
            return "(error: " + e.getMessage() + ")";
        }
    }

    // ── Deprecated aliases for backwards compatibility ────────────────────────

    /** @deprecated No-op — LP handles caching natively for NMS ServerPlayer entities. */
    @Deprecated
    public static void invalidateCache() {}

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} instead. */
    @Deprecated
    public static CompletableFuture<Void> addPlayerToGroup(UUID playerUuid, String groupName) {
        return setPlayerGroup(playerUuid, groupName);
    }

    /** @deprecated Use {@link #setPlayerGroup(UUID, String)} with "default" instead. */
    @Deprecated
    public static CompletableFuture<Void> cleanupBotUser(UUID playerUuid) {
        return setPlayerGroup(playerUuid, "default");
    }

    /** @deprecated Use {@link #getStoredPrimaryGroup(UUID)} instead. */
    @Deprecated
    public static CompletableFuture<String> getPlayerPrimaryGroup(UUID playerUuid) {
        return getStoredPrimaryGroup(playerUuid);
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import net.minecraft.core.BlockPos;
import net.minecraft.core.Direction;
import net.minecraft.network.protocol.game.ServerboundPlayerActionPacket;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.phys.BlockHitResult;
import net.minecraft.world.phys.Vec3;
import org.bukkit.Bukkit;
import org.bukkit.GameMode;
import org.bukkit.Location;
import org.bukkit.Material;
import org.bukkit.Tag;
import org.bukkit.World;
import org.bukkit.block.Block;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Item;
import org.bukkit.entity.Player;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.PlayerInventory;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;
import org.bukkit.util.BlockIterator;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Mine command with two modes:
 * <ul>
 *   <li>Classic: {@code /fpp mine <bot> [once|stop]}</li>
 *   <li>Area mode: {@code /fpp mine <bot> --pos1}, {@code --pos2}, {@code --start}</li>
 * </ul>
 *
 * <p>Area mining walks the bot to each reachable block in the cuboid selection, mines it,
 * and when the bot inventory is full automatically walks to the configured storage blocks
 * from {@code /fpp storage <bot> [storage_name]} to deposit items.
 */
public final class MineCommand implements FppCommand {

    private static final double ARRIVAL_DIST    = 1.2;
    private static final double SPRINT_DIST     = 6.0;
    private static final double WP_ARRIVE_XZ    = 0.65;
    private static final int    RECALC_INTERVAL = 60;
    private static final int    STUCK_TICKS     = 8;
    private static final double STUCK_THRESHOLD = 0.04;
    private static final int    LOOK_BLOCK_RANGE = 8;
    private static final int    AREA_CONTROLLER_PERIOD = 5;
    private static final int    AREA_PICKUP_WAIT_TICKS = 8;
    private static final int    AREA_PICKUP_EXTRA_TICKS = 20;

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;
    private final StorageStore storageStore;

    private final Map<UUID, BukkitTask> navTasks    = new ConcurrentHashMap<>();
    private final Map<UUID, Integer>    miningTasks  = new ConcurrentHashMap<>();
    private final Map<UUID, MiningState> miningStates = new ConcurrentHashMap<>();
    private final Map<UUID, Location>   activeMineLocations = new ConcurrentHashMap<>();
    private final Map<UUID, Boolean>    activeMineOnceFlags  = new ConcurrentHashMap<>();

    private final Map<UUID, AreaSelection> selections = new ConcurrentHashMap<>();
    private final Map<UUID, AreaMineJob> areaJobs = new ConcurrentHashMap<>();
    private final Map<UUID, Integer> areaTasks = new ConcurrentHashMap<>();

    public MineCommand(FakePlayerPlugin plugin, FakePlayerManager manager, StorageStore storageStore) {
        this.plugin = plugin;
        this.manager = manager;
        this.storageStore = storageStore;
    }

    @Override public String getName()        { return "mine"; }
    @Override public String getUsage()       { return "<bot> [once|stop|--pos1|--pos2|--start]  |  stop"; }
    @Override public String getDescription() { return "Walk a bot to mine one block, mine continuously, or clear a selected area with storage offloading."; }
    @Override public String getPermission()  { return Perm.MINE; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.MINE); }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("mine-usage"));
            return true;
        }

        // /fpp mine stop - stop every bot
        if (args[0].equalsIgnoreCase("stop") && args.length == 1) {
            stopAll();
            sender.sendMessage(Lang.get("mine-stopped-all"));
            return true;
        }

        String botName = args[0];
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("mine-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("mine-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        if (args.length >= 2) {
            String action = args[1].toLowerCase(Locale.ROOT);
            switch (action) {
                case "stop" -> {
                    cleanupBot(fp.getUuid());
                    sender.sendMessage(Lang.get("mine-stopped", "name", fp.getDisplayName()));
                    return true;
                }
                case "--pos1", "pos1" -> {
                    if (!(sender instanceof Player player)) {
                        sender.sendMessage(Lang.get("player-only"));
                        return true;
                    }
                    Block target = player.getTargetBlockExact(LOOK_BLOCK_RANGE);
                    if (target == null) {
                        sender.sendMessage(Lang.get("mine-look-at-block"));
                        return true;
                    }
                    AreaSelection selection = selections.computeIfAbsent(fp.getUuid(), k -> new AreaSelection());
                    selection.pos1 = target.getLocation();
                    sender.sendMessage(Lang.get("mine-pos1-set",
                            "name", fp.getDisplayName(),
                            "x", String.valueOf(target.getX()),
                            "y", String.valueOf(target.getY()),
                            "z", String.valueOf(target.getZ())));
                    return true;
                }
                case "--pos2", "pos2" -> {
                    if (!(sender instanceof Player player)) {
                        sender.sendMessage(Lang.get("player-only"));
                        return true;
                    }
                    Block target = player.getTargetBlockExact(LOOK_BLOCK_RANGE);
                    if (target == null) {
                        sender.sendMessage(Lang.get("mine-look-at-block"));
                        return true;
                    }
                    AreaSelection selection = selections.computeIfAbsent(fp.getUuid(), k -> new AreaSelection());
                    selection.pos2 = target.getLocation();
                    sender.sendMessage(Lang.get("mine-pos2-set",
                            "name", fp.getDisplayName(),
                            "x", String.valueOf(target.getX()),
                            "y", String.valueOf(target.getY()),
                            "z", String.valueOf(target.getZ())));
                    return true;
                }
                case "--start", "start" -> {
                    startAreaMining(sender, fp);
                    return true;
                }
            }
        }

        boolean once = args.length >= 2 && args[1].equalsIgnoreCase("once");
        stopAreaJob(fp.getUuid(), false);
        cancelAll(fp.getUuid());

        Location dest = (sender instanceof Player sp)
                ? sp.getLocation().clone()
                : bot.getLocation().clone();

        double xzDist = xzDist(bot.getLocation(), dest);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartMining(fp, once, dest, null, false);
            sender.sendMessage(once
                    ? Lang.get("mine-started-once", "name", fp.getDisplayName())
                    : Lang.get("mine-started", "name", fp.getDisplayName()));
        } else {
            startNavigation(fp, dest, () -> lockAndStartMining(fp, once, dest, null, false));
            sender.sendMessage(Lang.get("mine-walking", "name", fp.getDisplayName()));
        }
        return true;
    }

    // ── Tab-complete ──────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase(Locale.ROOT);
            List<String> out = new ArrayList<>();
            if ("stop".startsWith(prefix)) out.add("stop");
            for (FakePlayer fp : manager.getActivePlayers()) {
                if (fp.getName().toLowerCase(Locale.ROOT).startsWith(prefix)) out.add(fp.getName());
            }
            return out;
        }

        // Second arg only makes sense when the first arg is a bot name, not "stop"
        if (args.length == 2 && !args[0].equalsIgnoreCase("stop")) {
            String prefix = args[1].toLowerCase(Locale.ROOT);
            List<String> out = new ArrayList<>();
            for (String option : List.of("once", "stop", "--pos1", "--pos2", "--start")) {
                if (option.startsWith(prefix)) out.add(option);
            }
            return out;
        }

        return List.of();
    }

    // ── Area mining ────────────────────────────────────────────────────────────

    private void startAreaMining(CommandSender sender, FakePlayer fp) {
        AreaSelection selection = selections.get(fp.getUuid());
        if (selection == null || !selection.isComplete()) {
            sender.sendMessage(Lang.get("mine-area-missing-selection", "name", fp.getDisplayName()));
            return;
        }
        if (!selection.sameWorld()) {
            sender.sendMessage(Lang.get("mine-area-world-mismatch"));
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("mine-bot-offline", "name", fp.getDisplayName()));
            return;
        }
        if (bot.getWorld() != Objects.requireNonNull(selection.pos1.getWorld())) {
            sender.sendMessage(Lang.get("mine-area-bot-world",
                    "name", fp.getDisplayName(),
                    "world", selection.pos1.getWorld().getName()));
            return;
        }

        cleanupBot(fp.getUuid());
        AreaMineJob job = new AreaMineJob(selection.copy(), sender);
        areaJobs.put(fp.getUuid(), job);
        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> tickAreaJob(fp.getUuid()), 0L, AREA_CONTROLLER_PERIOD).getTaskId();
        areaTasks.put(fp.getUuid(), taskId);
        sender.sendMessage(Lang.get("mine-area-started",
                "name", fp.getDisplayName(),
                "count", String.valueOf(selection.blockCount())));
    }

    @SuppressWarnings("unchecked")
    private void startNavigation(FakePlayer fp, Location dest, Runnable onArrive) {
        final UUID uuid = fp.getUuid();
        // Cancel any previous nav task for this bot first
        BukkitTask old = navTasks.remove(uuid);
        if (old != null && !old.isCancelled()) old.cancel();
        manager.lockForNavigation(uuid);
        manager.clearNavJump(uuid);
        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[] wpIdx = {0};
        final int[] recalcIn = {0};
        final int[] stuckFor = {0};
        final double[] prevX = {fp.getPlayer().getLocation().getX()};
        final double[] prevZ = {fp.getPlayer().getLocation().getZ()};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player bot = Bukkit.getPlayer(uuid);
                if (bot == null || !bot.isOnline()) {
                    cleanup(null);
                    return;
                }

                Location botLoc = bot.getLocation();
                double dist = xzDist(botLoc, dest);
                if (dist <= ARRIVAL_DIST) {
                    cleanup(bot);
                    onArrive.run();
                    return;
                }

                boolean exhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat = (--recalcIn[0] <= 0);
                if (exhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(), dest.getBlockY(), dest.getBlockZ(),
                            opts);
                    pathRef[0] = newPath;
                    wpIdx[0] = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(bot, dest, dist);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5;
                double wpCZ = wp.z() + 0.5;
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) {
                        recalcIn[0] = 0;
                        return;
                    }
                    wp = path.get(wpIdx[0]);
                    wpCX = wp.x() + 0.5;
                    wpCZ = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                double dx = wpCX - botLoc.getX();
                double dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);

                if (!bot.isInWater() && !bot.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(uuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(uuid);
                    }
                }

                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!bot.isInWater() && !bot.isInLava()) manager.requestNavJump(uuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }
                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(Player bot) {
                manager.unlockNavigation(uuid);
                manager.clearNavJump(uuid);
                if (bot != null) {
                    NmsPlayerSpawner.setMovementForward(bot, 0f);
                    NmsPlayerSpawner.setJumping(bot, false);
                    bot.setSprinting(false);
                }
                cancel();
                navTasks.remove(uuid);
            }

            private void walkToward(Player bot, Location target, double dist) {
                Location bl = bot.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(target.getX() - bl.getX()), target.getZ() - bl.getZ()));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);
            }
        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(uuid, task);
    }

    // ── Phase 2: lock + mine ──────────────────────────────────────────────────

    /**
     * Called once the bot has arrived at the mining destination.
     * Snaps the bot to the exact position, registers the mining lock, and starts the
     * 1-tick mining loop.
     */
    private void lockAndStartMining(FakePlayer fp, boolean once, Location lockLoc,
                                    BlockPos forcedTarget, boolean stopAfterForcedTarget) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        // Final snap to exact position (bot is already ≤ ARRIVAL_DIST away, so imperceptible)
        bot.teleport(lockLoc);
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        // Lock position + head-AI in FakePlayerManager's tick loop
        manager.lockForMining(uuid, lockLoc);

        // Record active mine state for persistence
        activeMineLocations.put(uuid, lockLoc.clone());
        activeMineOnceFlags.put(uuid, once);

        // Init state
        MiningState state = new MiningState();
        state.once = once;
        state.forcedTarget = forcedTarget;
        state.stopAfterForcedTarget = stopAfterForcedTarget;
        miningStates.put(uuid, state);

        // 1-tick mining task
        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> {
            Player b = fp.getPlayer();
            if (b == null || !b.isOnline()) {
                stopMining(uuid);
                return;
            }
            tickMining(fp, state);
        }, 0L, 1L).getTaskId();

        miningTasks.put(uuid, taskId);
    }

    // ── Stop helpers ──────────────────────────────────────────────────────────

    /**
     * Cancels both the navigation task AND the mining task for the given bot,
     * and releases the position lock.
     */
    private void cancelAll(UUID botUuid) {
        // Cancel phase-1 nav
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        manager.clearNavJump(botUuid);

        // Stop phase-2 mine
        stopMining(botUuid);

        // Stop movement if bot still exists
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    /** Stops only the mining phase (task + lock + state cleanup). */
    public void stopMining(UUID botUuid) {
        Integer taskId = miningTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);
        manager.unlockNavigation(botUuid);

        // Clear persistence tracking
        activeMineLocations.remove(botUuid);
        activeMineOnceFlags.remove(botUuid);

        MiningState state = miningStates.remove(botUuid);
        if (state != null) {
            if (state.currentPos != null) {
                FakePlayer fp = manager.getByUuid(botUuid);
                if (fp != null) {
                    Player bot = fp.getPlayer();
                    if (bot != null && bot.isOnline()) {
                        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
                        nms.level().destroyBlockProgress(-1, state.currentPos, -1);
                        nms.gameMode.handleBlockBreakAction(
                                state.currentPos,
                                ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                                Direction.DOWN, nms.level().getMaxY(), -1);
                    }
                }
            }
            if (state.completeForcedTargetOnStop && state.stopAfterForcedTarget && state.forcedTarget != null) {
                AreaMineJob job = areaJobs.get(botUuid);
                if (job != null && job.currentTarget != null) {
                    job.completed.add(job.currentTarget);
                    job.currentTarget = null;
                    job.blocksMined++;
                    // Fast-trigger the area controller on the next tick instead of waiting
                    // up to AREA_CONTROLLER_PERIOD (5) ticks for the periodic task.
                    // This is safe — tickAreaJob checks nav/mine locks and returns early
                    // if either is still in progress.
                    Bukkit.getScheduler().runTaskLater(plugin, () -> tickAreaJob(botUuid), 1L);
                }
            }
        }
    }

    /** Stops all bots (navigation + mining). */
    public void stopAll() {
        new HashSet<>(navTasks.keySet()).forEach(this::cleanupBot);
        new HashSet<>(miningTasks.keySet()).forEach(this::cleanupBot);
        new HashSet<>(areaTasks.keySet()).forEach(this::cleanupBot);
    }

    /** Cleans up all navigation, mining, and area job state for the given bot. */
    public void cleanupBot(UUID botUuid) {
        cancelAll(botUuid);
        stopAreaJob(botUuid, false);
    }

    /** Removes any saved pos1/pos2 selection for this bot. */
    public void clearSelection(UUID botUuid) {
        selections.remove(botUuid);
    }

    /** Returns {@code true} if the bot is currently navigating to a mining spot. */
    public boolean isNavigating(UUID botUuid) { return navTasks.containsKey(botUuid); }

    /** Returns {@code true} if the bot is actively mining. */
    public boolean isMining(UUID botUuid)     { return miningTasks.containsKey(botUuid); }

    // ── Persistence API ───────────────────────────────────────────────────────

    /**
     * Returns the active mining lock location for the given bot,
     * or {@code null} when the bot is not mining.
     */
    @org.jetbrains.annotations.Nullable
    public Location getActiveMineLocation(UUID botUuid) {
        return activeMineLocations.get(botUuid);
    }

    /**
     * Returns {@code true} if the bot's active mine task is once-only.
     */
    public boolean isActiveMineOnce(UUID botUuid) {
        Boolean v = activeMineOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Resumes mining for a bot restored from persistence.
     * If the bot is already close enough to the lock location, starts mining
     * immediately; otherwise navigates there first.
     */
    public void resumeMining(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        double xzDist = xzDist(bot.getLocation(), loc);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartMining(fp, once, loc, null, false);
        } else {
            startNavigation(fp, loc, () -> lockAndStartMining(fp, once, loc, null, false));
        }
    }

    // ── Area mining helpers ────────────────────────────────────────────────────

    private void tickAreaJob(UUID botUuid) {
        AreaMineJob job = areaJobs.get(botUuid);
        if (job == null) {
            stopAreaJob(botUuid, false);
            return;
        }
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            stopAreaJob(botUuid, false);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            stopAreaJob(botUuid, false);
            return;
        }

        // If currently mining: check if the bot was displaced from its locked spot
        if (miningTasks.containsKey(botUuid)) {
            if (job.currentTarget != null) {
                Location lockLoc = activeMineLocations.get(botUuid);
                if (lockLoc != null && !isAtLockLocation(bot, lockLoc)) {
                    // Bot is not at the mining spot — interrupt and re-navigate there
                    interruptMining(botUuid);
                    Location retryFace = faceToward(lockLoc.clone(), job.currentTarget.center(bot.getWorld()));
                    startNavigation(fp, retryFace, () -> lockAndStartMining(fp, false, retryFace, job.currentTarget.toBlockPos(), true));
                }
            }
            return; // wait for the mining task to finish
        }

        // If navigating: wait for it to complete
        if (navTasks.containsKey(botUuid)) return;

        // Inventory full AND storage is configured? Pause to offload.
        // If no storage is set, skip this check entirely — the bot keeps mining at full
        // speed; mined items either get picked up naturally or drop on the ground.
        boolean hasStorage = !storageStore.getStorages(fp.getName()).isEmpty();
        if (hasStorage && isStorageOffloadNeeded(bot.getInventory())) {
            if (!startStorageOffload(fp, job)) {
                // Storage set but all containers are full or unreachable
                notifyStarter(job, "mine-storage-unavailable", "name", fp.getDisplayName());
                stopAreaJob(botUuid, false);
            }
            return;
        }

        // Finishing deposit: deposit nav/mine tasks are done — area is truly complete
        if (job.finishingDeposit) {
            notifyStarter(job, "mine-area-finished",
                    "name", fp.getDisplayName(),
                    "count", String.valueOf(job.blocksMined));
            stopAreaJob(botUuid, false);
            return;
        }

        // Find the next block to mine
        AreaBlock next = findNextAreaTarget(bot, job.selection, job);
        if (next == null) {
            // Area exhausted — if storage is configured and bot has loot, do a final deposit
            if (hasStorage && hasDepositableLoot(bot.getInventory())) {
                job.finishingDeposit = true;
                if (!startStorageOffload(fp, job)) {
                    // Storage set but unreachable — skip the deposit and finish now
                    notifyStarter(job, "mine-storage-unavailable", "name", fp.getDisplayName());
                    notifyStarter(job, "mine-area-finished",
                            "name", fp.getDisplayName(),
                            "count", String.valueOf(job.blocksMined));
                    stopAreaJob(botUuid, false);
                }
                return;
            }
            notifyStarter(job, "mine-area-finished",
                    "name", fp.getDisplayName(),
                    "count", String.valueOf(job.blocksMined));
            stopAreaJob(botUuid, false);
            return;
        }

        // If this was a finishing deposit pass and we're back to mining, clear the flag
        job.finishingDeposit = false;

        Location standLoc = findStandLocation(bot.getWorld(), next);
        if (standLoc == null) {
            job.skipped.add(next);
            return;
        }

        Location targetCenter = next.center(bot.getWorld());
        Location faceLoc = faceToward(standLoc, targetCenter);
        job.currentTarget = next;
        startNavigation(fp, faceLoc, () -> lockAndStartMining(fp, false, faceLoc, next.toBlockPos(), true));
    }

    private boolean startStorageOffload(FakePlayer fp, AreaMineJob job) {
        List<StorageStore.StoragePoint> storages = storageStore.getStorages(fp.getName());
        if (storages.isEmpty()) return false;

        Player bot = fp.getPlayer();
        if (bot == null) return false;

        for (int attempt = 0; attempt < storages.size(); attempt++) {
            int idx = (job.preferredStorageIndex + attempt) % storages.size();
            StorageStore.StoragePoint point = storages.get(idx);
            if (point.location().getWorld() != bot.getWorld()) continue;
            Block block = point.location().getBlock();
            if (!(block.getState() instanceof InventoryHolder holder)) continue;
            if (!containerCanAcceptAny(bot.getInventory(), holder.getInventory())) continue;
            Location standLoc = findStandLocation(bot.getWorld(), new AreaBlock(block.getX(), block.getY(), block.getZ()));
            if (standLoc == null) continue;
            Location faceLoc = faceToward(standLoc, block.getLocation().add(0.5, 0.5, 0.5));
            final int targetIndex = idx;
            startNavigation(fp, faceLoc, () -> depositToStorage(fp, job, targetIndex, point));
            return true;
        }
        return false;
    }

    private void depositToStorage(FakePlayer fp, AreaMineJob job, int storageIndex, StorageStore.StoragePoint point) {
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        Block block = point.location().getBlock();
        if (!(block.getState() instanceof InventoryHolder holder)) {
            job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
            return;
        }

        Location standLoc = findStandLocation(bot.getWorld(), new AreaBlock(block.getX(), block.getY(), block.getZ()));
        if (standLoc == null) {
            job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
            return;
        }

        Location faceLoc = faceToward(standLoc, block.getLocation().add(0.5, 0.5, 0.5));
        if (!isAtLockLocation(bot, faceLoc)) {
            startNavigation(fp, faceLoc, () -> depositToStorage(fp, job, storageIndex, point));
            return;
        }

        // Lock bot facing the storage block; enforce rotation every tick
        manager.lockForMining(fp.getUuid(), faceLoc);
        bot.teleport(faceLoc);
        bot.setRotation(faceLoc.getYaw(), faceLoc.getPitch());
        NmsPlayerSpawner.setHeadYaw(bot, faceLoc.getYaw());
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        // 1 tick delay so position lock packet reaches clients before the container opens
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            Player lookBot = fp.getPlayer();
            if (lookBot == null || !lookBot.isOnline()) {
                manager.unlockMining(fp.getUuid());
                return;
            }
            // Swing arm + use block — triggers the open animation for chest/barrel/shulker
            useStorageBlock(lookBot, block);

            // 2 ticks later: transfer items into the container and release the lock
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                Player liveBot = fp.getPlayer();
                if (liveBot == null || !liveBot.isOnline()) {
                    manager.unlockMining(fp.getUuid());
                    return;
                }
                Block liveBlock = point.location().getBlock();
                if (!(liveBlock.getState() instanceof InventoryHolder liveHolder)) {
                    manager.unlockMining(fp.getUuid());
                    job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
                    return;
                }

                int moved = moveBotInventoryToStorage(liveBot.getInventory(), liveHolder.getInventory());
                liveBot.closeInventory();
                manager.unlockMining(fp.getUuid());
                if (plugin.getInventoryCommand() != null) {
                    plugin.getInventoryCommand().refreshOpenGui(fp.getUuid());
                }
                if (moved > 0 && !isStorageOffloadNeeded(liveBot.getInventory())) {
                    job.preferredStorageIndex = storageIndex;
                } else if (moved > 0) {
                    job.preferredStorageIndex = storageIndex;
                } else {
                    job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
                }
            }, 3L);
        }, 1L);
    }

    // ── Mining tick ───────────────────────────────────────────────────────────

    private void tickMining(FakePlayer fp, MiningState state) {
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            stopMining(fp.getUuid());
            return;
        }

        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
        if (state.freeze > 0) {
            state.freeze--;
            return;
        }

        if (state.waitingForDrops) {
            if (state.pickupWaitTicks > 0) {
                state.pickupWaitTicks--;
                return;
            }
            if (fp.isPickUpItemsEnabled() && state.pickupWaitExtraTicks > 0 && hasNearbyDrops(bot, state.forcedTarget)) {
                state.pickupWaitExtraTicks--;
                return;
            }
            state.waitingForDrops = false;
            state.pickupWaitExtraTicks = 0;
            if (state.stopAfterForcedTarget) {
                stopMining(fp.getUuid());
                return;
            }
            // Fall through to continue mining the next look-target in classic mode
        }
            if (state.stopAfterForcedTarget) {
                stopMining(fp.getUuid());
                return;
            }
        }

        BlockPos targetPos = state.forcedTarget != null ? state.forcedTarget : getTargetBlock(bot);
        if (targetPos == null) {
            if (state.currentPos != null) abortMining(nms, state);
            if (state.stopAfterForcedTarget) stopMining(fp.getUuid());
            return;
        }

        BlockState blockState = nms.level().getBlockState(targetPos);
        if (blockState.isAir()) {
            if (state.currentPos != null && state.currentPos.equals(targetPos)) {
                state.currentPos = null;
                state.progress = 0;
            }
            if (state.stopAfterForcedTarget) stopMining(fp.getUuid());
            return;
        }

        if (nms.blockActionRestricted(nms.level(), targetPos, nms.gameMode.getGameModeForPlayer())) return;

        equipBestMiningTool(bot, targetPos);

        Direction side = Direction.DOWN;
        if (bot.getGameMode() == GameMode.CREATIVE) {
            nms.gameMode.handleBlockBreakAction(targetPos,
                    ServerboundPlayerActionPacket.Action.START_DESTROY_BLOCK,
                    side, nms.level().getMaxY(), -1);
            nms.swing(InteractionHand.MAIN_HAND);
            if (state.once || state.stopAfterForcedTarget) {
                beginPickupWait(fp, state, targetPos);
            } else {
                state.freeze = 5;
                state.currentPos = null;
            }
            return;
        }

        if (state.currentPos == null || !state.currentPos.equals(targetPos)) {
            if (state.currentPos != null) {
                nms.gameMode.handleBlockBreakAction(state.currentPos,
                        ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                        side, nms.level().getMaxY(), -1);
            }

            nms.gameMode.handleBlockBreakAction(targetPos,
                    ServerboundPlayerActionPacket.Action.START_DESTROY_BLOCK,
                    side, nms.level().getMaxY(), -1);

            if (state.progress == 0) blockState.attack(nms.level(), targetPos, nms);

            float speed = blockState.getDestroyProgress(nms, nms.level(), targetPos);
            if (speed >= 1.0F) {
                nms.swing(InteractionHand.MAIN_HAND);
                if (state.once || state.stopAfterForcedTarget) {
                    beginPickupWait(fp, state, targetPos);
                } else {
                    state.currentPos = null;
                    state.freeze = 5;
                }
                return;
            }
            state.currentPos = targetPos;
            state.progress = 0;
        } else {
            float speed = blockState.getDestroyProgress(nms, nms.level(), targetPos);
            state.progress += speed;
            if (state.progress >= 1.0F) {
                nms.gameMode.handleBlockBreakAction(targetPos,
                        ServerboundPlayerActionPacket.Action.STOP_DESTROY_BLOCK,
                        side, nms.level().getMaxY(), -1);
                nms.swing(InteractionHand.MAIN_HAND);
                if (state.once || state.stopAfterForcedTarget) {
                    beginPickupWait(fp, state, targetPos);
                } else {
                    state.currentPos = null;
                    state.progress = 0;
                    state.freeze = 5;
                }
                return;
            }
            nms.level().destroyBlockProgress(-1, targetPos, (int) (state.progress * 10));
        }

        nms.swing(InteractionHand.MAIN_HAND);
        nms.resetLastActionTime();
    }

    private void abortMining(ServerPlayer nms, MiningState state) {
        if (state.currentPos == null) return;
        nms.level().destroyBlockProgress(-1, state.currentPos, -1);
        nms.gameMode.handleBlockBreakAction(state.currentPos,
                ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                Direction.DOWN, nms.level().getMaxY(), -1);
        state.currentPos = null;
        state.progress = 0;
    }

    private BlockPos getTargetBlock(Player bot) {
        try {
            Location eye = bot.getEyeLocation();
            BlockIterator iter = new BlockIterator(bot.getWorld(), eye.toVector(), eye.getDirection(), 0, 5);
            while (iter.hasNext()) {
                Block b = iter.next();
                if (!b.getType().isAir() && b.getType().isSolid()) {
                    return new BlockPos(b.getX(), b.getY(), b.getZ());
                }
            }
        } catch (IllegalStateException ignored) {}
        return null;
    }

    private AreaBlock findNextAreaTarget(Player bot, AreaSelection selection, AreaMineJob job) {
        World world = bot.getWorld();
        AreaBlock best = null;
        double bestDist = Double.MAX_VALUE;

        for (int y = selection.maxY(); y >= selection.minY(); y--) {
            for (int x = selection.minX(); x <= selection.maxX(); x++) {
                for (int z = selection.minZ(); z <= selection.maxZ(); z++) {
                    AreaBlock candidate = new AreaBlock(x, y, z);
                    if (job.completed.contains(candidate) || job.skipped.contains(candidate)) continue;
                    Block block = world.getBlockAt(x, y, z);
                    if (!isMineable(block)) continue;
                    double dist = block.getLocation().add(0.5, 0.5, 0.5).distanceSquared(bot.getLocation());
                    if (dist < bestDist) {
                        bestDist = dist;
                        best = candidate;
                    }
                }
            }
        }
        return best;
    }

    private boolean isMineable(Block block) {
        if (block == null) return false;
        Material type = block.getType();
        if (type.isAir() || !type.isSolid()) return false;
        if (block.getState() instanceof InventoryHolder) return false;
        return switch (type) {
            case BEDROCK, BARRIER, END_PORTAL, END_PORTAL_FRAME, NETHER_PORTAL,
                 COMMAND_BLOCK, CHAIN_COMMAND_BLOCK, REPEATING_COMMAND_BLOCK,
                 STRUCTURE_BLOCK, JIGSAW, LIGHT, REINFORCED_DEEPSLATE -> false;
            default -> true;
        };
    }

    private Location findStandLocation(World world, AreaBlock target) {
        int x = target.x;
        int y = target.y;
        int z = target.z;
        int[][] candidates = new int[][]{
                {x + 1, y, z}, {x - 1, y, z}, {x, y, z + 1}, {x, y, z - 1},
                {x + 1, y - 1, z}, {x - 1, y - 1, z}, {x, y - 1, z + 1}, {x, y - 1, z - 1},
                {x + 1, y + 1, z}, {x - 1, y + 1, z}, {x, y + 1, z + 1}, {x, y + 1, z - 1}
        };
        for (int[] c : candidates) {
            if (BotPathfinder.walkable(world, c[0], c[1], c[2])) {
                Location loc = new Location(world, c[0] + 0.5, c[1], c[2] + 0.5);
                if (loc.distanceSquared(target.center(world)) <= 25.0) return loc;
            }
        }
        return null;
    }

    private Location faceToward(Location from, Location target) {
        Location loc = from.clone();
        double dx = target.getX() - loc.getX();
        double dy = target.getY() - (loc.getY() + 1.62);
        double dz = target.getZ() - loc.getZ();
        double xz = Math.sqrt(dx * dx + dz * dz);
        float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
        float pitch = (float) -Math.toDegrees(Math.atan2(dy, xz));
        loc.setYaw(yaw);
        loc.setPitch(pitch);
        return loc;
    }

    private boolean isStorageOffloadNeeded(PlayerInventory inv) {
        return inv.firstEmpty() == -1;
    }

    private boolean hasDepositableLoot(PlayerInventory inv) {
        int heldSlot = inv.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            if (isDepositCandidate(slot, heldSlot, inv.getItem(slot))) return true;
        }
        return false;
    }

    private int moveBotInventoryToStorage(PlayerInventory source, Inventory target) {
        int moved = 0;
        int heldSlot = source.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = source.getItem(slot);
            if (!isDepositCandidate(slot, heldSlot, item)) continue;
            ItemStack original = item.clone();
            Map<Integer, ItemStack> leftovers = target.addItem(original);
            if (leftovers.isEmpty()) {
                moved += original.getAmount();
                source.setItem(slot, null);
            } else {
                ItemStack left = leftovers.values().iterator().next();
                int movedNow = original.getAmount() - left.getAmount();
                if (movedNow > 0) {
                    moved += movedNow;
                    source.setItem(slot, left);
                }
            }
        }
        return moved;
    }

    private boolean containerCanAcceptAny(PlayerInventory source, Inventory target) {
        int heldSlot = source.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = source.getItem(slot);
            if (!isDepositCandidate(slot, heldSlot, item)) continue;
            if (inventoryCanFit(target, item)) return true;
        }
        return false;
    }

    private boolean inventoryCanFit(Inventory inv, ItemStack item) {
        for (ItemStack content : inv.getContents()) {
            if (content == null || content.getType() == Material.AIR) return true;
            if (content.isSimilar(item) && content.getAmount() < content.getMaxStackSize()) return true;
        }
        return false;
    }

    private boolean isDepositCandidate(int slot, int heldSlot, ItemStack item) {
        if (item == null || item.getType() == Material.AIR) return false;
        if (slot == heldSlot && isLikelyMiningTool(item)) return false;
        return !isLikelyMiningTool(item);
    }

    private boolean isLikelyMiningTool(ItemStack item) {
        Material type = item.getType();
        return type.name().endsWith("_PICKAXE")
                || type.name().endsWith("_AXE")
                || type.name().endsWith("_SHOVEL")
                || type.name().endsWith("_HOE")
                || type.name().endsWith("_SWORD")
                || type == Material.SHEARS;
    }

    private void beginPickupWait(FakePlayer fp, MiningState state, BlockPos targetPos) {
        state.currentPos = null;
        state.progress = 0;
        state.freeze = 0;
        state.forcedTarget = targetPos;
        state.completeForcedTargetOnStop = state.stopAfterForcedTarget;
        state.waitingForDrops = true;

        // No storage configured → skip the pickup delay entirely for maximum mining speed.
        // The bot will naturally pick up drops as it walks past them, or they stay on the ground.
        boolean hasStorage = !storageStore.getStorages(fp.getName()).isEmpty();
        if (!hasStorage) {
            state.pickupWaitTicks = 0;
            state.pickupWaitExtraTicks = 0;
        } else {
            state.pickupWaitTicks = fp.isPickUpItemsEnabled() ? AREA_PICKUP_WAIT_TICKS : 1;
            state.pickupWaitExtraTicks = fp.isPickUpItemsEnabled() ? AREA_PICKUP_EXTRA_TICKS : 0;
        }
    }

    private void interruptMining(UUID botUuid) {
        Integer taskId = miningTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);
        manager.unlockNavigation(botUuid);
        activeMineLocations.remove(botUuid);
        activeMineOnceFlags.remove(botUuid);

        MiningState state = miningStates.remove(botUuid);
        if (state == null) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;

        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
        abortMining(nms, state);
    }

    private boolean isAtLockLocation(Player bot, Location lockLoc) {
        if (bot == null || lockLoc == null) return false;
        if (bot.getWorld() != lockLoc.getWorld()) return false;
        double xz = xzDist(bot.getLocation(), lockLoc);
        double dy = Math.abs(bot.getLocation().getY() - lockLoc.getY());
        return xz <= ARRIVAL_DIST && dy < 1.25;
    }

    private void useStorageBlock(Player bot, Block block) {
        try {
            ServerPlayer nms = ((CraftPlayer) bot).getHandle();
            BlockPos pos = new BlockPos(block.getX(), block.getY(), block.getZ());
            Vec3 hitVec = new Vec3(block.getX() + 0.5, block.getY() + 0.5, block.getZ() + 0.5);
            BlockHitResult hit = new BlockHitResult(hitVec, Direction.UP, pos, false);
            nms.resetLastActionTime();
            var result = nms.gameMode.useItemOn(
                    nms, nms.level(), nms.getItemInHand(InteractionHand.MAIN_HAND), InteractionHand.MAIN_HAND, hit);
            if (result.consumesAction()) {
                nms.swing(InteractionHand.MAIN_HAND);
            }
        } catch (Throwable ignored) {}
    }

    private boolean hasNearbyDrops(Player bot, BlockPos targetPos) {
        if (targetPos == null) return false;
        Location center = new Location(bot.getWorld(), targetPos.getX() + 0.5, targetPos.getY() + 0.5, targetPos.getZ() + 0.5);
        for (org.bukkit.entity.Entity entity : bot.getNearbyEntities(2.0, 1.5, 2.0)) {
            if (!(entity instanceof Item item) || item.isDead()) continue;
            if (item.getLocation().distanceSquared(center) <= 6.25) return true;
        }
        return false;
    }

    private void equipBestMiningTool(Player bot, BlockPos targetPos) {
        if (targetPos == null) return;
        Block block = bot.getWorld().getBlockAt(targetPos.getX(), targetPos.getY(), targetPos.getZ());
        ToolClass preferred = determineToolClass(block.getType());
        PlayerInventory inv = bot.getInventory();
        int heldSlot = inv.getHeldItemSlot();
        int bestSlot = -1;
        int bestScore = Integer.MIN_VALUE;

        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = inv.getItem(slot);
            int score = toolScore(item, preferred);
            if (score > bestScore) {
                bestScore = score;
                bestSlot = slot;
            }
        }

        if (bestSlot < 0 || bestScore <= 0 || bestSlot == heldSlot) return;

        if (bestSlot <= 8) {
            inv.setHeldItemSlot(bestSlot);
            if (plugin.getInventoryCommand() != null) {
                plugin.getInventoryCommand().refreshOpenGui(bot.getUniqueId());
            }
            return;
        }

        ItemStack held = inv.getItem(heldSlot);
        inv.setItem(heldSlot, inv.getItem(bestSlot));
        inv.setItem(bestSlot, held);
        if (plugin.getInventoryCommand() != null) {
            plugin.getInventoryCommand().refreshOpenGui(bot.getUniqueId());
        }
    }

    private int toolScore(ItemStack item, ToolClass preferred) {
        if (item == null || item.getType() == Material.AIR) return Integer.MIN_VALUE;
        Material type = item.getType();
        ToolClass actual = classifyTool(type);
        if (actual == ToolClass.NONE) return Integer.MIN_VALUE;

        int score = toolTierScore(type);
        if (actual == preferred) score += 10_000;
        else if (preferred == ToolClass.SHEARS && type == Material.SHEARS) score += 10_000;
        else if (preferred == ToolClass.NONE) score += 100;
        else score += 1_000;

        if (type == Material.SHEARS && preferred != ToolClass.SHEARS) score -= 500;
        return score;
    }

    private ToolClass determineToolClass(Material blockType) {
        if (blockType == Material.COBWEB) return ToolClass.SWORD;
        if (blockType.name().contains("LEAVES")
                || blockType == Material.VINE
                || blockType == Material.GLOW_LICHEN
                || blockType.name().endsWith("_WOOL")) {
            return ToolClass.SHEARS;
        }
        if (Tag.MINEABLE_PICKAXE.isTagged(blockType)) return ToolClass.PICKAXE;
        if (Tag.MINEABLE_AXE.isTagged(blockType)) return ToolClass.AXE;
        if (Tag.MINEABLE_SHOVEL.isTagged(blockType)) return ToolClass.SHOVEL;
        if (Tag.MINEABLE_HOE.isTagged(blockType)) return ToolClass.HOE;
        return ToolClass.NONE;
    }

    private ToolClass classifyTool(Material toolType) {
        String name = toolType.name();
        if (toolType == Material.SHEARS) return ToolClass.SHEARS;
        if (name.endsWith("_PICKAXE")) return ToolClass.PICKAXE;
        if (name.endsWith("_AXE")) return ToolClass.AXE;
        if (name.endsWith("_SHOVEL")) return ToolClass.SHOVEL;
        if (name.endsWith("_HOE")) return ToolClass.HOE;
        if (name.endsWith("_SWORD")) return ToolClass.SWORD;
        return ToolClass.NONE;
    }

    private int toolTierScore(Material toolType) {
        String name = toolType.name();
        if (toolType == Material.SHEARS) return 650;
        if (name.startsWith("NETHERITE_")) return 900;
        if (name.startsWith("DIAMOND_")) return 800;
        if (name.startsWith("IRON_")) return 700;
        if (name.startsWith("GOLDEN_")) return 600;
        if (name.startsWith("STONE_")) return 500;
        if (name.startsWith("WOODEN_")) return 400;
        return 100;
    }

    private void stopAreaJob(UUID botUuid, boolean notifyStop) {
        Integer taskId = areaTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);
        AreaMineJob job = areaJobs.remove(botUuid);
        if (notifyStop && job != null) {
            FakePlayer fp = manager.getByUuid(botUuid);
            notifyStarter(job, "mine-area-stopped", "name", fp != null ? fp.getDisplayName() : botUuid.toString());
        }
    }

    private void notifyStarter(AreaMineJob job, String key, String... args) {
        if (job.starterUuid != null) {
            Player p = Bukkit.getPlayer(job.starterUuid);
            if (p != null && p.isOnline()) {
                p.sendMessage(Lang.get(key, args));
                return;
            }
        }
        if (job.consoleStarted) {
            plugin.getLogger().info(Lang.raw(key, args));
        }
    }

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx;
        double dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }

    private static final class MiningState {
        BlockPos currentPos;
        float progress;
        int freeze;
        boolean once;
        BlockPos forcedTarget;
        boolean stopAfterForcedTarget;
        boolean completeForcedTargetOnStop;
        boolean waitingForDrops;
        int pickupWaitTicks;
        int pickupWaitExtraTicks;
    }

    private enum ToolClass { PICKAXE, AXE, SHOVEL, HOE, SHEARS, SWORD, NONE }

    private static final class AreaSelection {
        Location pos1;
        Location pos2;

        boolean isComplete() { return pos1 != null && pos2 != null; }
        boolean sameWorld() {
            return isComplete() && pos1.getWorld() != null && pos1.getWorld().equals(pos2.getWorld());
        }
        int minX() { return Math.min(pos1.getBlockX(), pos2.getBlockX()); }
        int maxX() { return Math.max(pos1.getBlockX(), pos2.getBlockX()); }
        int minY() { return Math.min(pos1.getBlockY(), pos2.getBlockY()); }
        int maxY() { return Math.max(pos1.getBlockY(), pos2.getBlockY()); }
        int minZ() { return Math.min(pos1.getBlockZ(), pos2.getBlockZ()); }
        int maxZ() { return Math.max(pos1.getBlockZ(), pos2.getBlockZ()); }
        int blockCount() { return (maxX() - minX() + 1) * (maxY() - minY() + 1) * (maxZ() - minZ() + 1); }
        AreaSelection copy() {
            AreaSelection copy = new AreaSelection();
            copy.pos1 = pos1.clone();
            copy.pos2 = pos2.clone();
            return copy;
        }
    }

    private static final class AreaMineJob {
        final AreaSelection selection;
        final UUID starterUuid;
        final boolean consoleStarted;
        final Set<AreaBlock> completed = new HashSet<>();
        final Set<AreaBlock> skipped = new HashSet<>();
        AreaBlock currentTarget;
        int preferredStorageIndex = 0;
        int blocksMined = 0;
        /** {@code true} while the bot is depositing its final loot after the area is exhausted. */
        boolean finishingDeposit = false;

        AreaMineJob(AreaSelection selection, CommandSender sender) {
            this.selection = selection;
            this.starterUuid = sender instanceof Player p ? p.getUniqueId() : null;
            this.consoleStarted = !(sender instanceof Player);
        }
    }

    private record AreaBlock(int x, int y, int z) {
        BlockPos toBlockPos() { return new BlockPos(x, y, z); }
        Location center(World world) { return new Location(world, x + 0.5, y + 0.5, z + 0.5); }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;
import net.minecraft.core.BlockPos;
import net.minecraft.core.Direction;
import net.minecraft.network.protocol.game.ServerboundPlayerActionPacket;
import net.minecraft.server.level.ServerPlayer;
import net.minecraft.world.InteractionHand;
import net.minecraft.world.level.block.state.BlockState;
import net.minecraft.world.phys.BlockHitResult;
import net.minecraft.world.phys.Vec3;
import org.bukkit.Bukkit;
import org.bukkit.GameMode;
import org.bukkit.Location;
import org.bukkit.Material;
import org.bukkit.Tag;
import org.bukkit.World;
import org.bukkit.block.Block;
import org.bukkit.command.CommandSender;
import org.bukkit.craftbukkit.entity.CraftPlayer;
import org.bukkit.entity.Item;
import org.bukkit.entity.Player;
import org.bukkit.inventory.Inventory;
import org.bukkit.inventory.InventoryHolder;
import org.bukkit.inventory.ItemStack;
import org.bukkit.inventory.PlayerInventory;
import org.bukkit.scheduler.BukkitRunnable;
import org.bukkit.scheduler.BukkitTask;
import org.bukkit.util.BlockIterator;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Mine command with two modes:
 * <ul>
 *   <li>Classic: {@code /fpp mine <bot> [once|stop]}</li>
 *   <li>Area mode: {@code /fpp mine <bot> --pos1}, {@code --pos2}, {@code --start}</li>
 * </ul>
 *
 * <p>Area mining walks the bot to each reachable block in the cuboid selection, mines it,
 * and when the bot inventory is full automatically walks to the configured storage blocks
 * from {@code /fpp storage <bot> [storage_name]} to deposit items.
 */
public final class MineCommand implements FppCommand {

    private static final double ARRIVAL_DIST    = 1.2;
    private static final double SPRINT_DIST     = 6.0;
    private static final double WP_ARRIVE_XZ    = 0.65;
    private static final int    RECALC_INTERVAL = 60;
    private static final int    STUCK_TICKS     = 8;
    private static final double STUCK_THRESHOLD = 0.04;
    private static final int    LOOK_BLOCK_RANGE = 8;
    private static final int    AREA_CONTROLLER_PERIOD = 5;
    private static final int    AREA_PICKUP_WAIT_TICKS = 8;
    private static final int    AREA_PICKUP_EXTRA_TICKS = 20;

    private final FakePlayerPlugin  plugin;
    private final FakePlayerManager manager;
    private final StorageStore storageStore;

    private final Map<UUID, BukkitTask> navTasks    = new ConcurrentHashMap<>();
    private final Map<UUID, Integer>    miningTasks  = new ConcurrentHashMap<>();
    private final Map<UUID, MiningState> miningStates = new ConcurrentHashMap<>();
    private final Map<UUID, Location>   activeMineLocations = new ConcurrentHashMap<>();
    private final Map<UUID, Boolean>    activeMineOnceFlags  = new ConcurrentHashMap<>();

    private final Map<UUID, AreaSelection> selections = new ConcurrentHashMap<>();
    private final Map<UUID, AreaMineJob> areaJobs = new ConcurrentHashMap<>();
    private final Map<UUID, Integer> areaTasks = new ConcurrentHashMap<>();

    public MineCommand(FakePlayerPlugin plugin, FakePlayerManager manager, StorageStore storageStore) {
        this.plugin = plugin;
        this.manager = manager;
        this.storageStore = storageStore;
    }

    @Override public String getName()        { return "mine"; }
    @Override public String getUsage()       { return "<bot> [once|stop|--pos1|--pos2|--start]  |  stop"; }
    @Override public String getDescription() { return "Walk a bot to mine one block, mine continuously, or clear a selected area with storage offloading."; }
    @Override public String getPermission()  { return Perm.MINE; }
    @Override public boolean canUse(CommandSender sender) { return Perm.has(sender, Perm.MINE); }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("mine-usage"));
            return true;
        }

        // /fpp mine stop - stop every bot
        if (args[0].equalsIgnoreCase("stop") && args.length == 1) {
            stopAll();
            sender.sendMessage(Lang.get("mine-stopped-all"));
            return true;
        }

        String botName = args[0];
        FakePlayer fp = manager.getByName(botName);
        if (fp == null) {
            sender.sendMessage(Lang.get("mine-not-found", "name", botName));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("mine-bot-offline", "name", fp.getDisplayName()));
            return true;
        }

        if (args.length >= 2) {
            String action = args[1].toLowerCase(Locale.ROOT);
            switch (action) {
                case "stop" -> {
                    cleanupBot(fp.getUuid());
                    sender.sendMessage(Lang.get("mine-stopped", "name", fp.getDisplayName()));
                    return true;
                }
                case "--pos1", "pos1" -> {
                    if (!(sender instanceof Player player)) {
                        sender.sendMessage(Lang.get("player-only"));
                        return true;
                    }
                    Block target = player.getTargetBlockExact(LOOK_BLOCK_RANGE);
                    if (target == null) {
                        sender.sendMessage(Lang.get("mine-look-at-block"));
                        return true;
                    }
                    AreaSelection selection = selections.computeIfAbsent(fp.getUuid(), k -> new AreaSelection());
                    selection.pos1 = target.getLocation();
                    sender.sendMessage(Lang.get("mine-pos1-set",
                            "name", fp.getDisplayName(),
                            "x", String.valueOf(target.getX()),
                            "y", String.valueOf(target.getY()),
                            "z", String.valueOf(target.getZ())));
                    return true;
                }
                case "--pos2", "pos2" -> {
                    if (!(sender instanceof Player player)) {
                        sender.sendMessage(Lang.get("player-only"));
                        return true;
                    }
                    Block target = player.getTargetBlockExact(LOOK_BLOCK_RANGE);
                    if (target == null) {
                        sender.sendMessage(Lang.get("mine-look-at-block"));
                        return true;
                    }
                    AreaSelection selection = selections.computeIfAbsent(fp.getUuid(), k -> new AreaSelection());
                    selection.pos2 = target.getLocation();
                    sender.sendMessage(Lang.get("mine-pos2-set",
                            "name", fp.getDisplayName(),
                            "x", String.valueOf(target.getX()),
                            "y", String.valueOf(target.getY()),
                            "z", String.valueOf(target.getZ())));
                    return true;
                }
                case "--start", "start" -> {
                    startAreaMining(sender, fp);
                    return true;
                }
            }
        }

        boolean once = args.length >= 2 && args[1].equalsIgnoreCase("once");
        stopAreaJob(fp.getUuid(), false);
        cancelAll(fp.getUuid());

        Location dest = (sender instanceof Player sp)
                ? sp.getLocation().clone()
                : bot.getLocation().clone();

        double xzDist = xzDist(bot.getLocation(), dest);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartMining(fp, once, dest, null, false);
            sender.sendMessage(once
                    ? Lang.get("mine-started-once", "name", fp.getDisplayName())
                    : Lang.get("mine-started", "name", fp.getDisplayName()));
        } else {
            startNavigation(fp, dest, () -> lockAndStartMining(fp, once, dest, null, false));
            sender.sendMessage(Lang.get("mine-walking", "name", fp.getDisplayName()));
        }
        return true;
    }

    // ── Tab-complete ──────────────────────────────────────────────────────────

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        if (!canUse(sender)) return List.of();

        if (args.length == 1) {
            String prefix = args[0].toLowerCase(Locale.ROOT);
            List<String> out = new ArrayList<>();
            if ("stop".startsWith(prefix)) out.add("stop");
            for (FakePlayer fp : manager.getActivePlayers()) {
                if (fp.getName().toLowerCase(Locale.ROOT).startsWith(prefix)) out.add(fp.getName());
            }
            return out;
        }

        // Second arg only makes sense when the first arg is a bot name, not "stop"
        if (args.length == 2 && !args[0].equalsIgnoreCase("stop")) {
            String prefix = args[1].toLowerCase(Locale.ROOT);
            List<String> out = new ArrayList<>();
            for (String option : List.of("once", "stop", "--pos1", "--pos2", "--start")) {
                if (option.startsWith(prefix)) out.add(option);
            }
            return out;
        }

        return List.of();
    }

    // ── Area mining ────────────────────────────────────────────────────────────

    private void startAreaMining(CommandSender sender, FakePlayer fp) {
        AreaSelection selection = selections.get(fp.getUuid());
        if (selection == null || !selection.isComplete()) {
            sender.sendMessage(Lang.get("mine-area-missing-selection", "name", fp.getDisplayName()));
            return;
        }
        if (!selection.sameWorld()) {
            sender.sendMessage(Lang.get("mine-area-world-mismatch"));
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("mine-bot-offline", "name", fp.getDisplayName()));
            return;
        }
        if (bot.getWorld() != Objects.requireNonNull(selection.pos1.getWorld())) {
            sender.sendMessage(Lang.get("mine-area-bot-world",
                    "name", fp.getDisplayName(),
                    "world", selection.pos1.getWorld().getName()));
            return;
        }

        cleanupBot(fp.getUuid());
        AreaMineJob job = new AreaMineJob(selection.copy(), sender);
        areaJobs.put(fp.getUuid(), job);
        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> tickAreaJob(fp.getUuid()), 0L, AREA_CONTROLLER_PERIOD).getTaskId();
        areaTasks.put(fp.getUuid(), taskId);
        sender.sendMessage(Lang.get("mine-area-started",
                "name", fp.getDisplayName(),
                "count", String.valueOf(selection.blockCount())));
    }

    @SuppressWarnings("unchecked")
    private void startNavigation(FakePlayer fp, Location dest, Runnable onArrive) {
        final UUID uuid = fp.getUuid();
        // Cancel any previous nav task for this bot first
        BukkitTask old = navTasks.remove(uuid);
        if (old != null && !old.isCancelled()) old.cancel();
        manager.lockForNavigation(uuid);
        manager.clearNavJump(uuid);
        final List<BotPathfinder.Move>[] pathRef = new List[]{null};
        final int[] wpIdx = {0};
        final int[] recalcIn = {0};
        final int[] stuckFor = {0};
        final double[] prevX = {fp.getPlayer().getLocation().getX()};
        final double[] prevZ = {fp.getPlayer().getLocation().getZ()};

        BukkitTask task = new BukkitRunnable() {
            @Override
            public void run() {
                Player bot = Bukkit.getPlayer(uuid);
                if (bot == null || !bot.isOnline()) {
                    cleanup(null);
                    return;
                }

                Location botLoc = bot.getLocation();
                double dist = xzDist(botLoc, dest);
                if (dist <= ARRIVAL_DIST) {
                    cleanup(bot);
                    onArrive.run();
                    return;
                }

                boolean exhausted = (pathRef[0] == null || wpIdx[0] >= pathRef[0].size());
                boolean heartbeat = (--recalcIn[0] <= 0);
                if (exhausted || heartbeat) {
                    recalcIn[0] = RECALC_INTERVAL;
                    BotPathfinder.PathOptions opts = new BotPathfinder.PathOptions(
                            Config.pathfindingParkour(),
                            Config.pathfindingBreakBlocks(),
                            Config.pathfindingPlaceBlocks());
                    List<BotPathfinder.Move> newPath = BotPathfinder.findPathMoves(
                            botLoc.getWorld(),
                            botLoc.getBlockX(), botLoc.getBlockY(), botLoc.getBlockZ(),
                            dest.getBlockX(), dest.getBlockY(), dest.getBlockZ(),
                            opts);
                    pathRef[0] = newPath;
                    wpIdx[0] = (newPath != null && newPath.size() > 1) ? 1 : 0;
                    stuckFor[0] = 0;
                }

                List<BotPathfinder.Move> path = pathRef[0];
                if (path == null || path.isEmpty() || wpIdx[0] >= path.size()) {
                    walkToward(bot, dest, dist);
                    return;
                }

                BotPathfinder.Move wp = path.get(wpIdx[0]);
                double wpCX = wp.x() + 0.5;
                double wpCZ = wp.z() + 0.5;
                double wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                boolean wpYClose = Math.abs(botLoc.getY() - wp.y()) < 1.2;
                if (wpXZDist < WP_ARRIVE_XZ && wpYClose) {
                    wpIdx[0]++;
                    if (wpIdx[0] >= path.size()) {
                        recalcIn[0] = 0;
                        return;
                    }
                    wp = path.get(wpIdx[0]);
                    wpCX = wp.x() + 0.5;
                    wpCZ = wp.z() + 0.5;
                    wpXZDist = xzDistRaw(botLoc.getX(), botLoc.getZ(), wpCX, wpCZ);
                }

                double dx = wpCX - botLoc.getX();
                double dz = wpCZ - botLoc.getZ();
                float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST || wp.type() == BotPathfinder.MoveType.PARKOUR);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);

                if (!bot.isInWater() && !bot.isInLava()) {
                    if (wp.y() > botLoc.getBlockY()) {
                        manager.requestNavJump(uuid);
                    } else if (wp.type() == BotPathfinder.MoveType.PARKOUR && wpXZDist >= 1.0 && wpXZDist <= 3.5) {
                        manager.requestNavJump(uuid);
                    }
                }

                double moved = xzDistRaw(botLoc.getX(), botLoc.getZ(), prevX[0], prevZ[0]);
                if (moved < STUCK_THRESHOLD) {
                    if (++stuckFor[0] >= STUCK_TICKS) {
                        if (!bot.isInWater() && !bot.isInLava()) manager.requestNavJump(uuid);
                        recalcIn[0] = 0;
                        stuckFor[0] = 0;
                    }
                } else {
                    stuckFor[0] = 0;
                }
                prevX[0] = botLoc.getX();
                prevZ[0] = botLoc.getZ();
            }

            private void cleanup(Player bot) {
                manager.unlockNavigation(uuid);
                manager.clearNavJump(uuid);
                if (bot != null) {
                    NmsPlayerSpawner.setMovementForward(bot, 0f);
                    NmsPlayerSpawner.setJumping(bot, false);
                    bot.setSprinting(false);
                }
                cancel();
                navTasks.remove(uuid);
            }

            private void walkToward(Player bot, Location target, double dist) {
                Location bl = bot.getLocation();
                float yaw = (float) Math.toDegrees(
                        Math.atan2(-(target.getX() - bl.getX()), target.getZ() - bl.getZ()));
                bot.setRotation(yaw, 0f);
                NmsPlayerSpawner.setHeadYaw(bot, yaw);
                bot.setSprinting(dist > SPRINT_DIST);
                NmsPlayerSpawner.setMovementForward(bot, 1.0f);
            }
        }.runTaskTimer(plugin, 0L, 1L);

        navTasks.put(uuid, task);
    }

    // ── Phase 2: lock + mine ──────────────────────────────────────────────────

    /**
     * Called once the bot has arrived at the mining destination.
     * Snaps the bot to the exact position, registers the mining lock, and starts the
     * 1-tick mining loop.
     */
    private void lockAndStartMining(FakePlayer fp, boolean once, Location lockLoc,
                                    BlockPos forcedTarget, boolean stopAfterForcedTarget) {
        UUID uuid = fp.getUuid();
        Player bot = fp.getPlayer();
        if (bot == null) return;

        // Final snap to exact position (bot is already ≤ ARRIVAL_DIST away, so imperceptible)
        bot.teleport(lockLoc);
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        // Lock position + head-AI in FakePlayerManager's tick loop
        manager.lockForMining(uuid, lockLoc);

        // Record active mine state for persistence
        activeMineLocations.put(uuid, lockLoc.clone());
        activeMineOnceFlags.put(uuid, once);

        // Init state
        MiningState state = new MiningState();
        state.once = once;
        state.forcedTarget = forcedTarget;
        state.stopAfterForcedTarget = stopAfterForcedTarget;
        miningStates.put(uuid, state);

        // 1-tick mining task
        int taskId = Bukkit.getScheduler().runTaskTimer(plugin, () -> {
            Player b = fp.getPlayer();
            if (b == null || !b.isOnline()) {
                stopMining(uuid);
                return;
            }
            tickMining(fp, state);
        }, 0L, 1L).getTaskId();

        miningTasks.put(uuid, taskId);
    }

    // ── Stop helpers ──────────────────────────────────────────────────────────

    /**
     * Cancels both the navigation task AND the mining task for the given bot,
     * and releases the position lock.
     */
    private void cancelAll(UUID botUuid) {
        // Cancel phase-1 nav
        BukkitTask t = navTasks.remove(botUuid);
        if (t != null && !t.isCancelled()) t.cancel();
        manager.clearNavJump(botUuid);

        // Stop phase-2 mine
        stopMining(botUuid);

        // Stop movement if bot still exists
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp != null) {
            Player bot = fp.getPlayer();
            if (bot != null && bot.isOnline()) {
                NmsPlayerSpawner.setMovementForward(bot, 0f);
                NmsPlayerSpawner.setJumping(bot, false);
                bot.setSprinting(false);
            }
        }
    }

    /** Stops only the mining phase (task + lock + state cleanup). */
    public void stopMining(UUID botUuid) {
        Integer taskId = miningTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);
        manager.unlockNavigation(botUuid);

        // Clear persistence tracking
        activeMineLocations.remove(botUuid);
        activeMineOnceFlags.remove(botUuid);

        MiningState state = miningStates.remove(botUuid);
        if (state != null) {
            if (state.currentPos != null) {
                FakePlayer fp = manager.getByUuid(botUuid);
                if (fp != null) {
                    Player bot = fp.getPlayer();
                    if (bot != null && bot.isOnline()) {
                        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
                        nms.level().destroyBlockProgress(-1, state.currentPos, -1);
                        nms.gameMode.handleBlockBreakAction(
                                state.currentPos,
                                ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                                Direction.DOWN, nms.level().getMaxY(), -1);
                    }
                }
            }
            if (state.completeForcedTargetOnStop && state.stopAfterForcedTarget && state.forcedTarget != null) {
                AreaMineJob job = areaJobs.get(botUuid);
                if (job != null && job.currentTarget != null) {
                    job.completed.add(job.currentTarget);
                    job.currentTarget = null;
                    job.blocksMined++;
                    // Fast-trigger the area controller on the next tick instead of waiting
                    // up to AREA_CONTROLLER_PERIOD (5) ticks for the periodic task.
                    // This is safe — tickAreaJob checks nav/mine locks and returns early
                    // if either is still in progress.
                    Bukkit.getScheduler().runTaskLater(plugin, () -> tickAreaJob(botUuid), 1L);
                }
            }
        }
    }

    /** Stops all bots (navigation + mining). */
    public void stopAll() {
        new HashSet<>(navTasks.keySet()).forEach(this::cleanupBot);
        new HashSet<>(miningTasks.keySet()).forEach(this::cleanupBot);
        new HashSet<>(areaTasks.keySet()).forEach(this::cleanupBot);
    }

    /** Cleans up all navigation, mining, and area job state for the given bot. */
    public void cleanupBot(UUID botUuid) {
        cancelAll(botUuid);
        stopAreaJob(botUuid, false);
    }

    /** Removes any saved pos1/pos2 selection for this bot. */
    public void clearSelection(UUID botUuid) {
        selections.remove(botUuid);
    }

    /** Returns {@code true} if the bot is currently navigating to a mining spot. */
    public boolean isNavigating(UUID botUuid) { return navTasks.containsKey(botUuid); }

    /** Returns {@code true} if the bot is actively mining. */
    public boolean isMining(UUID botUuid)     { return miningTasks.containsKey(botUuid); }

    // ── Persistence API ───────────────────────────────────────────────────────

    /**
     * Returns the active mining lock location for the given bot,
     * or {@code null} when the bot is not mining.
     */
    @org.jetbrains.annotations.Nullable
    public Location getActiveMineLocation(UUID botUuid) {
        return activeMineLocations.get(botUuid);
    }

    /**
     * Returns {@code true} if the bot's active mine task is once-only.
     */
    public boolean isActiveMineOnce(UUID botUuid) {
        Boolean v = activeMineOnceFlags.get(botUuid);
        return v != null && v;
    }

    /**
     * Resumes mining for a bot restored from persistence.
     * If the bot is already close enough to the lock location, starts mining
     * immediately; otherwise navigates there first.
     */
    public void resumeMining(FakePlayer fp, boolean once, Location loc) {
        if (fp == null || loc == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        cancelAll(fp.getUuid());
        double xzDist = xzDist(bot.getLocation(), loc);
        if (xzDist <= ARRIVAL_DIST) {
            lockAndStartMining(fp, once, loc, null, false);
        } else {
            startNavigation(fp, loc, () -> lockAndStartMining(fp, once, loc, null, false));
        }
    }

    // ── Area mining helpers ────────────────────────────────────────────────────

    private void tickAreaJob(UUID botUuid) {
        AreaMineJob job = areaJobs.get(botUuid);
        if (job == null) {
            stopAreaJob(botUuid, false);
            return;
        }
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            stopAreaJob(botUuid, false);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            stopAreaJob(botUuid, false);
            return;
        }

        // If currently mining: check if the bot was displaced from its locked spot
        if (miningTasks.containsKey(botUuid)) {
            if (job.currentTarget != null) {
                Location lockLoc = activeMineLocations.get(botUuid);
                if (lockLoc != null && !isAtLockLocation(bot, lockLoc)) {
                    // Bot is not at the mining spot — interrupt and re-navigate there
                    interruptMining(botUuid);
                    Location retryFace = faceToward(lockLoc.clone(), job.currentTarget.center(bot.getWorld()));
                    startNavigation(fp, retryFace, () -> lockAndStartMining(fp, false, retryFace, job.currentTarget.toBlockPos(), true));
                }
            }
            return; // wait for the mining task to finish
        }

        // If navigating: wait for it to complete
        if (navTasks.containsKey(botUuid)) return;

        // Inventory full AND storage is configured? Pause to offload.
        // If no storage is set, skip this check entirely — the bot keeps mining at full
        // speed; mined items either get picked up naturally or drop on the ground.
        boolean hasStorage = !storageStore.getStorages(fp.getName()).isEmpty();
        if (hasStorage && isStorageOffloadNeeded(bot.getInventory())) {
            if (!startStorageOffload(fp, job)) {
                // Storage set but all containers are full or unreachable
                notifyStarter(job, "mine-storage-unavailable", "name", fp.getDisplayName());
                stopAreaJob(botUuid, false);
            }
            return;
        }

        // Finishing deposit: deposit nav/mine tasks are done — area is truly complete
        if (job.finishingDeposit) {
            notifyStarter(job, "mine-area-finished",
                    "name", fp.getDisplayName(),
                    "count", String.valueOf(job.blocksMined));
            stopAreaJob(botUuid, false);
            return;
        }

        // Find the next block to mine
        AreaBlock next = findNextAreaTarget(bot, job.selection, job);
        if (next == null) {
            // Area exhausted — if storage is configured and bot has loot, do a final deposit
            if (hasStorage && hasDepositableLoot(bot.getInventory())) {
                job.finishingDeposit = true;
                if (!startStorageOffload(fp, job)) {
                    // Storage set but unreachable — skip the deposit and finish now
                    notifyStarter(job, "mine-storage-unavailable", "name", fp.getDisplayName());
                    notifyStarter(job, "mine-area-finished",
                            "name", fp.getDisplayName(),
                            "count", String.valueOf(job.blocksMined));
                    stopAreaJob(botUuid, false);
                }
                return;
            }
            notifyStarter(job, "mine-area-finished",
                    "name", fp.getDisplayName(),
                    "count", String.valueOf(job.blocksMined));
            stopAreaJob(botUuid, false);
            return;
        }

        // If this was a finishing deposit pass and we're back to mining, clear the flag
        job.finishingDeposit = false;

        Location standLoc = findStandLocation(bot.getWorld(), next);
        if (standLoc == null) {
            job.skipped.add(next);
            return;
        }

        Location targetCenter = next.center(bot.getWorld());
        Location faceLoc = faceToward(standLoc, targetCenter);
        job.currentTarget = next;
        startNavigation(fp, faceLoc, () -> lockAndStartMining(fp, false, faceLoc, next.toBlockPos(), true));
    }

    private boolean startStorageOffload(FakePlayer fp, AreaMineJob job) {
        List<StorageStore.StoragePoint> storages = storageStore.getStorages(fp.getName());
        if (storages.isEmpty()) return false;

        Player bot = fp.getPlayer();
        if (bot == null) return false;

        for (int attempt = 0; attempt < storages.size(); attempt++) {
            int idx = (job.preferredStorageIndex + attempt) % storages.size();
            StorageStore.StoragePoint point = storages.get(idx);
            if (point.location().getWorld() != bot.getWorld()) continue;
            Block block = point.location().getBlock();
            if (!(block.getState() instanceof InventoryHolder holder)) continue;
            if (!containerCanAcceptAny(bot.getInventory(), holder.getInventory())) continue;
            Location standLoc = findStandLocation(bot.getWorld(), new AreaBlock(block.getX(), block.getY(), block.getZ()));
            if (standLoc == null) continue;
            Location faceLoc = faceToward(standLoc, block.getLocation().add(0.5, 0.5, 0.5));
            final int targetIndex = idx;
            startNavigation(fp, faceLoc, () -> depositToStorage(fp, job, targetIndex, point));
            return true;
        }
        return false;
    }

    private void depositToStorage(FakePlayer fp, AreaMineJob job, int storageIndex, StorageStore.StoragePoint point) {
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;
        Block block = point.location().getBlock();
        if (!(block.getState() instanceof InventoryHolder holder)) {
            job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
            return;
        }

        Location standLoc = findStandLocation(bot.getWorld(), new AreaBlock(block.getX(), block.getY(), block.getZ()));
        if (standLoc == null) {
            job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
            return;
        }

        Location faceLoc = faceToward(standLoc, block.getLocation().add(0.5, 0.5, 0.5));
        if (!isAtLockLocation(bot, faceLoc)) {
            startNavigation(fp, faceLoc, () -> depositToStorage(fp, job, storageIndex, point));
            return;
        }

        // Lock bot facing the storage block; enforce rotation every tick
        manager.lockForMining(fp.getUuid(), faceLoc);
        bot.teleport(faceLoc);
        bot.setRotation(faceLoc.getYaw(), faceLoc.getPitch());
        NmsPlayerSpawner.setHeadYaw(bot, faceLoc.getYaw());
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        // 1 tick delay so position lock packet reaches clients before the container opens
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            Player lookBot = fp.getPlayer();
            if (lookBot == null || !lookBot.isOnline()) {
                manager.unlockMining(fp.getUuid());
                return;
            }
            // Swing arm + use block — triggers the open animation for chest/barrel/shulker
            useStorageBlock(lookBot, block);

            // 2 ticks later: transfer items into the container and release the lock
            Bukkit.getScheduler().runTaskLater(plugin, () -> {
                Player liveBot = fp.getPlayer();
                if (liveBot == null || !liveBot.isOnline()) {
                    manager.unlockMining(fp.getUuid());
                    return;
                }
                Block liveBlock = point.location().getBlock();
                if (!(liveBlock.getState() instanceof InventoryHolder liveHolder)) {
                    manager.unlockMining(fp.getUuid());
                    job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
                    return;
                }

                int moved = moveBotInventoryToStorage(liveBot.getInventory(), liveHolder.getInventory());
                liveBot.closeInventory();
                manager.unlockMining(fp.getUuid());
                if (plugin.getInventoryCommand() != null) {
                    plugin.getInventoryCommand().refreshOpenGui(fp.getUuid());
                }
                if (moved > 0 && !isStorageOffloadNeeded(liveBot.getInventory())) {
                    job.preferredStorageIndex = storageIndex;
                } else if (moved > 0) {
                    job.preferredStorageIndex = storageIndex;
                } else {
                    job.preferredStorageIndex = (storageIndex + 1) % Math.max(1, storageStore.getStorages(fp.getName()).size());
                }
            }, 3L);
        }, 1L);
    }

    // ── Mining tick ───────────────────────────────────────────────────────────

    private void tickMining(FakePlayer fp, MiningState state) {
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            stopMining(fp.getUuid());
            return;
        }

        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
        if (state.freeze > 0) {
            state.freeze--;
            return;
        }

        if (state.waitingForDrops) {
            if (state.pickupWaitTicks > 0) {
                state.pickupWaitTicks--;
                return;
            }
            if (fp.isPickUpItemsEnabled() && state.pickupWaitExtraTicks > 0 && hasNearbyDrops(bot, state.forcedTarget)) {
                state.pickupWaitExtraTicks--;
                return;
            }
            state.waitingForDrops = false;
            state.pickupWaitExtraTicks = 0;
            if (state.stopAfterForcedTarget) {
                stopMining(fp.getUuid());
                return;
            }
            // Fall through to continue mining the next look-target in classic mode
        }

        BlockPos targetPos = state.forcedTarget != null ? state.forcedTarget : getTargetBlock(bot);
        if (targetPos == null) {
            if (state.currentPos != null) abortMining(nms, state);
            if (state.stopAfterForcedTarget) stopMining(fp.getUuid());
            return;
        }

        BlockState blockState = nms.level().getBlockState(targetPos);
        if (blockState.isAir()) {
            if (state.currentPos != null && state.currentPos.equals(targetPos)) {
                state.currentPos = null;
                state.progress = 0;
            }
            if (state.stopAfterForcedTarget) stopMining(fp.getUuid());
            return;
        }

        if (nms.blockActionRestricted(nms.level(), targetPos, nms.gameMode.getGameModeForPlayer())) return;

        equipBestMiningTool(bot, targetPos);

        Direction side = Direction.DOWN;
        if (bot.getGameMode() == GameMode.CREATIVE) {
            nms.gameMode.handleBlockBreakAction(targetPos,
                    ServerboundPlayerActionPacket.Action.START_DESTROY_BLOCK,
                    side, nms.level().getMaxY(), -1);
            nms.swing(InteractionHand.MAIN_HAND);
            if (state.once || state.stopAfterForcedTarget) {
                beginPickupWait(fp, state, targetPos);
            } else {
                state.freeze = 5;
                state.currentPos = null;
            }
            return;
        }

        if (state.currentPos == null || !state.currentPos.equals(targetPos)) {
            if (state.currentPos != null) {
                nms.gameMode.handleBlockBreakAction(state.currentPos,
                        ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                        side, nms.level().getMaxY(), -1);
            }

            nms.gameMode.handleBlockBreakAction(targetPos,
                    ServerboundPlayerActionPacket.Action.START_DESTROY_BLOCK,
                    side, nms.level().getMaxY(), -1);

            if (state.progress == 0) blockState.attack(nms.level(), targetPos, nms);

            float speed = blockState.getDestroyProgress(nms, nms.level(), targetPos);
            if (speed >= 1.0F) {
                nms.swing(InteractionHand.MAIN_HAND);
                if (state.once || state.stopAfterForcedTarget) {
                    beginPickupWait(fp, state, targetPos);
                } else {
                    state.currentPos = null;
                    state.freeze = 5;
                }
                return;
            }
            state.currentPos = targetPos;
            state.progress = 0;
        } else {
            float speed = blockState.getDestroyProgress(nms, nms.level(), targetPos);
            state.progress += speed;
            if (state.progress >= 1.0F) {
                nms.gameMode.handleBlockBreakAction(targetPos,
                        ServerboundPlayerActionPacket.Action.STOP_DESTROY_BLOCK,
                        side, nms.level().getMaxY(), -1);
                nms.swing(InteractionHand.MAIN_HAND);
                if (state.once || state.stopAfterForcedTarget) {
                    beginPickupWait(fp, state, targetPos);
                } else {
                    state.currentPos = null;
                    state.progress = 0;
                    state.freeze = 5;
                }
                return;
            }
            nms.level().destroyBlockProgress(-1, targetPos, (int) (state.progress * 10));
        }

        nms.swing(InteractionHand.MAIN_HAND);
        nms.resetLastActionTime();
    }

    private void abortMining(ServerPlayer nms, MiningState state) {
        if (state.currentPos == null) return;
        nms.level().destroyBlockProgress(-1, state.currentPos, -1);
        nms.gameMode.handleBlockBreakAction(state.currentPos,
                ServerboundPlayerActionPacket.Action.ABORT_DESTROY_BLOCK,
                Direction.DOWN, nms.level().getMaxY(), -1);
        state.currentPos = null;
        state.progress = 0;
    }

    private BlockPos getTargetBlock(Player bot) {
        try {
            Location eye = bot.getEyeLocation();
            BlockIterator iter = new BlockIterator(bot.getWorld(), eye.toVector(), eye.getDirection(), 0, 5);
            while (iter.hasNext()) {
                Block b = iter.next();
                if (!b.getType().isAir() && b.getType().isSolid()) {
                    return new BlockPos(b.getX(), b.getY(), b.getZ());
                }
            }
        } catch (IllegalStateException ignored) {}
        return null;
    }

    private AreaBlock findNextAreaTarget(Player bot, AreaSelection selection, AreaMineJob job) {
        World world = bot.getWorld();
        AreaBlock best = null;
        double bestDist = Double.MAX_VALUE;

        for (int y = selection.maxY(); y >= selection.minY(); y--) {
            for (int x = selection.minX(); x <= selection.maxX(); x++) {
                for (int z = selection.minZ(); z <= selection.maxZ(); z++) {
                    AreaBlock candidate = new AreaBlock(x, y, z);
                    if (job.completed.contains(candidate) || job.skipped.contains(candidate)) continue;
                    Block block = world.getBlockAt(x, y, z);
                    if (!isMineable(block)) continue;
                    double dist = block.getLocation().add(0.5, 0.5, 0.5).distanceSquared(bot.getLocation());
                    if (dist < bestDist) {
                        bestDist = dist;
                        best = candidate;
                    }
                }
            }
        }
        return best;
    }

    private boolean isMineable(Block block) {
        if (block == null) return false;
        Material type = block.getType();
        if (type.isAir() || !type.isSolid()) return false;
        if (block.getState() instanceof InventoryHolder) return false;
        return switch (type) {
            case BEDROCK, BARRIER, END_PORTAL, END_PORTAL_FRAME, NETHER_PORTAL,
                 COMMAND_BLOCK, CHAIN_COMMAND_BLOCK, REPEATING_COMMAND_BLOCK,
                 STRUCTURE_BLOCK, JIGSAW, LIGHT, REINFORCED_DEEPSLATE -> false;
            default -> true;
        };
    }

    private Location findStandLocation(World world, AreaBlock target) {
        int x = target.x;
        int y = target.y;
        int z = target.z;
        int[][] candidates = new int[][]{
                {x + 1, y, z}, {x - 1, y, z}, {x, y, z + 1}, {x, y, z - 1},
                {x + 1, y - 1, z}, {x - 1, y - 1, z}, {x, y - 1, z + 1}, {x, y - 1, z - 1},
                {x + 1, y + 1, z}, {x - 1, y + 1, z}, {x, y + 1, z + 1}, {x, y + 1, z - 1}
        };
        for (int[] c : candidates) {
            if (BotPathfinder.walkable(world, c[0], c[1], c[2])) {
                Location loc = new Location(world, c[0] + 0.5, c[1], c[2] + 0.5);
                if (loc.distanceSquared(target.center(world)) <= 25.0) return loc;
            }
        }
        return null;
    }

    private Location faceToward(Location from, Location target) {
        Location loc = from.clone();
        double dx = target.getX() - loc.getX();
        double dy = target.getY() - (loc.getY() + 1.62);
        double dz = target.getZ() - loc.getZ();
        double xz = Math.sqrt(dx * dx + dz * dz);
        float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
        float pitch = (float) -Math.toDegrees(Math.atan2(dy, xz));
        loc.setYaw(yaw);
        loc.setPitch(pitch);
        return loc;
    }

    private boolean isStorageOffloadNeeded(PlayerInventory inv) {
        return inv.firstEmpty() == -1;
    }

    private boolean hasDepositableLoot(PlayerInventory inv) {
        int heldSlot = inv.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            if (isDepositCandidate(slot, heldSlot, inv.getItem(slot))) return true;
        }
        return false;
    }

    private int moveBotInventoryToStorage(PlayerInventory source, Inventory target) {
        int moved = 0;
        int heldSlot = source.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = source.getItem(slot);
            if (!isDepositCandidate(slot, heldSlot, item)) continue;
            ItemStack original = item.clone();
            Map<Integer, ItemStack> leftovers = target.addItem(original);
            if (leftovers.isEmpty()) {
                moved += original.getAmount();
                source.setItem(slot, null);
            } else {
                ItemStack left = leftovers.values().iterator().next();
                int movedNow = original.getAmount() - left.getAmount();
                if (movedNow > 0) {
                    moved += movedNow;
                    source.setItem(slot, left);
                }
            }
        }
        return moved;
    }

    private boolean containerCanAcceptAny(PlayerInventory source, Inventory target) {
        int heldSlot = source.getHeldItemSlot();
        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = source.getItem(slot);
            if (!isDepositCandidate(slot, heldSlot, item)) continue;
            if (inventoryCanFit(target, item)) return true;
        }
        return false;
    }

    private boolean inventoryCanFit(Inventory inv, ItemStack item) {
        for (ItemStack content : inv.getContents()) {
            if (content == null || content.getType() == Material.AIR) return true;
            if (content.isSimilar(item) && content.getAmount() < content.getMaxStackSize()) return true;
        }
        return false;
    }

    private boolean isDepositCandidate(int slot, int heldSlot, ItemStack item) {
        if (item == null || item.getType() == Material.AIR) return false;
        if (slot == heldSlot && isLikelyMiningTool(item)) return false;
        return !isLikelyMiningTool(item);
    }

    private boolean isLikelyMiningTool(ItemStack item) {
        Material type = item.getType();
        return type.name().endsWith("_PICKAXE")
                || type.name().endsWith("_AXE")
                || type.name().endsWith("_SHOVEL")
                || type.name().endsWith("_HOE")
                || type.name().endsWith("_SWORD")
                || type == Material.SHEARS;
    }

    private void beginPickupWait(FakePlayer fp, MiningState state, BlockPos targetPos) {
        state.currentPos = null;
        state.progress = 0;
        state.freeze = 0;
        state.forcedTarget = targetPos;
        state.completeForcedTargetOnStop = state.stopAfterForcedTarget;
        state.waitingForDrops = true;

        // No storage configured → skip the pickup delay entirely for maximum mining speed.
        // The bot will naturally pick up drops as it walks past them, or they stay on the ground.
        boolean hasStorage = !storageStore.getStorages(fp.getName()).isEmpty();
        if (!hasStorage) {
            state.pickupWaitTicks = 0;
            state.pickupWaitExtraTicks = 0;
        } else {
            state.pickupWaitTicks = fp.isPickUpItemsEnabled() ? AREA_PICKUP_WAIT_TICKS : 1;
            state.pickupWaitExtraTicks = fp.isPickUpItemsEnabled() ? AREA_PICKUP_EXTRA_TICKS : 0;
        }
    }

    private void interruptMining(UUID botUuid) {
        Integer taskId = miningTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);

        manager.unlockMining(botUuid);
        manager.unlockNavigation(botUuid);
        activeMineLocations.remove(botUuid);
        activeMineOnceFlags.remove(botUuid);

        MiningState state = miningStates.remove(botUuid);
        if (state == null) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) return;

        ServerPlayer nms = ((CraftPlayer) bot).getHandle();
        abortMining(nms, state);
    }

    private boolean isAtLockLocation(Player bot, Location lockLoc) {
        if (bot == null || lockLoc == null) return false;
        if (bot.getWorld() != lockLoc.getWorld()) return false;
        double xz = xzDist(bot.getLocation(), lockLoc);
        double dy = Math.abs(bot.getLocation().getY() - lockLoc.getY());
        return xz <= ARRIVAL_DIST && dy < 1.25;
    }

    private void useStorageBlock(Player bot, Block block) {
        try {
            ServerPlayer nms = ((CraftPlayer) bot).getHandle();
            BlockPos pos = new BlockPos(block.getX(), block.getY(), block.getZ());
            Vec3 hitVec = new Vec3(block.getX() + 0.5, block.getY() + 0.5, block.getZ() + 0.5);
            BlockHitResult hit = new BlockHitResult(hitVec, Direction.UP, pos, false);
            nms.resetLastActionTime();
            var result = nms.gameMode.useItemOn(
                    nms, nms.level(), nms.getItemInHand(InteractionHand.MAIN_HAND), InteractionHand.MAIN_HAND, hit);
            if (result.consumesAction()) {
                nms.swing(InteractionHand.MAIN_HAND);
            }
        } catch (Throwable ignored) {}
    }

    private boolean hasNearbyDrops(Player bot, BlockPos targetPos) {
        if (targetPos == null) return false;
        Location center = new Location(bot.getWorld(), targetPos.getX() + 0.5, targetPos.getY() + 0.5, targetPos.getZ() + 0.5);
        for (org.bukkit.entity.Entity entity : bot.getNearbyEntities(2.0, 1.5, 2.0)) {
            if (!(entity instanceof Item item) || item.isDead()) continue;
            if (item.getLocation().distanceSquared(center) <= 6.25) return true;
        }
        return false;
    }

    private void equipBestMiningTool(Player bot, BlockPos targetPos) {
        if (targetPos == null) return;
        Block block = bot.getWorld().getBlockAt(targetPos.getX(), targetPos.getY(), targetPos.getZ());
        ToolClass preferred = determineToolClass(block.getType());
        PlayerInventory inv = bot.getInventory();
        int heldSlot = inv.getHeldItemSlot();
        int bestSlot = -1;
        int bestScore = Integer.MIN_VALUE;

        for (int slot = 0; slot < 36; slot++) {
            ItemStack item = inv.getItem(slot);
            int score = toolScore(item, preferred);
            if (score > bestScore) {
                bestScore = score;
                bestSlot = slot;
            }
        }

        if (bestSlot < 0 || bestScore <= 0 || bestSlot == heldSlot) return;

        if (bestSlot <= 8) {
            inv.setHeldItemSlot(bestSlot);
            if (plugin.getInventoryCommand() != null) {
                plugin.getInventoryCommand().refreshOpenGui(bot.getUniqueId());
            }
            return;
        }

        ItemStack held = inv.getItem(heldSlot);
        inv.setItem(heldSlot, inv.getItem(bestSlot));
        inv.setItem(bestSlot, held);
        if (plugin.getInventoryCommand() != null) {
            plugin.getInventoryCommand().refreshOpenGui(bot.getUniqueId());
        }
    }

    private int toolScore(ItemStack item, ToolClass preferred) {
        if (item == null || item.getType() == Material.AIR) return Integer.MIN_VALUE;
        Material type = item.getType();
        ToolClass actual = classifyTool(type);
        if (actual == ToolClass.NONE) return Integer.MIN_VALUE;

        int score = toolTierScore(type);
        if (actual == preferred) score += 10_000;
        else if (preferred == ToolClass.SHEARS && type == Material.SHEARS) score += 10_000;
        else if (preferred == ToolClass.NONE) score += 100;
        else score += 1_000;

        if (type == Material.SHEARS && preferred != ToolClass.SHEARS) score -= 500;
        return score;
    }

    private ToolClass determineToolClass(Material blockType) {
        if (blockType == Material.COBWEB) return ToolClass.SWORD;
        if (blockType.name().contains("LEAVES")
                || blockType == Material.VINE
                || blockType == Material.GLOW_LICHEN
                || blockType.name().endsWith("_WOOL")) {
            return ToolClass.SHEARS;
        }
        if (Tag.MINEABLE_PICKAXE.isTagged(blockType)) return ToolClass.PICKAXE;
        if (Tag.MINEABLE_AXE.isTagged(blockType)) return ToolClass.AXE;
        if (Tag.MINEABLE_SHOVEL.isTagged(blockType)) return ToolClass.SHOVEL;
        if (Tag.MINEABLE_HOE.isTagged(blockType)) return ToolClass.HOE;
        return ToolClass.NONE;
    }

    private ToolClass classifyTool(Material toolType) {
        String name = toolType.name();
        if (toolType == Material.SHEARS) return ToolClass.SHEARS;
        if (name.endsWith("_PICKAXE")) return ToolClass.PICKAXE;
        if (name.endsWith("_AXE")) return ToolClass.AXE;
        if (name.endsWith("_SHOVEL")) return ToolClass.SHOVEL;
        if (name.endsWith("_HOE")) return ToolClass.HOE;
        if (name.endsWith("_SWORD")) return ToolClass.SWORD;
        return ToolClass.NONE;
    }

    private int toolTierScore(Material toolType) {
        String name = toolType.name();
        if (toolType == Material.SHEARS) return 650;
        if (name.startsWith("NETHERITE_")) return 900;
        if (name.startsWith("DIAMOND_")) return 800;
        if (name.startsWith("IRON_")) return 700;
        if (name.startsWith("GOLDEN_")) return 600;
        if (name.startsWith("STONE_")) return 500;
        if (name.startsWith("WOODEN_")) return 400;
        return 100;
    }

    private void stopAreaJob(UUID botUuid, boolean notifyStop) {
        Integer taskId = areaTasks.remove(botUuid);
        if (taskId != null) Bukkit.getScheduler().cancelTask(taskId);
        AreaMineJob job = areaJobs.remove(botUuid);
        if (notifyStop && job != null) {
            FakePlayer fp = manager.getByUuid(botUuid);
            notifyStarter(job, "mine-area-stopped", "name", fp != null ? fp.getDisplayName() : botUuid.toString());
        }
    }

    private void notifyStarter(AreaMineJob job, String key, String... args) {
        if (job.starterUuid != null) {
            Player p = Bukkit.getPlayer(job.starterUuid);
            if (p != null && p.isOnline()) {
                p.sendMessage(Lang.get(key, args));
                return;
            }
        }
        if (job.consoleStarted) {
            plugin.getLogger().info(Lang.raw(key, args));
        }
    }

    private static double xzDist(Location a, Location b) {
        return xzDistRaw(a.getX(), a.getZ(), b.getX(), b.getZ());
    }

    private static double xzDistRaw(double ax, double az, double bx, double bz) {
        double dx = ax - bx;
        double dz = az - bz;
        return Math.sqrt(dx * dx + dz * dz);
    }

    private static final class MiningState {
        BlockPos currentPos;
        float progress;
        int freeze;
        boolean once;
        BlockPos forcedTarget;
        boolean stopAfterForcedTarget;
        boolean completeForcedTargetOnStop;
        boolean waitingForDrops;
        int pickupWaitTicks;
        int pickupWaitExtraTicks;
    }

    private enum ToolClass { PICKAXE, AXE, SHOVEL, HOE, SHEARS, SWORD, NONE }

    private static final class AreaSelection {
        Location pos1;
        Location pos2;

        boolean isComplete() { return pos1 != null && pos2 != null; }
        boolean sameWorld() {
            return isComplete() && pos1.getWorld() != null && pos1.getWorld().equals(pos2.getWorld());
        }
        int minX() { return Math.min(pos1.getBlockX(), pos2.getBlockX()); }
        int maxX() { return Math.max(pos1.getBlockX(), pos2.getBlockX()); }
        int minY() { return Math.min(pos1.getBlockY(), pos2.getBlockY()); }
        int maxY() { return Math.max(pos1.getBlockY(), pos2.getBlockY()); }
        int minZ() { return Math.min(pos1.getBlockZ(), pos2.getBlockZ()); }
        int maxZ() { return Math.max(pos1.getBlockZ(), pos2.getBlockZ()); }
        int blockCount() { return (maxX() - minX() + 1) * (maxY() - minY() + 1) * (maxZ() - minZ() + 1); }
        AreaSelection copy() {
            AreaSelection copy = new AreaSelection();
            copy.pos1 = pos1.clone();
            copy.pos2 = pos2.clone();
            return copy;
        }
    }

    private static final class AreaMineJob {
        final AreaSelection selection;
        final UUID starterUuid;
        final boolean consoleStarted;
        final Set<AreaBlock> completed = new HashSet<>();
        final Set<AreaBlock> skipped = new HashSet<>();
        AreaBlock currentTarget;
        int preferredStorageIndex = 0;
        int blocksMined = 0;
        /** {@code true} while the bot is depositing its final loot after the area is exhausted. */
        boolean finishingDeposit = false;

        AreaMineJob(AreaSelection selection, CommandSender sender) {
            this.selection = selection;
            this.starterUuid = sender instanceof Player p ? p.getUniqueId() : null;
            this.consoleStarted = !(sender instanceof Player);
        }
    }

    private record AreaBlock(int x, int y, int z) {
        BlockPos toBlockPos() { return new BlockPos(x, y, z); }
        Location center(World world) { return new Location(world, x + 0.5, y + 0.5, z + 0.5); }
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.fakeplayer.PathfindingService;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitTask;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ThreadLocalRandom;

public final class MoveCommand implements FppCommand {

    private final FakePlayerPlugin plugin;
    private final FakePlayerManager manager;
    private final PathfindingService pathfinding;

    private final Map<UUID, List<Integer>> randomWpOrder = new ConcurrentHashMap<>();

    private final Map<UUID, String> activeRouteNames = new ConcurrentHashMap<>();

    private final Map<UUID, Boolean> activeRandomFlags = new ConcurrentHashMap<>();

    // ── Roaming state ──
    /** Center location for roaming bots (world + x/y/z). */
    private final Map<UUID, Location> roamCenters = new ConcurrentHashMap<>();
    /** Roam radius per bot. */
    private final Map<UUID, Double> roamRadii = new ConcurrentHashMap<>();
    /** Pause task handles so we can cancel mid-pause. */
    private final Map<UUID, BukkitTask> roamPauseTasks = new ConcurrentHashMap<>();
    /** Head-look task handles during roam pauses. */
    private final Map<UUID, BukkitTask> roamLookTasks = new ConcurrentHashMap<>();

    private WaypointStore waypointStore;

    public MoveCommand(
            FakePlayerPlugin plugin, FakePlayerManager manager, PathfindingService pathfinding) {
        this.plugin = plugin;
        this.manager = manager;
        this.pathfinding = pathfinding;
    }

    public void setWaypointStore(WaypointStore store) {
        this.waypointStore = store;
    }

    @Override
    public String getName() {
        return "move";
    }

    @Override
    public String getUsage() {
        return "<bot|all> --to <player>  |  <bot|all> --wp <route> [--random]  |  <bot|all> --roam [x,y,z] [radius]  |  <bot|all> --stop";
    }

    @Override
    public String getDescription() {
        return "Navigate a bot (or all bots) to a player, patrol a waypoint route, or roam"
                   + " randomly within an area.";
    }

    @Override
    public String getPermission() {
        return Perm.MOVE;
    }

    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.MOVE);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        if (args[0].equalsIgnoreCase("all")) {
            return executeAll(sender, args);
        }

        FakePlayer fp = manager.getByName(args[0]);
        if (fp == null) {
            sender.sendMessage(Lang.get("move-bot-not-found", "name", args[0]));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("move-bot-not-online", "name", args[0]));
            return true;
        }

        if (args.length >= 2 && args[1].startsWith("--")) {
            String flag = args[1].toLowerCase();

            if (flag.equals("--stop")) {
                boolean wasRoaming = isRoaming(bot.getUniqueId());
                if (!wasRoaming && !pathfinding.isNavigating(bot.getUniqueId(), PathfindingService.Owner.MOVE)) {
                    sender.sendMessage(
                            Lang.get("move-not-navigating", "name", fp.getDisplayName()));
                } else {
                    cancelNavigation(bot.getUniqueId());
                    sender.sendMessage(Lang.get("move-stopped", "name", fp.getDisplayName()));
                }
                return true;
            }

            if (flag.equals("--roam")) {
                return handleRoam(sender, fp, bot, args);
            }

            if (flag.equals("--wp")) {
                if (waypointStore == null || args.length < 3) {
                    sender.sendMessage(Lang.get("move-wp-usage"));
                    return true;
                }
                String wpName = args[2];
                boolean randomOrder = args.length >= 4 && args[3].equalsIgnoreCase("--random");

                List<Location> route = waypointStore.getRoute(wpName);
                if (route == null || route.isEmpty()) {
                    sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                    return true;
                }

                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-different-world",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());

                activeRouteNames.put(bot.getUniqueId(), wpName);
                activeRandomFlags.put(bot.getUniqueId(), randomOrder);
                if (randomOrder) {
                    startRandomPatrol(bot, route);
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-started-random",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName,
                                    "count",
                                    String.valueOf(route.size())));
                } else {
                    startPatrol(bot, route);
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-started",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName,
                                    "count",
                                    String.valueOf(route.size())));
                }
                return true;
            }

            if (flag.equals("--to")) {
                if (args.length < 3) {
                    sender.sendMessage(Lang.get("move-usage"));
                    return true;
                }
                Player target = Bukkit.getPlayer(args[2]);
                if (target == null) {
                    sender.sendMessage(Lang.get("player-not-found", "player", args[2]));
                    return true;
                }
                if (!bot.getWorld().equals(target.getWorld())) {
                    sender.sendMessage(
                            Lang.get(
                                    "move-different-world",
                                    "name",
                                    fp.getDisplayName(),
                                    "player",
                                    target.getName()));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());
                startNavigation(bot, target);
                sender.sendMessage(
                        Lang.get(
                                "move-navigating",
                                "name",
                                fp.getDisplayName(),
                                "player",
                                target.getName()));
                return true;
            }

            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        if (args.length >= 2) {
            Player target = Bukkit.getPlayer(args[1]);
            if (target == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
                return true;
            }

            if (!bot.getWorld().equals(target.getWorld())) {
                sender.sendMessage(
                        Lang.get(
                                "move-different-world",
                                "name",
                                fp.getDisplayName(),
                                "player",
                                target.getName()));
                return true;
            }

            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);

            sender.sendMessage(
                    Lang.get(
                            "move-navigating",
                            "name",
                            fp.getDisplayName(),
                            "player",
                            target.getName()));
            return true;
        }

        sender.sendMessage(Lang.get("move-usage"));
        return true;
    }

    // ── Roam command handler ──

    private boolean handleRoam(CommandSender sender, FakePlayer fp, Player bot, String[] args) {
        Location center = bot.getLocation().clone();
        double radius = 20.0;

        // Parse optional coords: --roam [x,y,z] [radius]
        //   /fpp move <bot> --roam                      → bot loc, r=20
        //   /fpp move <bot> --roam 15                   → bot loc, r=15
        //   /fpp move <bot> --roam 100,64,-200          → coords, r=20
        //   /fpp move <bot> --roam 100,64,-200 30       → coords, r=30
        int nextArg = 2;
        if (args.length > nextArg) {
            String possibleCoords = args[nextArg];
            if (possibleCoords.contains(",")) {
                // Parse x,y,z
                String[] parts = possibleCoords.split(",");
                if (parts.length != 3) {
                    sender.sendMessage(Lang.get("move-roam-invalid-coords"));
                    return true;
                }
                try {
                    double cx = parseCoord(parts[0], sender instanceof Player p ? p.getLocation().getX() : 0);
                    double cy = parseCoord(parts[1], sender instanceof Player p ? p.getLocation().getY() : 64);
                    double cz = parseCoord(parts[2], sender instanceof Player p ? p.getLocation().getZ() : 0);
                    center = new Location(bot.getWorld(), cx, cy, cz);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("move-roam-invalid-coords"));
                    return true;
                }
                nextArg++;
            }
            // Parse radius (next arg or the first arg if no coords)
            if (args.length > nextArg) {
                try {
                    radius = Double.parseDouble(args[nextArg]);
                    if (radius < 3 || radius > 500) {
                        sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                        return true;
                    }
                } catch (NumberFormatException e) {
                    // If the first non-flag arg is just a number (no coords), treat as radius
                    if (nextArg == 2) {
                        try {
                            radius = Double.parseDouble(args[2]);
                            if (radius < 3 || radius > 500) {
                                sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                                return true;
                            }
                        } catch (NumberFormatException ex) {
                            sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                            return true;
                        }
                    } else {
                        sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                        return true;
                    }
                }
            } else if (nextArg == 2) {
                // First extra arg might be just a radius number
                try {
                    radius = Double.parseDouble(possibleCoords);
                    if (radius < 3 || radius > 500) {
                        sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                        return true;
                    }
                    center = bot.getLocation().clone(); // keep bot loc
                } catch (NumberFormatException e) {
                    // Not a number and not coords — invalid
                    sender.sendMessage(Lang.get("move-roam-usage"));
                    return true;
                }
            }
        }

        cancelNavigation(bot.getUniqueId());
        startRoaming(fp, center, radius);
        sender.sendMessage(
                Lang.get(
                        "move-roam-started",
                        "name", fp.getDisplayName(),
                        "x", String.valueOf((int) center.getX()),
                        "y", String.valueOf((int) center.getY()),
                        "z", String.valueOf((int) center.getZ()),
                        "radius", String.valueOf((int) radius)));
        return true;
    }

    private double parseCoord(String raw, double relative) {
        raw = raw.trim();
        if (raw.startsWith("~")) {
            String offset = raw.substring(1);
            if (offset.isEmpty()) return relative;
            return relative + Double.parseDouble(offset);
        }
        return Double.parseDouble(raw);
    }

    private boolean executeAll(CommandSender sender, String[] args) {
        if (args.length < 2) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        String flag = args[1].toLowerCase();

        if (flag.equals("--stop")) {
            int stopped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null) continue;
                UUID uid = bot.getUniqueId();
                if (isRoaming(uid) || pathfinding.isNavigating(uid, PathfindingService.Owner.MOVE)) {
                    cancelNavigation(uid);
                    stopped++;
                }
            }
            sender.sendMessage(Lang.get("move-all-stopped", "count", String.valueOf(stopped)));
            return true;
        }

        if (flag.equals("--roam")) {
            // /fpp move all --roam [x,y,z] [radius]
            Location center = null;
            double radius = 20.0;
            int nextArg = 2;
            if (args.length > nextArg) {
                String possibleCoords = args[nextArg];
                if (possibleCoords.contains(",")) {
                    String[] parts = possibleCoords.split(",");
                    if (parts.length == 3) {
                        try {
                            double cx = sender instanceof Player p ? parseCoord(parts[0], p.getLocation().getX()) : Double.parseDouble(parts[0]);
                            double cy = sender instanceof Player p ? parseCoord(parts[1], p.getLocation().getY()) : Double.parseDouble(parts[1]);
                            double cz = sender instanceof Player p ? parseCoord(parts[2], p.getLocation().getZ()) : Double.parseDouble(parts[2]);
                            if (sender instanceof Player p) {
                                center = new Location(p.getWorld(), cx, cy, cz);
                            }
                        } catch (NumberFormatException ignored) {}
                    }
                    nextArg++;
                }
                if (args.length > nextArg) {
                    try { radius = Double.parseDouble(args[nextArg]); } catch (NumberFormatException ignored) {}
                } else if (nextArg == 2) {
                    try { radius = Double.parseDouble(possibleCoords); } catch (NumberFormatException ignored) {}
                }
            }
            radius = Math.max(3, Math.min(500, radius));

            int started = 0, skipped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) { skipped++; continue; }
                cancelNavigation(bot.getUniqueId());
                Location c = center != null ? center.clone() : bot.getLocation().clone();
                if (center != null) c.setWorld(bot.getWorld());
                startRoaming(fp, c, radius);
                started++;
            }
            sender.sendMessage(
                    Lang.get("move-all-roam-started",
                            "count", String.valueOf(started),
                            "radius", String.valueOf((int) radius),
                            "skipped", String.valueOf(skipped)));
            return true;
        }

        if (flag.equals("--wp")) {
            if (waypointStore == null || args.length < 3) {
                sender.sendMessage(Lang.get("move-wp-usage"));
                return true;
            }
            String wpName = args[2];
            boolean randomOrder = args.length >= 4 && args[3].equalsIgnoreCase("--random");

            List<Location> route = waypointStore.getRoute(wpName);
            if (route == null || route.isEmpty()) {
                sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                return true;
            }

            int started = 0, skipped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) {
                    skipped++;
                    continue;
                }
                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    skipped++;
                    continue;
                }
                cancelNavigation(bot.getUniqueId());
                activeRouteNames.put(bot.getUniqueId(), wpName);
                activeRandomFlags.put(bot.getUniqueId(), randomOrder);
                if (randomOrder) startRandomPatrol(bot, route);
                else startPatrol(bot, route);
                started++;
            }

            if (randomOrder) {
                sender.sendMessage(
                        Lang.get(
                                "move-all-wp-started-random",
                                "waypoint",
                                wpName,
                                "count",
                                String.valueOf(started),
                                "skipped",
                                String.valueOf(skipped)));
            } else {
                sender.sendMessage(
                        Lang.get(
                                "move-all-wp-started",
                                "waypoint",
                                wpName,
                                "count",
                                String.valueOf(started),
                                "skipped",
                                String.valueOf(skipped)));
            }
            return true;
        }

        Player target = Bukkit.getPlayer(args[1]);
        if (target == null) {
            sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
            return true;
        }

        int started = 0, skipped = 0;
        for (FakePlayer fp : manager.getActivePlayers()) {
            Player bot = fp.getPlayer();
            if (bot == null || !bot.isOnline()) {
                skipped++;
                continue;
            }
            if (!bot.getWorld().equals(target.getWorld())) {
                skipped++;
                continue;
            }
            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);
            started++;
        }
        sender.sendMessage(
                Lang.get(
                        "move-all-navigating",
                        "player",
                        target.getName(),
                        "count",
                        String.valueOf(started),
                        "skipped",
                        String.valueOf(skipped)));
        return true;
    }

    // ═══════════════════════════════════════════════════════════════
    //  Navigation — follow player
    // ═══════════════════════════════════════════════════════════════

    private void startNavigation(@NotNull Player bot, @NotNull Player target) {
        final UUID botUuid = bot.getUniqueId();
        final UUID targetUuid = target.getUniqueId();
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> {
                            Player liveTarget = Bukkit.getPlayer(targetUuid);
                            if (liveTarget == null || !liveTarget.isOnline()) return null;
                            return liveTarget.getLocation();
                        },
                        Config.pathfindingArrivalDistance(),
                        Config.pathfindingFollowRecalcDistance(),
                        Integer.MAX_VALUE,
                        null,
                        () -> clearMoveState(botUuid),
                        null));
    }

    // ═══════════════════════════════════════════════════════════════
    //  Patrol — waypoint routes
    // ═══════════════════════════════════════════════════════════════

    private void startPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        navigatePatrolStep(bot.getUniqueId(), new ArrayList<>(waypoints), 0);
    }

    private void startRandomPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        UUID botUuid = bot.getUniqueId();
        List<Integer> shuffled = new ArrayList<>();
        for (int i = 0; i < waypoints.size(); i++) shuffled.add(i);
        Collections.shuffle(shuffled, new Random());
        randomWpOrder.put(botUuid, shuffled);
        navigateRandomPatrolStep(botUuid, new ArrayList<>(waypoints), 0);
    }

    private void navigatePatrolStep(
            @NotNull UUID botUuid, @NotNull List<Location> waypoints, int idx) {
        if (waypoints.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            clearMoveState(botUuid);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            clearMoveState(botUuid);
            return;
        }

        int nextIdx = Math.floorMod(idx, waypoints.size());
        Location dest = waypoints.get(nextIdx);
        if (dest.getWorld() == null || !dest.getWorld().equals(bot.getWorld())) {
            clearMoveState(botUuid);
            return;
        }

        int arrivalIdx = (nextIdx + 1) % waypoints.size();
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> navigatePatrolStep(botUuid, waypoints, arrivalIdx),
                        () -> clearMoveState(botUuid),
                        () -> navigatePatrolStep(botUuid, waypoints, arrivalIdx)));
    }

    private void navigateRandomPatrolStep(
            @NotNull UUID botUuid, @NotNull List<Location> waypoints, int cycleIdx) {
        if (waypoints.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }
        List<Integer> order = randomWpOrder.get(botUuid);
        if (order == null || order.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            clearMoveState(botUuid);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            clearMoveState(botUuid);
            return;
        }

        int normalizedCycle = cycleIdx;
        if (normalizedCycle >= order.size()) {
            Collections.shuffle(order, new Random());
            normalizedCycle = 0;
        }

        int actualIdx = order.get(normalizedCycle);
        Location dest = waypoints.get(actualIdx);
        if (dest.getWorld() == null || !dest.getWorld().equals(bot.getWorld())) {
            clearMoveState(botUuid);
            return;
        }

        int nextCycle = normalizedCycle + 1;
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> navigateRandomPatrolStep(botUuid, waypoints, nextCycle),
                        () -> clearMoveState(botUuid),
                        () -> navigateRandomPatrolStep(botUuid, waypoints, nextCycle)));
    }

    // ═══════════════════════════════════════════════════════════════
    //  Roaming — random wandering within a radius
    // ═══════════════════════════════════════════════════════════════

    private void startRoaming(@NotNull FakePlayer fp, @NotNull Location center, double radius) {
        UUID uid = fp.getUuid();
        roamCenters.put(uid, center.clone());
        roamRadii.put(uid, radius);
        navigateRoamStep(uid);
    }

    private void navigateRoamStep(@NotNull UUID botUuid) {
        if (!roamCenters.containsKey(botUuid)) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) { clearRoamState(botUuid); return; }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) { clearRoamState(botUuid); return; }

        Location center = roamCenters.get(botUuid);
        Double radius = roamRadii.get(botUuid);
        if (center == null || radius == null) { clearRoamState(botUuid); return; }

        Location dest = findRandomWalkableLocation(bot.getWorld(), center, radius);
        if (dest == null) {
            // Couldn't find a valid location — retry after a pause
            BukkitTask pause = Bukkit.getScheduler().runTaskLater(plugin, () -> {
                roamPauseTasks.remove(botUuid);
                navigateRoamStep(botUuid);
            }, 40L); // 2 seconds
            roamPauseTasks.put(botUuid, pause);
            return;
        }

        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> onRoamArrival(botUuid),       // onArrive — pause then next
                        () -> clearRoamState(botUuid),      // onCancel
                        () -> onRoamArrival(botUuid)));     // onPathFailure — try next spot
    }

    private void onRoamArrival(@NotNull UUID botUuid) {
        if (!roamCenters.containsKey(botUuid)) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) { clearRoamState(botUuid); return; }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) { clearRoamState(botUuid); return; }

        // Stop forward motion
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        ThreadLocalRandom rng = ThreadLocalRandom.current();

        // Realistic pause: 1.5–6 seconds (30–120 ticks)
        int pauseTicks = rng.nextInt(30, 121);

        // Head-look task: look around naturally during the pause
        // Pick 1–3 random look directions
        int lookCount = rng.nextInt(1, 4);
        int lookInterval = Math.max(10, pauseTicks / (lookCount + 1));

        BukkitTask lookTask = Bukkit.getScheduler().runTaskTimer(plugin, new Runnable() {
            int ticks = 0;
            int looksDone = 0;
            float baseYaw = bot.getLocation().getYaw();
            @Override
            public void run() {
                ticks++;
                Player b = fp.getPlayer();
                if (b == null || !b.isOnline() || !roamCenters.containsKey(botUuid)) return;

                if (looksDone < lookCount && ticks % lookInterval == 0) {
                    // Random head turn: ±60° yaw, -15° to +25° pitch
                    float newYaw = baseYaw + rng.nextFloat(-60f, 61f);
                    float newPitch = rng.nextFloat(-15f, 26f);
                    b.setRotation(newYaw, newPitch);
                    NmsPlayerSpawner.setHeadYaw(b, newYaw);
                    looksDone++;
                }
            }
        }, 5L, 1L);
        roamLookTasks.put(botUuid, lookTask);

        // After pause, go to next random spot
        BukkitTask pause = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            cancelRoamPauseTasks(botUuid);
            navigateRoamStep(botUuid);
        }, pauseTicks);
        roamPauseTasks.put(botUuid, pause);
    }

    @Nullable
    private Location findRandomWalkableLocation(@NotNull World world, @NotNull Location center, double radius) {
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        int cx = center.getBlockX();
        int cz = center.getBlockZ();
        int r = (int) radius;

        for (int attempt = 0; attempt < 30; attempt++) {
            // Random point within circle (uniform distribution)
            double angle = rng.nextDouble(Math.PI * 2);
            double dist = Math.sqrt(rng.nextDouble()) * r;  // sqrt for uniform area distribution
            int tx = cx + (int) Math.round(Math.cos(angle) * dist);
            int tz = cz + (int) Math.round(Math.sin(angle) * dist);

            // Find a walkable Y level near the surface
            int ty = findWalkableY(world, tx, tz, center.getBlockY());
            if (ty >= world.getMinHeight() && BotPathfinder.walkable(world, tx, ty, tz)) {
                return new Location(world, tx + 0.5, ty, tz + 0.5);
            }
        }
        return null;
    }

    /**
     * Search for a walkable Y level at the given XZ, preferring heights close to the reference Y.
     * Scans ±16 blocks from refY, checking top-down for closer first.
     */
    private int findWalkableY(@NotNull World world, int x, int z, int refY) {
        int minY = Math.max(world.getMinHeight(), refY - 16);
        int maxY = Math.min(world.getMaxHeight() - 2, refY + 16);
        int bestY = world.getMinHeight() - 1;
        int bestDist = Integer.MAX_VALUE;
        for (int y = maxY; y >= minY; y--) {
            if (BotPathfinder.walkable(world, x, y, z)) {
                int d = Math.abs(y - refY);
                if (d < bestDist) {
                    bestDist = d;
                    bestY = y;
                    if (d == 0) break;
                }
            }
        }
        return bestY;
    }

    // ═══════════════════════════════════════════════════════════════
    //  State management
    // ═══════════════════════════════════════════════════════════════

    private void cancelRoamPauseTasks(@NotNull UUID botUuid) {
        BukkitTask look = roamLookTasks.remove(botUuid);
        if (look != null && !look.isCancelled()) look.cancel();
        BukkitTask pause = roamPauseTasks.remove(botUuid);
        if (pause != null && !pause.isCancelled()) pause.cancel();
    }

    private void clearRoamState(@NotNull UUID botUuid) {
        roamCenters.remove(botUuid);
        roamRadii.remove(botUuid);
        cancelRoamPauseTasks(botUuid);
    }

    private void clearMoveState(@NotNull UUID botUuid) {
        randomWpOrder.remove(botUuid);
        activeRouteNames.remove(botUuid);
        activeRandomFlags.remove(botUuid);
        clearRoamState(botUuid);
    }

    private void cancelNavigation(@NotNull UUID botUuid) {
        pathfinding.cancel(botUuid);
        clearMoveState(botUuid);
    }

    public void cancelAll() {
        pathfinding.cancelAll(PathfindingService.Owner.MOVE);
        new ArrayList<>(activeRouteNames.keySet()).forEach(this::clearMoveState);
        new ArrayList<>(randomWpOrder.keySet()).forEach(this::clearMoveState);
        new ArrayList<>(roamCenters.keySet()).forEach(this::clearMoveState);
    }

    public void cleanupBot(@NotNull UUID botUuid) {
        cancelNavigation(botUuid);
    }

    // ═══════════════════════════════════════════════════════════════
    //  Public API — roaming queries (for persistence / GUI)
    // ═══════════════════════════════════════════════════════════════

    public boolean isRoaming(@NotNull UUID botUuid) {
        return roamCenters.containsKey(botUuid);
    }

    @Nullable
    public Location getRoamCenter(@NotNull UUID botUuid) {
        return roamCenters.get(botUuid);
    }

    @Nullable
    public Double getRoamRadius(@NotNull UUID botUuid) {
        return roamRadii.get(botUuid);
    }

    /**
     * Resume roaming after a server restart (called by BotPersistence).
     */
    public void resumeRoaming(@NotNull FakePlayer fp, @NotNull Location center, double radius) {
        UUID uid = fp.getUuid();
        cancelNavigation(uid);
        startRoaming(fp, center, radius);
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        List<String> out = new ArrayList<>();
        if (args.length == 1) {
            String in = args[0].toLowerCase();

            if ("all".startsWith(in)) out.add("all");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(in)) out.add(fp.getName());
        } else if (args.length == 2) {
            String in = args[1].toLowerCase();

            for (String flag : List.of("--to", "--wp", "--roam", "--stop")) if (flag.startsWith(in)) out.add(flag);

            for (Player p : Bukkit.getOnlinePlayers()) {
                if (manager.getByName(p.getName()) == null
                        && p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
            }
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--to")) {
            String in = args[2].toLowerCase();
            for (Player p : Bukkit.getOnlinePlayers()) {
                if (manager.getByName(p.getName()) == null
                        && p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
            }
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--wp")) {

            if (waypointStore != null) {
                String in = args[2].toLowerCase();
                for (String name : waypointStore.getNames()) if (name.startsWith(in)) out.add(name);
            }
        } else if (args.length == 4 && args[1].equalsIgnoreCase("--wp")) {

            String in = args[3].toLowerCase();
            if ("--random".startsWith(in)) out.add("--random");
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--roam")) {
            // Suggest <radius> or <x,y,z>
            if (sender instanceof Player p) {
                Location loc = p.getLocation();
                out.add(loc.getBlockX() + "," + loc.getBlockY() + "," + loc.getBlockZ());
            }
            out.add("10");
            out.add("20");
            out.add("30");
            out.add("50");
        } else if (args.length == 4 && args[1].equalsIgnoreCase("--roam")) {
            // After coords, suggest radius
            out.add("10");
            out.add("20");
            out.add("30");
            out.add("50");
        }
        return out;
    }

    @Nullable
    public String getActiveRouteForBot(@NotNull UUID botUuid) {
        return activeRouteNames.get(botUuid);
    }

    public boolean isRandomPatrolForBot(@NotNull UUID botUuid) {
        Boolean v = activeRandomFlags.get(botUuid);
        return v != null && v;
    }

    public void resumePatrol(
            @NotNull Player bot,
            @NotNull List<Location> route,
            boolean random,
            @NotNull String routeName) {
        UUID uid = bot.getUniqueId();
        cancelNavigation(uid);
        activeRouteNames.put(uid, routeName);
        activeRandomFlags.put(uid, random);
        if (random) startRandomPatrol(bot, route);
        else startPatrol(bot, route);
    }
}

package me.bill.fakePlayerPlugin.command;

import me.bill.fakePlayerPlugin.FakePlayerPlugin;
import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.fakeplayer.BotPathfinder;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayer;
import me.bill.fakePlayerPlugin.fakeplayer.FakePlayerManager;
import me.bill.fakePlayerPlugin.fakeplayer.NmsPlayerSpawner;
import me.bill.fakePlayerPlugin.fakeplayer.PathfindingService;
import me.bill.fakePlayerPlugin.lang.Lang;
import me.bill.fakePlayerPlugin.permission.Perm;

import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;
import org.bukkit.scheduler.BukkitTask;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.annotations.Nullable;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ThreadLocalRandom;

public final class MoveCommand implements FppCommand {

    private final FakePlayerPlugin plugin;
    private final FakePlayerManager manager;
    private final PathfindingService pathfinding;

    private final Map<UUID, List<Integer>> randomWpOrder = new ConcurrentHashMap<>();

    private final Map<UUID, String> activeRouteNames = new ConcurrentHashMap<>();

    private final Map<UUID, Boolean> activeRandomFlags = new ConcurrentHashMap<>();

    // ── Roaming state ──
    /** Center location for roaming bots (world + x/y/z). */
    private final Map<UUID, Location> roamCenters = new ConcurrentHashMap<>();
    /** Roam radius per bot. */
    private final Map<UUID, Double> roamRadii = new ConcurrentHashMap<>();
    /** Pause task handles so we can cancel mid-pause. */
    private final Map<UUID, BukkitTask> roamPauseTasks = new ConcurrentHashMap<>();
    /** Head-look task handles during roam pauses. */
    private final Map<UUID, BukkitTask> roamLookTasks = new ConcurrentHashMap<>();

    private WaypointStore waypointStore;

    public MoveCommand(
            FakePlayerPlugin plugin, FakePlayerManager manager, PathfindingService pathfinding) {
        this.plugin = plugin;
        this.manager = manager;
        this.pathfinding = pathfinding;
    }

    public void setWaypointStore(WaypointStore store) {
        this.waypointStore = store;
    }

    @Override
    public String getName() {
        return "move";
    }

    @Override
    public String getUsage() {
        return "<bot|all> --to <player>  |  <bot|all> --wp <route> [--random]  |  <bot|all> --roam [x,y,z] [radius]  |  <bot|all> --stop";
    }

    @Override
    public String getDescription() {
        return "Navigate a bot (or all bots) to a player, patrol a waypoint route, or roam"
                   + " randomly within an area.";
    }

    @Override
    public String getPermission() {
        return Perm.MOVE;
    }

    @Override
    public boolean canUse(CommandSender sender) {
        return Perm.has(sender, Perm.MOVE);
    }

    @Override
    public boolean execute(CommandSender sender, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        if (args[0].equalsIgnoreCase("all")) {
            return executeAll(sender, args);
        }

        FakePlayer fp = manager.getByName(args[0]);
        if (fp == null) {
            sender.sendMessage(Lang.get("move-bot-not-found", "name", args[0]));
            return true;
        }

        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            sender.sendMessage(Lang.get("move-bot-not-online", "name", args[0]));
            return true;
        }

        if (args.length >= 2 && args[1].startsWith("--")) {
            String flag = args[1].toLowerCase();

            if (flag.equals("--stop")) {
                boolean wasRoaming = isRoaming(bot.getUniqueId());
                if (!wasRoaming && !pathfinding.isNavigating(bot.getUniqueId(), PathfindingService.Owner.MOVE)) {
                    sender.sendMessage(
                            Lang.get("move-not-navigating", "name", fp.getDisplayName()));
                } else {
                    cancelNavigation(bot.getUniqueId());
                    sender.sendMessage(Lang.get("move-stopped", "name", fp.getDisplayName()));
                }
                return true;
            }

            if (flag.equals("--roam")) {
                return handleRoam(sender, fp, bot, args);
            }

            if (flag.equals("--wp")) {
                if (waypointStore == null || args.length < 3) {
                    sender.sendMessage(Lang.get("move-wp-usage"));
                    return true;
                }
                String wpName = args[2];
                boolean randomOrder = args.length >= 4 && args[3].equalsIgnoreCase("--random");

                List<Location> route = waypointStore.getRoute(wpName);
                if (route == null || route.isEmpty()) {
                    sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                    return true;
                }

                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-different-world",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());

                activeRouteNames.put(bot.getUniqueId(), wpName);
                activeRandomFlags.put(bot.getUniqueId(), randomOrder);
                if (randomOrder) {
                    startRandomPatrol(bot, route);
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-started-random",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName,
                                    "count",
                                    String.valueOf(route.size())));
                } else {
                    startPatrol(bot, route);
                    sender.sendMessage(
                            Lang.get(
                                    "move-wp-started",
                                    "name",
                                    fp.getDisplayName(),
                                    "waypoint",
                                    wpName,
                                    "count",
                                    String.valueOf(route.size())));
                }
                return true;
            }

            if (flag.equals("--to")) {
                if (args.length < 3) {
                    sender.sendMessage(Lang.get("move-usage"));
                    return true;
                }
                Player target = Bukkit.getPlayer(args[2]);
                if (target == null) {
                    sender.sendMessage(Lang.get("player-not-found", "player", args[2]));
                    return true;
                }
                if (!bot.getWorld().equals(target.getWorld())) {
                    sender.sendMessage(
                            Lang.get(
                                    "move-different-world",
                                    "name",
                                    fp.getDisplayName(),
                                    "player",
                                    target.getName()));
                    return true;
                }
                cancelNavigation(bot.getUniqueId());
                startNavigation(bot, target);
                sender.sendMessage(
                        Lang.get(
                                "move-navigating",
                                "name",
                                fp.getDisplayName(),
                                "player",
                                target.getName()));
                return true;
            }

            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        if (args.length >= 2) {
            Player target = Bukkit.getPlayer(args[1]);
            if (target == null) {
                sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
                return true;
            }

            if (!bot.getWorld().equals(target.getWorld())) {
                sender.sendMessage(
                        Lang.get(
                                "move-different-world",
                                "name",
                                fp.getDisplayName(),
                                "player",
                                target.getName()));
                return true;
            }

            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);

            sender.sendMessage(
                    Lang.get(
                            "move-navigating",
                            "name",
                            fp.getDisplayName(),
                            "player",
                            target.getName()));
            return true;
        }

        sender.sendMessage(Lang.get("move-usage"));
        return true;
    }

    // ── Roam command handler ──

    private boolean handleRoam(CommandSender sender, FakePlayer fp, Player bot, String[] args) {
        Location center = bot.getLocation().clone();
        double radius = 20.0;

        // Parse optional coords: --roam [x,y,z] [radius]  or  --roam [radius]
        //   /fpp move <bot> --roam                      → bot loc, r=20
        //   /fpp move <bot> --roam 15                   → bot loc, r=15
        //   /fpp move <bot> --roam 100,64,-200          → coords, r=20
        //   /fpp move <bot> --roam 100,64,-200 30       → coords, r=30
        if (args.length > 2) {
            String token = args[2];
            if (token.contains(",")) {
                // Parse x,y,z
                String[] parts = token.split(",");
                if (parts.length != 3) {
                    sender.sendMessage(Lang.get("move-roam-invalid-coords"));
                    return true;
                }
                try {
                    double cx = parseCoord(parts[0], sender instanceof Player p ? p.getLocation().getX() : 0);
                    double cy = parseCoord(parts[1], sender instanceof Player p ? p.getLocation().getY() : 64);
                    double cz = parseCoord(parts[2], sender instanceof Player p ? p.getLocation().getZ() : 0);
                    center = new Location(bot.getWorld(), cx, cy, cz);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("move-roam-invalid-coords"));
                    return true;
                }
                // Optional radius after coords
                if (args.length > 3) {
                    try {
                        radius = Double.parseDouble(args[3]);
                    } catch (NumberFormatException e) {
                        sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                        return true;
                    }
                }
            } else {
                // Treat as radius
                try {
                    radius = Double.parseDouble(token);
                } catch (NumberFormatException e) {
                    sender.sendMessage(Lang.get("move-roam-usage"));
                    return true;
                }
            }
            if (radius < 3 || radius > 500) {
                sender.sendMessage(Lang.get("move-roam-invalid-radius"));
                return true;
            }
        }

        cancelNavigation(bot.getUniqueId());
        startRoaming(fp, center, radius);
        sender.sendMessage(
                Lang.get(
                        "move-roam-started",
                        "name", fp.getDisplayName(),
                        "x", String.valueOf((int) center.getX()),
                        "y", String.valueOf((int) center.getY()),
                        "z", String.valueOf((int) center.getZ()),
                        "radius", String.valueOf((int) radius)));
        return true;
    }

    private double parseCoord(String raw, double relative) {
        raw = raw.trim();
        if (raw.startsWith("~")) {
            String offset = raw.substring(1);
            if (offset.isEmpty()) return relative;
            return relative + Double.parseDouble(offset);
        }
        return Double.parseDouble(raw);
    }

    private boolean executeAll(CommandSender sender, String[] args) {
        if (args.length < 2) {
            sender.sendMessage(Lang.get("move-usage"));
            return true;
        }

        String flag = args[1].toLowerCase();

        if (flag.equals("--stop")) {
            int stopped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null) continue;
                UUID uid = bot.getUniqueId();
                if (isRoaming(uid) || pathfinding.isNavigating(uid, PathfindingService.Owner.MOVE)) {
                    cancelNavigation(uid);
                    stopped++;
                }
            }
            sender.sendMessage(Lang.get("move-all-stopped", "count", String.valueOf(stopped)));
            return true;
        }

        if (flag.equals("--roam")) {
            // /fpp move all --roam [x,y,z] [radius]
            Location center = null;
            double radius = 20.0;
            int nextArg = 2;
            if (args.length > nextArg) {
                String possibleCoords = args[nextArg];
                if (possibleCoords.contains(",")) {
                    String[] parts = possibleCoords.split(",");
                    if (parts.length == 3) {
                        try {
                            double cx = sender instanceof Player p ? parseCoord(parts[0], p.getLocation().getX()) : Double.parseDouble(parts[0]);
                            double cy = sender instanceof Player p ? parseCoord(parts[1], p.getLocation().getY()) : Double.parseDouble(parts[1]);
                            double cz = sender instanceof Player p ? parseCoord(parts[2], p.getLocation().getZ()) : Double.parseDouble(parts[2]);
                            if (sender instanceof Player p) {
                                center = new Location(p.getWorld(), cx, cy, cz);
                            }
                        } catch (NumberFormatException ignored) {}
                    }
                    nextArg++;
                }
                if (args.length > nextArg) {
                    try { radius = Double.parseDouble(args[nextArg]); } catch (NumberFormatException ignored) {}
                } else if (nextArg == 2) {
                    try { radius = Double.parseDouble(possibleCoords); } catch (NumberFormatException ignored) {}
                }
            }
            radius = Math.max(3, Math.min(500, radius));

            int started = 0, skipped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) { skipped++; continue; }
                cancelNavigation(bot.getUniqueId());
                Location c = center != null ? center.clone() : bot.getLocation().clone();
                if (center != null) c.setWorld(bot.getWorld());
                startRoaming(fp, c, radius);
                started++;
            }
            sender.sendMessage(
                    Lang.get("move-all-roam-started",
                            "count", String.valueOf(started),
                            "radius", String.valueOf((int) radius),
                            "skipped", String.valueOf(skipped)));
            return true;
        }

        if (flag.equals("--wp")) {
            if (waypointStore == null || args.length < 3) {
                sender.sendMessage(Lang.get("move-wp-usage"));
                return true;
            }
            String wpName = args[2];
            boolean randomOrder = args.length >= 4 && args[3].equalsIgnoreCase("--random");

            List<Location> route = waypointStore.getRoute(wpName);
            if (route == null || route.isEmpty()) {
                sender.sendMessage(Lang.get("move-wp-not-found", "name", wpName));
                return true;
            }

            int started = 0, skipped = 0;
            for (FakePlayer fp : manager.getActivePlayers()) {
                Player bot = fp.getPlayer();
                if (bot == null || !bot.isOnline()) {
                    skipped++;
                    continue;
                }
                Location first = route.get(0);
                if (first.getWorld() == null || !first.getWorld().equals(bot.getWorld())) {
                    skipped++;
                    continue;
                }
                cancelNavigation(bot.getUniqueId());
                activeRouteNames.put(bot.getUniqueId(), wpName);
                activeRandomFlags.put(bot.getUniqueId(), randomOrder);
                if (randomOrder) startRandomPatrol(bot, route);
                else startPatrol(bot, route);
                started++;
            }

            if (randomOrder) {
                sender.sendMessage(
                        Lang.get(
                                "move-all-wp-started-random",
                                "waypoint",
                                wpName,
                                "count",
                                String.valueOf(started),
                                "skipped",
                                String.valueOf(skipped)));
            } else {
                sender.sendMessage(
                        Lang.get(
                                "move-all-wp-started",
                                "waypoint",
                                wpName,
                                "count",
                                String.valueOf(started),
                                "skipped",
                                String.valueOf(skipped)));
            }
            return true;
        }

        Player target = Bukkit.getPlayer(args[1]);
        if (target == null) {
            sender.sendMessage(Lang.get("player-not-found", "player", args[1]));
            return true;
        }

        int started = 0, skipped = 0;
        for (FakePlayer fp : manager.getActivePlayers()) {
            Player bot = fp.getPlayer();
            if (bot == null || !bot.isOnline()) {
                skipped++;
                continue;
            }
            if (!bot.getWorld().equals(target.getWorld())) {
                skipped++;
                continue;
            }
            cancelNavigation(bot.getUniqueId());
            startNavigation(bot, target);
            started++;
        }
        sender.sendMessage(
                Lang.get(
                        "move-all-navigating",
                        "player",
                        target.getName(),
                        "count",
                        String.valueOf(started),
                        "skipped",
                        String.valueOf(skipped)));
        return true;
    }

    // ═══════════════════════════════════════════════════════════════
    //  Navigation — follow player
    // ═══════════════════════════════════════════════════════════════

    private void startNavigation(@NotNull Player bot, @NotNull Player target) {
        final UUID botUuid = bot.getUniqueId();
        final UUID targetUuid = target.getUniqueId();
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) return;
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> {
                            Player liveTarget = Bukkit.getPlayer(targetUuid);
                            if (liveTarget == null || !liveTarget.isOnline()) return null;
                            return liveTarget.getLocation();
                        },
                        Config.pathfindingArrivalDistance(),
                        Config.pathfindingFollowRecalcDistance(),
                        Integer.MAX_VALUE,
                        null,
                        () -> clearMoveState(botUuid),
                        null));
    }

    // ═══════════════════════════════════════════════════════════════
    //  Patrol — waypoint routes
    // ═══════════════════════════════════════════════════════════════

    private void startPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        navigatePatrolStep(bot.getUniqueId(), new ArrayList<>(waypoints), 0);
    }

    private void startRandomPatrol(@NotNull Player bot, @NotNull List<Location> waypoints) {
        UUID botUuid = bot.getUniqueId();
        List<Integer> shuffled = new ArrayList<>();
        for (int i = 0; i < waypoints.size(); i++) shuffled.add(i);
        Collections.shuffle(shuffled, new Random());
        randomWpOrder.put(botUuid, shuffled);
        navigateRandomPatrolStep(botUuid, new ArrayList<>(waypoints), 0);
    }

    private void navigatePatrolStep(
            @NotNull UUID botUuid, @NotNull List<Location> waypoints, int idx) {
        if (waypoints.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }
        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            clearMoveState(botUuid);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            clearMoveState(botUuid);
            return;
        }

        int nextIdx = Math.floorMod(idx, waypoints.size());
        Location dest = waypoints.get(nextIdx);
        if (dest.getWorld() == null || !dest.getWorld().equals(bot.getWorld())) {
            clearMoveState(botUuid);
            return;
        }

        int arrivalIdx = (nextIdx + 1) % waypoints.size();
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> navigatePatrolStep(botUuid, waypoints, arrivalIdx),
                        () -> clearMoveState(botUuid),
                        () -> navigatePatrolStep(botUuid, waypoints, arrivalIdx)));
    }

    private void navigateRandomPatrolStep(
            @NotNull UUID botUuid, @NotNull List<Location> waypoints, int cycleIdx) {
        if (waypoints.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }
        List<Integer> order = randomWpOrder.get(botUuid);
        if (order == null || order.isEmpty()) {
            clearMoveState(botUuid);
            return;
        }

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) {
            clearMoveState(botUuid);
            return;
        }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) {
            clearMoveState(botUuid);
            return;
        }

        int normalizedCycle = cycleIdx;
        if (normalizedCycle >= order.size()) {
            Collections.shuffle(order, new Random());
            normalizedCycle = 0;
        }

        int actualIdx = order.get(normalizedCycle);
        Location dest = waypoints.get(actualIdx);
        if (dest.getWorld() == null || !dest.getWorld().equals(bot.getWorld())) {
            clearMoveState(botUuid);
            return;
        }

        int nextCycle = normalizedCycle + 1;
        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> navigateRandomPatrolStep(botUuid, waypoints, nextCycle),
                        () -> clearMoveState(botUuid),
                        () -> navigateRandomPatrolStep(botUuid, waypoints, nextCycle)));
    }

    // ═══════════════════════════════════════════════════════════════
    //  Roaming — random wandering within a radius
    // ═══════════════════════════════════════════════════════════════

    private void startRoaming(@NotNull FakePlayer fp, @NotNull Location center, double radius) {
        UUID uid = fp.getUuid();
        roamCenters.put(uid, center.clone());
        roamRadii.put(uid, radius);
        navigateRoamStep(uid);
    }

    private void navigateRoamStep(@NotNull UUID botUuid) {
        if (!roamCenters.containsKey(botUuid)) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) { clearRoamState(botUuid); return; }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) { clearRoamState(botUuid); return; }

        Location center = roamCenters.get(botUuid);
        Double radius = roamRadii.get(botUuid);
        if (center == null || radius == null) { clearRoamState(botUuid); return; }

        Location dest = findRandomWalkableLocation(bot.getWorld(), center, radius);
        if (dest == null) {
            // Couldn't find a valid location — retry after a pause
            BukkitTask pause = Bukkit.getScheduler().runTaskLater(plugin, () -> {
                roamPauseTasks.remove(botUuid);
                navigateRoamStep(botUuid);
            }, 40L); // 2 seconds
            roamPauseTasks.put(botUuid, pause);
            return;
        }

        pathfinding.navigate(
                fp,
                new PathfindingService.NavigationRequest(
                        PathfindingService.Owner.MOVE,
                        () -> dest,
                        Config.pathfindingPatrolArrivalDistance(),
                        0.0,
                        10,
                        () -> onRoamArrival(botUuid),       // onArrive — pause then next
                        () -> clearRoamState(botUuid),      // onCancel
                        () -> onRoamArrival(botUuid)));     // onPathFailure — try next spot
    }

    private void onRoamArrival(@NotNull UUID botUuid) {
        if (!roamCenters.containsKey(botUuid)) return;

        FakePlayer fp = manager.getByUuid(botUuid);
        if (fp == null) { clearRoamState(botUuid); return; }
        Player bot = fp.getPlayer();
        if (bot == null || !bot.isOnline()) { clearRoamState(botUuid); return; }

        // Stop forward motion
        NmsPlayerSpawner.setMovementForward(bot, 0f);
        bot.setSprinting(false);

        ThreadLocalRandom rng = ThreadLocalRandom.current();

        // Realistic pause: 1.5–6 seconds (30–120 ticks)
        int pauseTicks = rng.nextInt(30, 121);

        // Head-look task: look around naturally during the pause
        // Pick 1–3 random look directions
        int lookCount = rng.nextInt(1, 4);
        int lookInterval = Math.max(10, pauseTicks / (lookCount + 1));

        BukkitTask lookTask = Bukkit.getScheduler().runTaskTimer(plugin, new Runnable() {
            int ticks = 0;
            int looksDone = 0;
            float baseYaw = bot.getLocation().getYaw();
            @Override
            public void run() {
                ticks++;
                Player b = fp.getPlayer();
                if (b == null || !b.isOnline() || !roamCenters.containsKey(botUuid)) return;

                if (looksDone < lookCount && ticks % lookInterval == 0) {
                    // Random head turn: ±60° yaw, -15° to +25° pitch
                    float newYaw = baseYaw + rng.nextFloat(-60f, 61f);
                    float newPitch = rng.nextFloat(-15f, 26f);
                    b.setRotation(newYaw, newPitch);
                    NmsPlayerSpawner.setHeadYaw(b, newYaw);
                    looksDone++;
                }
            }
        }, 5L, 1L);
        roamLookTasks.put(botUuid, lookTask);

        // After pause, go to next random spot
        BukkitTask pause = Bukkit.getScheduler().runTaskLater(plugin, () -> {
            cancelRoamPauseTasks(botUuid);
            navigateRoamStep(botUuid);
        }, pauseTicks);
        roamPauseTasks.put(botUuid, pause);
    }

    @Nullable
    private Location findRandomWalkableLocation(@NotNull World world, @NotNull Location center, double radius) {
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        int cx = center.getBlockX();
        int cz = center.getBlockZ();
        int r = (int) radius;

        for (int attempt = 0; attempt < 30; attempt++) {
            // Random point within circle (uniform distribution)
            double angle = rng.nextDouble(Math.PI * 2);
            double dist = Math.sqrt(rng.nextDouble()) * r;  // sqrt for uniform area distribution
            int tx = cx + (int) Math.round(Math.cos(angle) * dist);
            int tz = cz + (int) Math.round(Math.sin(angle) * dist);

            // Find a walkable Y level near the surface
            int ty = findWalkableY(world, tx, tz, center.getBlockY());
            if (ty >= world.getMinHeight() && BotPathfinder.walkable(world, tx, ty, tz)) {
                return new Location(world, tx + 0.5, ty, tz + 0.5);
            }
        }
        return null;
    }

    /**
     * Search for a walkable Y level at the given XZ, preferring heights close to the reference Y.
     * Scans ±16 blocks from refY, checking top-down for closer first.
     */
    private int findWalkableY(@NotNull World world, int x, int z, int refY) {
        int minY = Math.max(world.getMinHeight(), refY - 16);
        int maxY = Math.min(world.getMaxHeight() - 2, refY + 16);
        int bestY = world.getMinHeight() - 1;
        int bestDist = Integer.MAX_VALUE;
        for (int y = maxY; y >= minY; y--) {
            if (BotPathfinder.walkable(world, x, y, z)) {
                int d = Math.abs(y - refY);
                if (d < bestDist) {
                    bestDist = d;
                    bestY = y;
                    if (d == 0) break;
                }
            }
        }
        return bestY;
    }

    // ═══════════════════════════════════════════════════════════════
    //  State management
    // ═══════════════════════════════════════════════════════════════

    private void cancelRoamPauseTasks(@NotNull UUID botUuid) {
        BukkitTask look = roamLookTasks.remove(botUuid);
        if (look != null && !look.isCancelled()) look.cancel();
        BukkitTask pause = roamPauseTasks.remove(botUuid);
        if (pause != null && !pause.isCancelled()) pause.cancel();
    }

    private void clearRoamState(@NotNull UUID botUuid) {
        roamCenters.remove(botUuid);
        roamRadii.remove(botUuid);
        cancelRoamPauseTasks(botUuid);
    }

    private void clearMoveState(@NotNull UUID botUuid) {
        randomWpOrder.remove(botUuid);
        activeRouteNames.remove(botUuid);
        activeRandomFlags.remove(botUuid);
        clearRoamState(botUuid);
    }

    private void cancelNavigation(@NotNull UUID botUuid) {
        pathfinding.cancel(botUuid);
        clearMoveState(botUuid);
    }

    public void cancelAll() {
        pathfinding.cancelAll(PathfindingService.Owner.MOVE);
        new ArrayList<>(activeRouteNames.keySet()).forEach(this::clearMoveState);
        new ArrayList<>(randomWpOrder.keySet()).forEach(this::clearMoveState);
        new ArrayList<>(roamCenters.keySet()).forEach(this::clearMoveState);
    }

    public void cleanupBot(@NotNull UUID botUuid) {
        cancelNavigation(botUuid);
    }

    // ═══════════════════════════════════════════════════════════════
    //  Public API — roaming queries (for persistence / GUI)
    // ═══════════════════════════════════════════════════════════════

    public boolean isRoaming(@NotNull UUID botUuid) {
        return roamCenters.containsKey(botUuid);
    }

    @Nullable
    public Location getRoamCenter(@NotNull UUID botUuid) {
        return roamCenters.get(botUuid);
    }

    @Nullable
    public Double getRoamRadius(@NotNull UUID botUuid) {
        return roamRadii.get(botUuid);
    }

    /**
     * Resume roaming after a server restart (called by BotPersistence).
     */
    public void resumeRoaming(@NotNull FakePlayer fp, @NotNull Location center, double radius) {
        UUID uid = fp.getUuid();
        cancelNavigation(uid);
        startRoaming(fp, center, radius);
    }

    @Override
    public List<String> tabComplete(CommandSender sender, String[] args) {
        List<String> out = new ArrayList<>();
        if (args.length == 1) {
            String in = args[0].toLowerCase();

            if ("all".startsWith(in)) out.add("all");
            for (FakePlayer fp : manager.getActivePlayers())
                if (fp.getName().toLowerCase().startsWith(in)) out.add(fp.getName());
        } else if (args.length == 2) {
            String in = args[1].toLowerCase();

            for (String flag : List.of("--to", "--wp", "--roam", "--stop")) if (flag.startsWith(in)) out.add(flag);

            for (Player p : Bukkit.getOnlinePlayers()) {
                if (manager.getByName(p.getName()) == null
                        && p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
            }
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--to")) {
            String in = args[2].toLowerCase();
            for (Player p : Bukkit.getOnlinePlayers()) {
                if (manager.getByName(p.getName()) == null
                        && p.getName().toLowerCase().startsWith(in)) out.add(p.getName());
            }
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--wp")) {

            if (waypointStore != null) {
                String in = args[2].toLowerCase();
                for (String name : waypointStore.getNames()) if (name.startsWith(in)) out.add(name);
            }
        } else if (args.length == 4 && args[1].equalsIgnoreCase("--wp")) {

            String in = args[3].toLowerCase();
            if ("--random".startsWith(in)) out.add("--random");
        } else if (args.length == 3 && args[1].equalsIgnoreCase("--roam")) {
            // Suggest <radius> or <x,y,z>
            if (sender instanceof Player p) {
                Location loc = p.getLocation();
                out.add(loc.getBlockX() + "," + loc.getBlockY() + "," + loc.getBlockZ());
            }
            out.add("10");
            out.add("20");
            out.add("30");
            out.add("50");
        } else if (args.length == 4 && args[1].equalsIgnoreCase("--roam")) {
            // After coords, suggest radius
            out.add("10");
            out.add("20");
            out.add("30");
            out.add("50");
        }
        return out;
    }

    @Nullable
    public String getActiveRouteForBot(@NotNull UUID botUuid) {
        return activeRouteNames.get(botUuid);
    }

    public boolean isRandomPatrolForBot(@NotNull UUID botUuid) {
        Boolean v = activeRandomFlags.get(botUuid);
        return v != null && v;
    }

    public void resumePatrol(
            @NotNull Player bot,
            @NotNull List<Location> route,
            boolean random,
            @NotNull String routeName) {
        UUID uid = bot.getUniqueId();
        cancelNavigation(uid);
        activeRouteNames.put(uid, routeName);
        activeRandomFlags.put(uid, random);
        if (random) startRandomPatrol(bot, route);
        else startPatrol(bot, route);
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.util.UUID;

/**
 * NMS-based fake player spawner using reflection (version-independent).
 * Creates real NMS ServerPlayer entities that appear as genuine players.
 *
 * <p><b>Architecture:</b> Uses reflection to access NMS classes without direct imports,
 * making it compatible across Paper versions. Creates a true {@code ServerPlayer} instance
 * that bypasses Mojang authentication.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP connection,
 * so the Mojang session server handshake is never triggered.
 */
public final class NmsPlayerSpawner {

    private static boolean initialized = false;
    private static boolean failed = false;

    // Cached classes
    private static Class<?> minecraftServerClass;
    private static Class<?> serverLevelClass;
    private static Class<?> serverPlayerClass;
    private static Class<?> gameProfileClass;
    private static Class<?> clientInformationClass;
    private static Class<?> commonListenerCookieClass;
    private static Class<?> connectionClass;
    private static Class<?> serverGamePacketListenerClass;
    private static Class<?> chatVisibilityClass;
    private static Class<?> humanoidArmClass;
    private static Class<?> particleStatusClass;
    private static Class<?> playerListClass;

    // Cached methods
    private static Method getServerMethod;
    private static Method getHandleMethod;
    private static Method craftPlayerGetHandleMethod; // CraftPlayer.getHandle() → NMS ServerPlayer
    private static Method getPlayerListMethod;
    private static Method placeNewPlayerMethod;
    private static Method setPosMethod;

    // Cached constructors  
    private static Constructor<?> gameProfileConstructor;
    private static Constructor<?> serverPlayerConstructor;
    private static Constructor<?> clientInformationConstructor;
    private static Constructor<?> commonListenerCookieConstructor;
    private static Constructor<?> serverGamePacketListenerConstructor;

    // Cached enum values
    private static Object chatVisibilityHidden;
    private static Object humanoidArmRight;
    private static Object particleStatusAll;

    private NmsPlayerSpawner() {}

    /**
     * Initialize NMS reflection. Safe to call multiple times.
     */
    private static synchronized void init() {
        if (initialized || failed) return;

        try {
            // Get CraftBukkit version (or detect Mojang-mapped Paper)
            String packageName = Bukkit.getServer().getClass().getPackage().getName();
            String version = packageName.substring(packageName.lastIndexOf('.') + 1);

            // On Mojang-mapped Paper, classes are in org.bukkit.craftbukkit directly (no version)
            String craftBukkitPackage = "org.bukkit.craftbukkit";
            if (!version.equals("craftbukkit")) {
                // Legacy/Spigot: org.bukkit.craftbukkit.v1_XX_RX
                craftBukkitPackage += "." + version;
            }

            FppLogger.debug("Detected CraftBukkit package: " + craftBukkitPackage);

            // Load CraftBukkit classes
            Class<?> craftServerClass = Class.forName(craftBukkitPackage + ".CraftServer");
            Class<?> craftWorldClass = Class.forName(craftBukkitPackage + ".CraftWorld");

            // Get NMS class loader
            ClassLoader nmsLoader = craftServerClass.getClassLoader();

            // Try Mojang-mapped names first, fall back to Spigot names
            // Load critical classes first (these determine Mojang vs Spigot)
            try {
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.ServerPlayer");
                // If ServerPlayer loads, we're on Mojang mappings
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.ServerLevel");
                FppLogger.debug("Using Mojang-mapped NMS classes");
            } catch (ClassNotFoundException e) {
                // Fall back to Spigot-mapped names
                FppLogger.info("Mojang mappings not found, trying Spigot mappings...");
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.WorldServer");
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.EntityPlayer");
                FppLogger.debug("Loaded Spigot-mapped NMS classes");
            }

            // Load optional classes individually (don't fail init if any are missing)
            try {
                clientInformationClass = nmsLoader.loadClass("net.minecraft.server.level.ClientInformation");
                FppLogger.debug("✓ Loaded ClientInformation class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ ClientInformation class not found: " + e.getMessage());
            }

            try {
                chatVisibilityClass = nmsLoader.loadClass("net.minecraft.world.entity.player.ChatVisiblity");  // Note: typo in MC code
                FppLogger.debug("✓ Loaded ChatVisiblity class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ ChatVisiblity class not found: " + e.getMessage());
            }

            try {
                humanoidArmClass = nmsLoader.loadClass("net.minecraft.world.entity.HumanoidArm");
                FppLogger.debug("✓ Loaded HumanoidArm class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ HumanoidArm class not found: " + e.getMessage());
            }

            // Try multiple possible locations for ParticleStatus
            String[] particleStatusPaths = {
                "net.minecraft.world.level.GameRules$ParticleStatus",
                "net.minecraft.world.entity.player.ParticleStatus",
                "net.minecraft.core.particles.ParticleStatus",
                "net.minecraft.server.level.ParticleStatus"
            };

            for (String path : particleStatusPaths) {
                try {
                    particleStatusClass = nmsLoader.loadClass(path);
                    FppLogger.debug("✓ Loaded ParticleStatus class from: " + path);
                    break;
                } catch (ClassNotFoundException e) {
                    FppLogger.debug("✗ ParticleStatus not found at: " + path);
                }
            }

            if (particleStatusClass == null) {
                FppLogger.debug("✗ ParticleStatus class not found in any known location");
            }

            // Load other optional classes (currently unused but may be needed for future features)
            try {
                commonListenerCookieClass = nmsLoader.loadClass("net.minecraft.server.network.CommonListenerCookie");
                connectionClass = nmsLoader.loadClass("net.minecraft.network.Connection");
                serverGamePacketListenerClass = nmsLoader.loadClass("net.minecraft.server.network.ServerGamePacketListenerImpl");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("Some optional network classes not available: " + e.getMessage());
            }

            // Load authlib (should be on classpath)
            gameProfileClass = Class.forName("com.mojang.authlib.GameProfile");

            // Cache methods
            getServerMethod = craftServerClass.getMethod("getServer");
            getHandleMethod = craftWorldClass.getMethod("getHandle");
            getPlayerListMethod = minecraftServerClass.getMethod("getPlayerList");

            // Find setPos method (various signatures across versions)
            for (Method m : serverPlayerClass.getMethods()) {
                if (m.getName().equals("setPos") && m.getParameterCount() == 3) {
                    Class<?>[] params = m.getParameterTypes();
                    if (params[0] == double.class && params[1] == double.class && params[2] == double.class) {
                        setPosMethod = m;
                        break;
                    }
                }
            }

            // Cache constructors
            gameProfileConstructor = gameProfileClass.getConstructor(UUID.class, String.class);

            // Cache CraftPlayer.getHandle() for setPosition() use
            Class<?> craftPlayerClass = Class.forName(craftBukkitPackage + ".entity.CraftPlayer");
            craftPlayerGetHandleMethod = craftPlayerClass.getMethod("getHandle");
            craftPlayerGetHandleMethod.setAccessible(true);

            initialized = true;
            FppLogger.info("NMS reflection initialized successfully");

        } catch (Exception e) {
            failed = true;
            FppLogger.error("Failed to initialize NMS reflection: " + e.getMessage());
            e.printStackTrace();
        }
    }

    /**
     * Check if NMS spawning is available.
     */
    public static boolean isAvailable() {
        if (!initialized && !failed) init();
        return initialized;
    }

    /**
     * Spawn a fake NMS ServerPlayer at the given location.
     *
     * <p><b>IMPORTANT:</b> This method creates the ServerPlayer with the bot's REAL name
     * (e.g., "BotName"), not the packet profile name (e.g., "{00_BotName").
     * The packet profile name with the sorting prefix is only used in tab-list packets
     * sent via {@code PacketHelper}, not in the actual NMS entity.
     *
     * @param name     Bot name (REAL name, not packet profile name)
     * @param world    World to spawn in
     * @param x        X coordinate
     * @param y        Y coordinate
     * @param z        Z coordinate
     * @return         Bukkit Player wrapper, or null if spawn failed
     */
    public static Player spawnFakePlayer(String name, World world, double x, double y, double z) {
        if (!isAvailable()) {
            FppLogger.warn("NMS spawning not available, cannot spawn " + name);
            return null;
        }

        try {
            // Create deterministic UUID (offline mode formula)
            UUID uuid = UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + name).getBytes(StandardCharsets.UTF_8)
            );

            // Create GameProfile
            Object gameProfile = gameProfileConstructor.newInstance(uuid, name);

            // Get MinecraftServer
            Object craftServer = Bukkit.getServer();
            Object minecraftServer = getServerMethod.invoke(craftServer);

            // Get ServerLevel
            Object craftWorld = world;
            Object serverLevel = getHandleMethod.invoke(craftWorld);

            // Create ClientInformation (if available)
            Object clientInfo = null;
            if (clientInformationClass != null) {
                clientInfo = createClientInformation();
            }

            // Create ServerPlayer
            // Constructor signature varies by version, try multiple approaches
            Object serverPlayer = createServerPlayer(minecraftServer, serverLevel, gameProfile, clientInfo);

            if (serverPlayer == null) {
                FppLogger.warn("Failed to create ServerPlayer for " + name);
                return null;
            }

            // Set position BEFORE adding to world
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // CRITICAL: set up a fake network connection BEFORE adding to world.
            // ServerPlayer.tick() immediately calls this.connection.tickClientLoadTimeout(),
            // so connection must be non-null or the server crashes on the next tick.
            setupFakeConnection(minecraftServer, serverPlayer, gameProfile, clientInfo);

            // Add the ServerPlayer to the world via PlayerList.placeNewPlayer(),
            // which properly registers the player, fires join events, and sends
            // spawn packets to nearby players so they can see the bot.
            boolean addedViaPlayerList = false;
            try {
                Object playerList = getPlayerListMethod.invoke(minecraftServer);
                // placeNewPlayer(Connection, ServerPlayer, CommonListenerCookie)
                // The Connection is already set inside setupFakeConnection;
                // retrieve it from the player's connection field.
                Object sgpl = getConnectionField(serverPlayer);
                if (sgpl != null && commonListenerCookieClass != null) {
                    // Extract the Connection from the ServerGamePacketListenerImpl
                    Object conn = getConnectionFromSgpl(sgpl);
                    Object cookie = createCookieDynamic(gameProfile, clientInfo);
                    if (conn != null && cookie != null) {
                        Method placeMethod = findMethod(playerList.getClass(), "placeNewPlayer", 3);
                        if (placeMethod != null) {
                            placeMethod.setAccessible(true);
                            placeMethod.invoke(playerList, conn, serverPlayer, cookie);
                            addedViaPlayerList = true;
                            FppLogger.debug("Added ServerPlayer via PlayerList.placeNewPlayer()");
                        }
                    }
                }
            } catch (Exception e) {
                FppLogger.debug("placeNewPlayer failed (" + e.getMessage() + "), trying addNewPlayer fallback");
            }

            // Fallback: add directly to the ServerLevel entity list
            if (!addedViaPlayerList) {
                try {
                    Method addMethod = findMethod(serverLevel.getClass(), "addNewPlayer", 1);
                    if (addMethod != null) {
                        addMethod.setAccessible(true);
                        addMethod.invoke(serverLevel, serverPlayer);
                        FppLogger.debug("Added ServerPlayer via ServerLevel.addNewPlayer()");
                    }
                } catch (Exception e) {
                    FppLogger.debug("addNewPlayer also failed: " + e.getMessage());
                }
            }

            // Restore position after placeNewPlayer (it may have teleported to spawn)
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // Get Bukkit wrapper
            Method getBukkitEntityMethod = serverPlayerClass.getMethod("getBukkitEntity");
            Object bukkitEntity = getBukkitEntityMethod.invoke(serverPlayer);

            if (bukkitEntity instanceof Player) {
                Player result = (Player) bukkitEntity;

                // placeNewPlayer() may have reset the game mode to the server default
                // (often CREATIVE or ADVENTURE on test servers).  Force SURVIVAL so:
                //  • Mobs can target the bot (spectator/creative players are ignored)
                //  • Drowning works (creative players are immune)
                //  • Fall damage fires (creative players take no fall damage)
                //  • All other survival-specific mechanics work correctly
                result.setGameMode(org.bukkit.GameMode.SURVIVAL);

                FppLogger.info("NMS ServerPlayer spawned: " + name + " (UUID: " + result.getUniqueId() + ")");
                return result;
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to spawn fake player " + name + ": " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    private static Object createClientInformation() {
        try {
            // Verify critical classes are loaded
            if (chatVisibilityClass == null || humanoidArmClass == null) {
                FppLogger.warn("Required classes not loaded for ClientInformation");
                return null;
            }

            if (clientInformationConstructor == null) {
                // Find the 9-parameter constructor and extract the actual ParticleStatus class
                Constructor<?>[] constructors = clientInformationClass.getConstructors();
                for (Constructor<?> ctor : constructors) {
                    if (ctor.getParameterCount() == 9) {
                        Class<?>[] params = ctor.getParameterTypes();
                        particleStatusClass = params[8]; // 9th parameter (ParticleStatus)

                        // Get the constructor with the discovered class
                        clientInformationConstructor = clientInformationClass.getConstructor(
                            String.class, int.class, chatVisibilityClass, boolean.class,
                            int.class, humanoidArmClass, boolean.class, boolean.class,
                            particleStatusClass
                        );

                        // Cache enum values
                        chatVisibilityHidden = chatVisibilityClass.getEnumConstants()[2]; // HIDDEN
                        humanoidArmRight = humanoidArmClass.getEnumConstants()[1]; // RIGHT
                        particleStatusAll = particleStatusClass.getEnumConstants()[0]; // ALL

                        FppLogger.debug("ClientInformation constructor cached (ParticleStatus: " + particleStatusClass.getSimpleName() + ")");
                        break;
                    }
                }

                if (clientInformationConstructor == null) {
                    FppLogger.warn("Could not find 9-parameter ClientInformation constructor");
                    return null;
                }
            }

            return clientInformationConstructor.newInstance(
                "en", 2, chatVisibilityHidden, true, 0, humanoidArmRight, false, false, particleStatusAll
            );
        } catch (Exception e) {
            FppLogger.warn("Failed to create ClientInformation: " + e.getMessage());
            return null;
        }
    }

    private static Object createServerPlayer(Object minecraftServer, Object serverLevel, 
                                             Object gameProfile, Object clientInfo) {
        try {
            // Try modern constructor (1.19+): ServerPlayer(MinecraftServer, ServerLevel, GameProfile, ClientInformation)
            if (clientInfo != null) {
                try {
                    serverPlayerConstructor = serverPlayerClass.getConstructor(
                        minecraftServerClass, serverLevelClass, gameProfileClass, clientInformationClass
                    );
                    return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile, clientInfo);
                } catch (NoSuchMethodException e) {
                    FppLogger.debug("4-arg ServerPlayer constructor not found, trying 3-arg");
                }
            }

            // Try older constructor: ServerPlayer(MinecraftServer, ServerLevel, GameProfile)
            try {
                serverPlayerConstructor = serverPlayerClass.getConstructor(
                    minecraftServerClass, serverLevelClass, gameProfileClass
                );
                return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile);
            } catch (NoSuchMethodException e) {
                FppLogger.warn("No compatible ServerPlayer constructor found");
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to create ServerPlayer instance: " + e.getMessage());
            return null;
        }
    }

    /**
     * Creates a fake network connection backed by a Netty {@link io.netty.channel.embedded.EmbeddedChannel}
     * and wires it into a new {@code ServerGamePacketListenerImpl} assigned to {@code serverPlayer.connection}.
     *
     * <p><b>Why EmbeddedChannel?</b>  {@code EmbeddedChannel} is always open ({@code isOpen()} == {@code true}),
     * so {@code Connection.isConnected()} returns {@code true} and the server never removes the bot on a
     * perceived connection loss.  Any packets "sent" to the channel are stored in Netty's outbound
     * buffer without triggering encoder exceptions — no real network I/O occurs.
     *
     * <p><b>Dummy socket address:</b>  {@code Connection.handleDisconnection()} calls
     * {@code this.address.getAddress()} and NPEs if address is {@code null}.  We inject a dummy
     * {@code InetSocketAddress} to prevent this crash when the bot is kicked.
     * 
     * <p><b>Null Promise Fix:</b> Overrides Connection methods to handle null promises gracefully.
     */
    private static void setupFakeConnection(Object minecraftServer, Object serverPlayer,
                                            Object gameProfile, Object clientInfo) {
        if (connectionClass == null || commonListenerCookieClass == null
                || serverGamePacketListenerClass == null) {
            FppLogger.debug("Network classes not loaded — skipping fake connection setup");
            return;
        }
        try {
            ClassLoader nmsLoader = minecraftServerClass.getClassLoader();

            // 1. Create EmbeddedChannel - simple, no handlers needed
            Class<?> embeddedChannelClass = Class.forName("io.netty.channel.embedded.EmbeddedChannel");
            Constructor<?> embeddedChannelConstructor = embeddedChannelClass.getDeclaredConstructor();
            Object embeddedChannel = embeddedChannelConstructor.newInstance();

            // 2. PacketFlow.SERVERBOUND
            Class<?> packetFlowClass = nmsLoader.loadClass("net.minecraft.network.protocol.PacketFlow");
            Object serverbound = packetFlowClass.getEnumConstants()[0]; // SERVERBOUND

            // 3. Create Connection subclass that handles null promises gracefully
            Constructor<?> connCtor = connectionClass.getDeclaredConstructor(packetFlowClass);
            connCtor.setAccessible(true);
            Object conn = createNullSafeConnection(connCtor, serverbound, embeddedChannel);

            // 4.5. Inject a dummy InetSocketAddress so Connection.handleDisconnection()
            // does not NPE when the bot is kicked.
            for (Field f : getAllDeclaredFields(connectionClass)) {
                if (java.net.SocketAddress.class.isAssignableFrom(f.getType())) {
                    try {
                        f.setAccessible(true);
                        if (f.get(conn) == null) {
                            f.set(conn, new java.net.InetSocketAddress("127.0.0.1", 25565));
                            FppLogger.debug("Injected dummy InetSocketAddress into Connection." + f.getName());
                        }
                    } catch (Exception ignored) {}
                    break;
                }
            }

            // 5. CommonListenerCookie
            Object cookie = createCookieDynamic(gameProfile, clientInfo);
            if (cookie == null) {
                FppLogger.warn("Could not create CommonListenerCookie — fake connection incomplete");
                return;
            }

            // 6. ServerGamePacketListenerImpl(MinecraftServer, Connection, ServerPlayer, CommonListenerCookie)
            //    Its constructor sets player.connection = this automatically.
            for (Constructor<?> c : serverGamePacketListenerClass.getDeclaredConstructors()) {
                if (c.getParameterCount() == 4) {
                    c.setAccessible(true);
                    c.newInstance(minecraftServer, conn, serverPlayer, cookie);
                    FppLogger.debug("ServerGamePacketListenerImpl created; connection set on ServerPlayer");
                    return;
                }
            }
            FppLogger.warn("Could not find 4-arg ServerGamePacketListenerImpl constructor");

        } catch (Exception e) {
            FppLogger.warn("setupFakeConnection failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
        }
    }

    /**
     * Creates a Connection object that handles null promises gracefully to prevent Netty NPEs.
     */
    private static Object createNullSafeConnection(Constructor<?> connCtor, Object serverbound, Object embeddedChannel) throws Exception {
        // Create the Connection instance 
        Object conn = connCtor.newInstance(serverbound);

        // Inject EmbeddedChannel into the Connection's channel field
        for (Field f : getAllDeclaredFields(connectionClass)) {
            if (f.getType().getSimpleName().equals("Channel")) {
                f.setAccessible(true);
                f.set(conn, embeddedChannel);
                FppLogger.debug("Injected EmbeddedChannel into Connection." + f.getName());
                break;
            }
        }

        // Instead of proxy, let's override specific methods by wrapping the connection
        // First, let's try to override the problematic send/flush methods directly using reflection
        try {
            // Override the doSendPacket method to be a no-op
            Method doSendPacketMethod = findMethodInClass(connectionClass, "doSendPacket");
            if (doSendPacketMethod != null) {
                // We can't easily override methods without bytecode manipulation, 
                // so let's try a different approach - modify the channel itself
                FppLogger.debug("Found doSendPacket method, will rely on channel modification");
            }
        } catch (Exception e) {
            Config.debug("Could not find doSendPacket method: " + e.getMessage());
        }

        return conn;
    }

    /**
     * Find a method in a class or its superclasses by name.
     */
    private static Method findMethodInClass(Class<?> clazz, String methodName) {
        Class<?> current = clazz;
        while (current != null && current != Object.class) {
            for (Method method : current.getDeclaredMethods()) {
                if (method.getName().equals(methodName)) {
                    return method;
                }
            }
            current = current.getSuperclass();
        }
        return null;
    }

    /** Dynamically creates a {@code CommonListenerCookie} by iterating its constructors. */
    private static Object createCookieDynamic(Object gameProfile, Object clientInfo) {
        try {
            Constructor<?>[] ctors = commonListenerCookieClass.getDeclaredConstructors();

            // Log available constructors on first attempt (debug aids)
            FppLogger.info("CommonListenerCookie constructors (" + ctors.length + "):");
            for (Constructor<?> c : ctors) {
                StringBuilder sb = new StringBuilder("  [" + c.getParameterCount() + "] ");
                for (Class<?> p : c.getParameterTypes()) sb.append(p.getSimpleName()).append(", ");
                FppLogger.info(sb.toString());
            }

            for (Constructor<?> c : ctors) {
                c.setAccessible(true);
                Class<?>[] p = c.getParameterTypes();
                // Skip synthetic constructors added by the compiler (e.g. for records)
                if (p.length > 0 && p[p.length - 1].getSimpleName().contains("DefaultConstructorMarker")) continue;
                try {
                    switch (p.length) {
                        case 1 -> { return c.newInstance(gameProfile); }
                        case 2 -> { return c.newInstance(gameProfile, 0); }
                        case 3 -> { return c.newInstance(gameProfile, 0, clientInfo); }
                        case 4 -> { return c.newInstance(gameProfile, 0, clientInfo, false); }
                        case 5 -> { return c.newInstance(gameProfile, 0, clientInfo, false, false); }
                        case 7 -> {
                            // Paper 1.21.11+: (GameProfile, int, ClientInformation, boolean, String, Set, KeepAlive)
                            // Pass null for String (server address) and KeepAlive; empty Set for server cookies.
                            return c.newInstance(gameProfile, 0, clientInfo, false,
                                    null, java.util.Collections.emptySet(), null);
                        }
                    }
                } catch (Exception e) {
                    FppLogger.info("  → [" + p.length + "-arg] failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
                }
            }
        } catch (Exception e) {
            FppLogger.debug("createCookieDynamic failed: " + e.getMessage());
        }
        FppLogger.warn("createCookieDynamic: no constructor worked for CommonListenerCookie");
        return null;
    }

    /** Returns the value of {@code serverPlayer.connection} (the ServerGamePacketListenerImpl). */
    private static Object getConnectionField(Object serverPlayer) {
        try {
            for (Field f : getAllDeclaredFields(serverPlayerClass)) {
                if (serverGamePacketListenerClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(serverPlayer);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Returns the {@code Connection} object held inside a {@code ServerGamePacketListenerImpl}. */
    private static Object getConnectionFromSgpl(Object sgpl) {
        try {
            for (Field f : getAllDeclaredFields(sgpl.getClass())) {
                if (connectionClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(sgpl);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Finds a method on a class (or its supers) by name and parameter count. */
    private static Method findMethod(Class<?> clazz, String name, int paramCount) {
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Method m : cur.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                    m.setAccessible(true);
                    return m;
                }
            }
            cur = cur.getSuperclass();
        }
        return null;
    }

    /** Collects all declared fields from a class and all its superclasses. */
    private static java.util.List<Field> getAllDeclaredFields(Class<?> clazz) {
        java.util.List<Field> fields = new java.util.ArrayList<>();
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Field f : cur.getDeclaredFields()) fields.add(f);
            cur = cur.getSuperclass();
        }
        return fields;
    }

    /**
     * Directly sets the NMS entity's position via {@code Entity.setPos(x, y, z)}.
     *
     * <p>This bypasses client-authoritative movement — the entity's server-side
     * coordinates are updated immediately, and the entity tracker then broadcasts
     * the position change to all nearby players on its next update cycle.
     *
     * <p>Used by the manual physics loop in {@code BotCollisionListener} to move
     * NMS fake-player bots that have a fake (EmbeddedChannel) connection that
     * discards all outgoing packets, including velocity and position packets.
     */
    public static void setPosition(Player bot, double x, double y, double z) {
        if (!initialized || setPosMethod == null || craftPlayerGetHandleMethod == null) return;
        try {
            Object nmsPlayer = craftPlayerGetHandleMethod.invoke(bot);
            setPosMethod.invoke(nmsPlayer, x, y, z);
        } catch (Exception e) {
            FppLogger.debug("NmsPlayerSpawner.setPosition failed: " + e.getMessage());
        }
    }

    /**
     * Remove a fake player from the server.
     */
    public static void removeFakePlayer(Player player) {
        if (player == null) return;

        try {
            // Simply disconnect/remove the player
            player.kick(net.kyori.adventure.text.Component.empty());
        } catch (Exception e) {
            FppLogger.error("Failed to remove fake player: " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.fakeplayer;

import me.bill.fakePlayerPlugin.config.Config;
import me.bill.fakePlayerPlugin.util.FppLogger;
import org.bukkit.Bukkit;
import org.bukkit.Location;
import org.bukkit.World;
import org.bukkit.entity.Player;
import org.bukkit.plugin.Plugin;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.util.UUID;

/**
 * NMS-based fake player spawner using reflection (version-independent).
 * Creates real NMS ServerPlayer entities that appear as genuine players.
 *
 * <p><b>Architecture:</b> Uses reflection to access NMS classes without direct imports,
 * making it compatible across Paper versions. Creates a true {@code ServerPlayer} instance
 * that bypasses Mojang authentication.
 *
 * <p><b>Auth bypass:</b> The player is created directly in JVM memory without a TCP connection,
 * so the Mojang session server handshake is never triggered.
 */
public final class NmsPlayerSpawner {

    private static boolean initialized = false;
    private static boolean failed = false;

    // Cached classes
    private static Class<?> minecraftServerClass;
    private static Class<?> serverLevelClass;
    private static Class<?> serverPlayerClass;
    private static Class<?> gameProfileClass;
    private static Class<?> clientInformationClass;
    private static Class<?> commonListenerCookieClass;
    private static Class<?> connectionClass;
    private static Class<?> serverGamePacketListenerClass;
    private static Class<?> chatVisibilityClass;
    private static Class<?> humanoidArmClass;
    private static Class<?> particleStatusClass;
    private static Class<?> playerListClass;

    // Cached methods
    private static Method getServerMethod;
    private static Method getHandleMethod;
    private static Method craftPlayerGetHandleMethod; // CraftPlayer.getHandle() → NMS ServerPlayer
    private static Method getPlayerListMethod;
    private static Method placeNewPlayerMethod;
    private static Method setPosMethod;

    // Cached constructors  
    private static Constructor<?> gameProfileConstructor;
    private static Constructor<?> serverPlayerConstructor;
    private static Constructor<?> clientInformationConstructor;
    private static Constructor<?> commonListenerCookieConstructor;
    private static Constructor<?> serverGamePacketListenerConstructor;

    // Cached enum values
    private static Object chatVisibilityHidden;
    private static Object humanoidArmRight;
    private static Object particleStatusAll;

    private NmsPlayerSpawner() {}

    /**
     * Initialize NMS reflection. Safe to call multiple times.
     */
    private static synchronized void init() {
        if (initialized || failed) return;

        try {
            // Get CraftBukkit version (or detect Mojang-mapped Paper)
            String packageName = Bukkit.getServer().getClass().getPackage().getName();
            String version = packageName.substring(packageName.lastIndexOf('.') + 1);

            // On Mojang-mapped Paper, classes are in org.bukkit.craftbukkit directly (no version)
            String craftBukkitPackage = "org.bukkit.craftbukkit";
            if (!version.equals("craftbukkit")) {
                // Legacy/Spigot: org.bukkit.craftbukkit.v1_XX_RX
                craftBukkitPackage += "." + version;
            }

            FppLogger.debug("Detected CraftBukkit package: " + craftBukkitPackage);

            // Load CraftBukkit classes
            Class<?> craftServerClass = Class.forName(craftBukkitPackage + ".CraftServer");
            Class<?> craftWorldClass = Class.forName(craftBukkitPackage + ".CraftWorld");

            // Get NMS class loader
            ClassLoader nmsLoader = craftServerClass.getClassLoader();

            // Try Mojang-mapped names first, fall back to Spigot names
            // Load critical classes first (these determine Mojang vs Spigot)
            try {
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.ServerPlayer");
                // If ServerPlayer loads, we're on Mojang mappings
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.ServerLevel");
                FppLogger.debug("Using Mojang-mapped NMS classes");
            } catch (ClassNotFoundException e) {
                // Fall back to Spigot-mapped names
                FppLogger.info("Mojang mappings not found, trying Spigot mappings...");
                minecraftServerClass = nmsLoader.loadClass("net.minecraft.server.MinecraftServer");
                serverLevelClass = nmsLoader.loadClass("net.minecraft.server.level.WorldServer");
                serverPlayerClass = nmsLoader.loadClass("net.minecraft.server.level.EntityPlayer");
                FppLogger.debug("Loaded Spigot-mapped NMS classes");
            }

            // Load optional classes individually (don't fail init if any are missing)
            try {
                clientInformationClass = nmsLoader.loadClass("net.minecraft.server.level.ClientInformation");
                FppLogger.debug("✓ Loaded ClientInformation class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ ClientInformation class not found: " + e.getMessage());
            }

            try {
                chatVisibilityClass = nmsLoader.loadClass("net.minecraft.world.entity.player.ChatVisiblity");  // Note: typo in MC code
                FppLogger.debug("✓ Loaded ChatVisiblity class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ ChatVisiblity class not found: " + e.getMessage());
            }

            try {
                humanoidArmClass = nmsLoader.loadClass("net.minecraft.world.entity.HumanoidArm");
                FppLogger.debug("✓ Loaded HumanoidArm class");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("✗ HumanoidArm class not found: " + e.getMessage());
            }

            // Try multiple possible locations for ParticleStatus
            String[] particleStatusPaths = {
                "net.minecraft.world.level.GameRules$ParticleStatus",
                "net.minecraft.world.entity.player.ParticleStatus",
                "net.minecraft.core.particles.ParticleStatus",
                "net.minecraft.server.level.ParticleStatus"
            };

            for (String path : particleStatusPaths) {
                try {
                    particleStatusClass = nmsLoader.loadClass(path);
                    FppLogger.debug("✓ Loaded ParticleStatus class from: " + path);
                    break;
                } catch (ClassNotFoundException e) {
                    FppLogger.debug("✗ ParticleStatus not found at: " + path);
                }
            }

            if (particleStatusClass == null) {
                FppLogger.debug("✗ ParticleStatus class not found in any known location");
            }

            // Load other optional classes (currently unused but may be needed for future features)
            try {
                commonListenerCookieClass = nmsLoader.loadClass("net.minecraft.server.network.CommonListenerCookie");
                connectionClass = nmsLoader.loadClass("net.minecraft.network.Connection");
                serverGamePacketListenerClass = nmsLoader.loadClass("net.minecraft.server.network.ServerGamePacketListenerImpl");
            } catch (ClassNotFoundException e) {
                FppLogger.debug("Some optional network classes not available: " + e.getMessage());
            }

            // Load authlib (should be on classpath)
            gameProfileClass = Class.forName("com.mojang.authlib.GameProfile");

            // Cache methods
            getServerMethod = craftServerClass.getMethod("getServer");
            getHandleMethod = craftWorldClass.getMethod("getHandle");
            getPlayerListMethod = minecraftServerClass.getMethod("getPlayerList");

            // Find setPos method (various signatures across versions)
            for (Method m : serverPlayerClass.getMethods()) {
                if (m.getName().equals("setPos") && m.getParameterCount() == 3) {
                    Class<?>[] params = m.getParameterTypes();
                    if (params[0] == double.class && params[1] == double.class && params[2] == double.class) {
                        setPosMethod = m;
                        break;
                    }
                }
            }

            // Cache constructors
            gameProfileConstructor = gameProfileClass.getConstructor(UUID.class, String.class);

            // Cache CraftPlayer.getHandle() for setPosition() use
            Class<?> craftPlayerClass = Class.forName(craftBukkitPackage + ".entity.CraftPlayer");
            craftPlayerGetHandleMethod = craftPlayerClass.getMethod("getHandle");
            craftPlayerGetHandleMethod.setAccessible(true);

            initialized = true;
            FppLogger.info("NMS reflection initialized successfully");

        } catch (Exception e) {
            failed = true;
            FppLogger.error("Failed to initialize NMS reflection: " + e.getMessage());
            e.printStackTrace();
        }
    }

    /**
     * Check if NMS spawning is available.
     */
    public static boolean isAvailable() {
        if (!initialized && !failed) init();
        return initialized;
    }

    /**
     * Spawn a fake NMS ServerPlayer at the given location.
     *
     * <p><b>IMPORTANT:</b> This method creates the ServerPlayer with the bot's REAL name
     * (e.g., "BotName"), not the packet profile name (e.g., "{00_BotName").
     * The packet profile name with the sorting prefix is only used in tab-list packets
     * sent via {@code PacketHelper}, not in the actual NMS entity.
     *
     * @param name     Bot name (REAL name, not packet profile name)
     * @param world    World to spawn in
     * @param x        X coordinate
     * @param y        Y coordinate
     * @param z        Z coordinate
     * @return         Bukkit Player wrapper, or null if spawn failed
     */
    public static Player spawnFakePlayer(String name, World world, double x, double y, double z) {
        if (!isAvailable()) {
            FppLogger.warn("NMS spawning not available, cannot spawn " + name);
            return null;
        }

        try {
            // Create deterministic UUID (offline mode formula)
            UUID uuid = UUID.nameUUIDFromBytes(
                ("OfflinePlayer:" + name).getBytes(StandardCharsets.UTF_8)
            );

            // Create GameProfile
            Object gameProfile = gameProfileConstructor.newInstance(uuid, name);

            // Get MinecraftServer
            Object craftServer = Bukkit.getServer();
            Object minecraftServer = getServerMethod.invoke(craftServer);

            // Get ServerLevel
            Object craftWorld = world;
            Object serverLevel = getHandleMethod.invoke(craftWorld);

            // Create ClientInformation (if available)
            Object clientInfo = null;
            if (clientInformationClass != null) {
                clientInfo = createClientInformation();
            }

            // Create ServerPlayer
            // Constructor signature varies by version, try multiple approaches
            Object serverPlayer = createServerPlayer(minecraftServer, serverLevel, gameProfile, clientInfo);

            if (serverPlayer == null) {
                FppLogger.warn("Failed to create ServerPlayer for " + name);
                return null;
            }

            // Set position BEFORE adding to world
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // CRITICAL: set up a fake network connection BEFORE adding to world.
            // ServerPlayer.tick() immediately calls this.connection.tickClientLoadTimeout(),
            // so connection must be non-null or the server crashes on the next tick.
            setupFakeConnection(minecraftServer, serverPlayer, gameProfile, clientInfo);

            // Add the ServerPlayer to the world via PlayerList.placeNewPlayer(),
            // which properly registers the player, fires join events, and sends
            // spawn packets to nearby players so they can see the bot.
            boolean addedViaPlayerList = false;
            try {
                Object playerList = getPlayerListMethod.invoke(minecraftServer);
                // placeNewPlayer(Connection, ServerPlayer, CommonListenerCookie)
                // The Connection is already set inside setupFakeConnection;
                // retrieve it from the player's connection field.
                Object sgpl = getConnectionField(serverPlayer);
                if (sgpl != null && commonListenerCookieClass != null) {
                    // Extract the Connection from the ServerGamePacketListenerImpl
                    Object conn = getConnectionFromSgpl(sgpl);
                    Object cookie = createCookieDynamic(gameProfile, clientInfo);
                    if (conn != null && cookie != null) {
                        Method placeMethod = findMethod(playerList.getClass(), "placeNewPlayer", 3);
                        if (placeMethod != null) {
                            placeMethod.setAccessible(true);
                            placeMethod.invoke(playerList, conn, serverPlayer, cookie);
                            addedViaPlayerList = true;
                            FppLogger.debug("Added ServerPlayer via PlayerList.placeNewPlayer()");
                        }
                    }
                }
            } catch (Exception e) {
                FppLogger.debug("placeNewPlayer failed (" + e.getMessage() + "), trying addNewPlayer fallback");
            }

            // Fallback: add directly to the ServerLevel entity list
            if (!addedViaPlayerList) {
                try {
                    Method addMethod = findMethod(serverLevel.getClass(), "addNewPlayer", 1);
                    if (addMethod != null) {
                        addMethod.setAccessible(true);
                        addMethod.invoke(serverLevel, serverPlayer);
                        FppLogger.debug("Added ServerPlayer via ServerLevel.addNewPlayer()");
                    }
                } catch (Exception e) {
                    FppLogger.debug("addNewPlayer also failed: " + e.getMessage());
                }
            }

            // Restore position after placeNewPlayer (it may have teleported to spawn)
            if (setPosMethod != null) {
                setPosMethod.invoke(serverPlayer, x, y, z);
            }

            // Get Bukkit wrapper
            Method getBukkitEntityMethod = serverPlayerClass.getMethod("getBukkitEntity");
            Object bukkitEntity = getBukkitEntityMethod.invoke(serverPlayer);

            if (bukkitEntity instanceof Player) {
                Player result = (Player) bukkitEntity;

                // placeNewPlayer() may have reset the game mode to the server default
                // (often CREATIVE or ADVENTURE on test servers).  Force SURVIVAL so:
                //  • Mobs can target the bot (spectator/creative players are ignored)
                //  • Drowning works (creative players are immune)
                //  • Fall damage fires (creative players take no fall damage)
                //  • All other survival-specific mechanics work correctly
                result.setGameMode(org.bukkit.GameMode.SURVIVAL);

                FppLogger.info("NMS ServerPlayer spawned: " + name + " (UUID: " + result.getUniqueId() + ")");
                return result;
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to spawn fake player " + name + ": " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    private static Object createClientInformation() {
        try {
            // Verify critical classes are loaded
            if (chatVisibilityClass == null || humanoidArmClass == null) {
                FppLogger.warn("Required classes not loaded for ClientInformation");
                return null;
            }

            if (clientInformationConstructor == null) {
                // Find the 9-parameter constructor and extract the actual ParticleStatus class
                Constructor<?>[] constructors = clientInformationClass.getConstructors();
                for (Constructor<?> ctor : constructors) {
                    if (ctor.getParameterCount() == 9) {
                        Class<?>[] params = ctor.getParameterTypes();
                        particleStatusClass = params[8]; // 9th parameter (ParticleStatus)

                        // Get the constructor with the discovered class
                        clientInformationConstructor = clientInformationClass.getConstructor(
                            String.class, int.class, chatVisibilityClass, boolean.class,
                            int.class, humanoidArmClass, boolean.class, boolean.class,
                            particleStatusClass
                        );

                        // Cache enum values
                        chatVisibilityHidden = chatVisibilityClass.getEnumConstants()[2]; // HIDDEN
                        humanoidArmRight = humanoidArmClass.getEnumConstants()[1]; // RIGHT
                        particleStatusAll = particleStatusClass.getEnumConstants()[0]; // ALL

                        FppLogger.debug("ClientInformation constructor cached (ParticleStatus: " + particleStatusClass.getSimpleName() + ")");
                        break;
                    }
                }

                if (clientInformationConstructor == null) {
                    FppLogger.warn("Could not find 9-parameter ClientInformation constructor");
                    return null;
                }
            }

            return clientInformationConstructor.newInstance(
                "en", 2, chatVisibilityHidden, true, 0, humanoidArmRight, false, false, particleStatusAll
            );
        } catch (Exception e) {
            FppLogger.warn("Failed to create ClientInformation: " + e.getMessage());
            return null;
        }
    }

    private static Object createServerPlayer(Object minecraftServer, Object serverLevel, 
                                             Object gameProfile, Object clientInfo) {
        try {
            // Try modern constructor (1.19+): ServerPlayer(MinecraftServer, ServerLevel, GameProfile, ClientInformation)
            if (clientInfo != null) {
                try {
                    serverPlayerConstructor = serverPlayerClass.getConstructor(
                        minecraftServerClass, serverLevelClass, gameProfileClass, clientInformationClass
                    );
                    return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile, clientInfo);
                } catch (NoSuchMethodException e) {
                    FppLogger.debug("4-arg ServerPlayer constructor not found, trying 3-arg");
                }
            }

            // Try older constructor: ServerPlayer(MinecraftServer, ServerLevel, GameProfile)
            try {
                serverPlayerConstructor = serverPlayerClass.getConstructor(
                    minecraftServerClass, serverLevelClass, gameProfileClass
                );
                return serverPlayerConstructor.newInstance(minecraftServer, serverLevel, gameProfile);
            } catch (NoSuchMethodException e) {
                FppLogger.warn("No compatible ServerPlayer constructor found");
            }

            return null;

        } catch (Exception e) {
            FppLogger.error("Failed to create ServerPlayer instance: " + e.getMessage());
            return null;
        }
    }

    /**
     * Creates a fake network connection backed by a Netty {@link io.netty.channel.embedded.EmbeddedChannel}
     * and wires it into a new {@code ServerGamePacketListenerImpl} assigned to {@code serverPlayer.connection}.
     *
     * <p><b>Why EmbeddedChannel?</b>  {@code EmbeddedChannel} is always open ({@code isOpen()} == {@code true}),
     * so {@code Connection.isConnected()} returns {@code true} and the server never removes the bot on a
     * perceived connection loss.  Any packets "sent" to the channel are stored in Netty's outbound
     * buffer without triggering encoder exceptions — no real network I/O occurs.
     *
     * <p><b>Dummy socket address:</b>  {@code Connection.handleDisconnection()} calls
     * {@code this.address.getAddress()} and NPEs if address is {@code null}.  We inject a dummy
     * {@code InetSocketAddress} to prevent this crash when the bot is kicked.
     * 
     * <p><b>Null Promise Fix:</b> Overrides Connection methods to handle null promises gracefully.
     */
    private static void setupFakeConnection(Object minecraftServer, Object serverPlayer,
                                            Object gameProfile, Object clientInfo) {
        if (connectionClass == null || commonListenerCookieClass == null
                || serverGamePacketListenerClass == null) {
            FppLogger.debug("Network classes not loaded — skipping fake connection setup");
            return;
        }
        try {
            ClassLoader nmsLoader = minecraftServerClass.getClassLoader();

            // 1. Create custom EmbeddedChannel that handles null promises safely
            Class<?> embeddedChannelClass = Class.forName("io.netty.channel.embedded.EmbeddedChannel");
            Class<?> channelHandlerClass = Class.forName("io.netty.channel.ChannelHandler");
            Class<?> channelPromiseClass = Class.forName("io.netty.channel.ChannelPromise");
            Class<?> channelInboundHandlerAdapterClass = Class.forName("io.netty.channel.ChannelInboundHandlerAdapter");

            // Create a handler that creates dummy promises when needed
            Object customHandler = java.lang.reflect.Proxy.newProxyInstance(
                nmsLoader,
                new Class<?>[]{channelHandlerClass},
                (proxy, method, args) -> {
                    // For any method that might receive null promises, we'll just ignore and return
                    Config.debug("Custom channel handler called: " + method.getName());
                    return null;
                }
            );

            Constructor<?> embeddedChannelConstructor;
            Object embeddedChannel;

            try {
                // Try to create EmbeddedChannel with our custom handler
                embeddedChannelConstructor = embeddedChannelClass.getConstructor(channelHandlerClass.arrayType());
                embeddedChannel = embeddedChannelConstructor.newInstance((Object)new Object[]{customHandler});
                FppLogger.debug("Created EmbeddedChannel with custom handler");
            } catch (Exception e) {
                // Fallback to default constructor if that doesn't work
                embeddedChannelConstructor = embeddedChannelClass.getDeclaredConstructor();
                embeddedChannel = embeddedChannelConstructor.newInstance();
                FppLogger.debug("Created EmbeddedChannel with default constructor");
            }

            // Override the channel's writeAndFlush and flush methods to handle null promises
            try {
                // Wrap the channel in a proxy that handles null promise issues
                embeddedChannel = createNullSafeChannel(embeddedChannel, embeddedChannelClass);
            } catch (Exception e) {
                Config.debug("Could not wrap channel for null safety: " + e.getMessage());
            }

            // 2. PacketFlow.SERVERBOUND
            Class<?> packetFlowClass = nmsLoader.loadClass("net.minecraft.network.protocol.PacketFlow");
            Object serverbound = packetFlowClass.getEnumConstants()[0]; // SERVERBOUND

            // 3. Create Connection subclass that handles null promises gracefully
            Constructor<?> connCtor = connectionClass.getDeclaredConstructor(packetFlowClass);
            connCtor.setAccessible(true);
            Object conn = createNullSafeConnection(connCtor, serverbound, embeddedChannel);

            // 4.5. Inject a dummy InetSocketAddress so Connection.handleDisconnection()
            // does not NPE when the bot is kicked.
            for (Field f : getAllDeclaredFields(connectionClass)) {
                if (java.net.SocketAddress.class.isAssignableFrom(f.getType())) {
                    try {
                        f.setAccessible(true);
                        if (f.get(conn) == null) {
                            f.set(conn, new java.net.InetSocketAddress("127.0.0.1", 25565));
                            FppLogger.debug("Injected dummy InetSocketAddress into Connection." + f.getName());
                        }
                    } catch (Exception ignored) {}
                    break;
                }
            }

            // 5. CommonListenerCookie
            Object cookie = createCookieDynamic(gameProfile, clientInfo);
            if (cookie == null) {
                FppLogger.warn("Could not create CommonListenerCookie — fake connection incomplete");
                return;
            }

            // 6. ServerGamePacketListenerImpl(MinecraftServer, Connection, ServerPlayer, CommonListenerCookie)
            //    Its constructor sets player.connection = this automatically.
            for (Constructor<?> c : serverGamePacketListenerClass.getDeclaredConstructors()) {
                if (c.getParameterCount() == 4) {
                    c.setAccessible(true);
                    c.newInstance(minecraftServer, conn, serverPlayer, cookie);
                    FppLogger.debug("ServerGamePacketListenerImpl created; connection set on ServerPlayer");
                    return;
                }
            }
            FppLogger.warn("Could not find 4-arg ServerGamePacketListenerImpl constructor");

        } catch (Exception e) {
            FppLogger.warn("setupFakeConnection failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
        }
    }

    /**
     * Creates a Connection object that handles null promises gracefully to prevent Netty NPEs.
     */
    private static Object createNullSafeConnection(Constructor<?> connCtor, Object serverbound, Object embeddedChannel) throws Exception {
        // Create the Connection instance 
        Object conn = connCtor.newInstance(serverbound);

        // Inject EmbeddedChannel into the Connection's channel field
        for (Field f : getAllDeclaredFields(connectionClass)) {
            if (f.getType().getSimpleName().equals("Channel")) {
                f.setAccessible(true);
                f.set(conn, embeddedChannel);
                FppLogger.debug("Injected EmbeddedChannel into Connection." + f.getName());
                break;
            }
        }

        // Instead of proxy, let's override specific methods by wrapping the connection
        // First, let's try to override the problematic send/flush methods directly using reflection
        try {
            // Override the doSendPacket method to be a no-op
            Method doSendPacketMethod = findMethodInClass(connectionClass, "doSendPacket");
            if (doSendPacketMethod != null) {
                // We can't easily override methods without bytecode manipulation, 
                // so let's try a different approach - modify the channel itself
                FppLogger.debug("Found doSendPacket method, will rely on channel modification");
            }
        } catch (Exception e) {
            Config.debug("Could not find doSendPacket method: " + e.getMessage());
        }

        return conn;
    }

    /**
     * Find a method in a class or its superclasses by name.
     */
    private static Method findMethodInClass(Class<?> clazz, String methodName) {
        Class<?> current = clazz;
        while (current != null && current != Object.class) {
            for (Method method : current.getDeclaredMethods()) {
                if (method.getName().equals(methodName)) {
                    return method;
                }
            }
            current = current.getSuperclass();
        }
        return null;
    }

    /** Dynamically creates a {@code CommonListenerCookie} by iterating its constructors. */
    private static Object createCookieDynamic(Object gameProfile, Object clientInfo) {
        try {
            Constructor<?>[] ctors = commonListenerCookieClass.getDeclaredConstructors();

            // Log available constructors on first attempt (debug aids)
            FppLogger.info("CommonListenerCookie constructors (" + ctors.length + "):");
            for (Constructor<?> c : ctors) {
                StringBuilder sb = new StringBuilder("  [" + c.getParameterCount() + "] ");
                for (Class<?> p : c.getParameterTypes()) sb.append(p.getSimpleName()).append(", ");
                FppLogger.info(sb.toString());
            }

            for (Constructor<?> c : ctors) {
                c.setAccessible(true);
                Class<?>[] p = c.getParameterTypes();
                // Skip synthetic constructors added by the compiler (e.g. for records)
                if (p.length > 0 && p[p.length - 1].getSimpleName().contains("DefaultConstructorMarker")) continue;
                try {
                    switch (p.length) {
                        case 1 -> { return c.newInstance(gameProfile); }
                        case 2 -> { return c.newInstance(gameProfile, 0); }
                        case 3 -> { return c.newInstance(gameProfile, 0, clientInfo); }
                        case 4 -> { return c.newInstance(gameProfile, 0, clientInfo, false); }
                        case 5 -> { return c.newInstance(gameProfile, 0, clientInfo, false, false); }
                        case 7 -> {
                            // Paper 1.21.11+: (GameProfile, int, ClientInformation, boolean, String, Set, KeepAlive)
                            // Pass null for String (server address) and KeepAlive; empty Set for server cookies.
                            return c.newInstance(gameProfile, 0, clientInfo, false,
                                    null, java.util.Collections.emptySet(), null);
                        }
                    }
                } catch (Exception e) {
                    FppLogger.info("  → [" + p.length + "-arg] failed: " + e.getClass().getSimpleName() + ": " + e.getMessage());
                }
            }
        } catch (Exception e) {
            FppLogger.debug("createCookieDynamic failed: " + e.getMessage());
        }
        FppLogger.warn("createCookieDynamic: no constructor worked for CommonListenerCookie");
        return null;
    }

    /** Returns the value of {@code serverPlayer.connection} (the ServerGamePacketListenerImpl). */
    private static Object getConnectionField(Object serverPlayer) {
        try {
            for (Field f : getAllDeclaredFields(serverPlayerClass)) {
                if (serverGamePacketListenerClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(serverPlayer);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Returns the {@code Connection} object held inside a {@code ServerGamePacketListenerImpl}. */
    private static Object getConnectionFromSgpl(Object sgpl) {
        try {
            for (Field f : getAllDeclaredFields(sgpl.getClass())) {
                if (connectionClass.isAssignableFrom(f.getType())) {
                    f.setAccessible(true);
                    return f.get(sgpl);
                }
            }
        } catch (Exception ignored) {}
        return null;
    }

    /** Finds a method on a class (or its supers) by name and parameter count. */
    private static Method findMethod(Class<?> clazz, String name, int paramCount) {
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Method m : cur.getDeclaredMethods()) {
                if (m.getName().equals(name) && m.getParameterCount() == paramCount) {
                    m.setAccessible(true);
                    return m;
                }
            }
            cur = cur.getSuperclass();
        }
        return null;
    }

    /** Collects all declared fields from a class and all its superclasses. */
    private static java.util.List<Field> getAllDeclaredFields(Class<?> clazz) {
        java.util.List<Field> fields = new java.util.ArrayList<>();
        Class<?> cur = clazz;
        while (cur != null && cur != Object.class) {
            for (Field f : cur.getDeclaredFields()) fields.add(f);
            cur = cur.getSuperclass();
        }
        return fields;
    }

    /**
     * Directly sets the NMS entity's position via {@code Entity.setPos(x, y, z)}.
     *
     * <p>This bypasses client-authoritative movement — the entity's server-side
     * coordinates are updated immediately, and the entity tracker then broadcasts
     * the position change to all nearby players on its next update cycle.
     *
     * <p>Used by the manual physics loop in {@code BotCollisionListener} to move
     * NMS fake-player bots that have a fake (EmbeddedChannel) connection that
     * discards all outgoing packets, including velocity and position packets.
     */
    public static void setPosition(Player bot, double x, double y, double z) {
        if (!initialized || setPosMethod == null || craftPlayerGetHandleMethod == null) return;
        try {
            Object nmsPlayer = craftPlayerGetHandleMethod.invoke(bot);
            setPosMethod.invoke(nmsPlayer, x, y, z);
        } catch (Exception e) {
            FppLogger.debug("NmsPlayerSpawner.setPosition failed: " + e.getMessage());
        }
    }

    /**
     * Remove a fake player from the server.
     */
    public static void removeFakePlayer(Player player) {
        if (player == null) return;

        try {
            // Simply disconnect/remove the player
            player.kick(net.kyori.adventure.text.Component.empty());
        } catch (Exception e) {
            FppLogger.error("Failed to remove fake player: " + e.getMessage());
        }
    }
}

package me.bill.fakePlayerPlugin.ai;

import com.google.gson.JsonArray;
import com.google.gson.JsonObject;
import com.google.gson.JsonParser;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ThreadLocalRandom;

/**
 * Ollama provider — local/self-hosted LLM inference.
 * No API key required, just a running Ollama server.
 */
public final class OllamaProvider implements AIProvider {

    private final String endpoint;
    private final String configuredModel;
    private List<String> availableModels = null;

    public OllamaProvider(String endpoint, String model) {
        this.endpoint = endpoint.endsWith("/") ? endpoint : endpoint + "/";
        this.configuredModel = model;
    }

    @Override
    public String getName() {
        return "Ollama (Local)";
    }

    @Override
    public boolean isAvailable() {
        return endpoint != null && !endpoint.isBlank();
    }

    /**
     * Fetch available models from Ollama server.
     */
    private List<String> fetchAvailableModels() {
        try {
            URL url = new URL(endpoint + "api/tags");
            HttpURLConnection conn = (HttpURLConnection) url.openConnection();
            conn.setRequestMethod("GET");
            conn.setConnectTimeout(3000);
            conn.setReadTimeout(5000);

            int responseCode = conn.getResponseCode();
            if (responseCode != 200) {
                return List.of("llama2"); // Fallback
            }

            StringBuilder response = new StringBuilder();
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(conn.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = br.readLine()) != null) {
                    response.append(line);
                }
            }

            JsonObject json = JsonParser.parseString(response.toString()).getAsJsonObject();
            JsonArray models = json.getAsJsonArray("models");

            List<String> modelNames = new ArrayList<>();
            if (models != null) {
                for (int i = 0; i < models.size(); i++) {
                    JsonObject modelObj = models.get(i).getAsJsonObject();
                    String name = modelObj.get("name").getAsString();
                    modelNames.add(name);
                }
            }

            return modelNames.isEmpty() ? List.of("llama2") : modelNames;
        } catch (Exception e) {
            return List.of("llama2"); // Fallback
        }
    }

    /**
     * Select a model for this request.
     * If configuredModel is blank, randomly select from available models on the Ollama server.
     */
    private String selectModel() {
        if (configuredModel != null && !configuredModel.isBlank()) {
            return configuredModel;
        }

        // Lazy load available models
        if (availableModels == null) {
            availableModels = fetchAvailableModels();
        }

        // Random selection
        if (availableModels.isEmpty()) {
            return "llama2"; // Ultimate fallback
        }
        int index = ThreadLocalRandom.current().nextInt(availableModels.size());
        return availableModels.get(index);
    }

    @Override
    public CompletableFuture<String> generateResponse(
            List<ChatMessage> messages,
            String botName,
            String personality
    ) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                String model = selectModel();

                JsonObject requestBody = new JsonObject();
                requestBody.addProperty("model", model);
                requestBody.addProperty("stream", false);

                JsonArray messagesArray = new JsonArray();

                if (personality != null && !personality.isBlank()) {
                    JsonObject systemMsg = new JsonObject();
                    systemMsg.addProperty("role", "system");
                    systemMsg.addProperty("content", personality);
                    messagesArray.add(systemMsg);
                }

                for (ChatMessage msg : messages) {
                    JsonObject msgObj = new JsonObject();
                    msgObj.addProperty("role", msg.role());
                    msgObj.addProperty("content", msg.content());
                    messagesArray.add(msgObj);
                }

                requestBody.add("messages", messagesArray);

                // Options
                JsonObject options = new JsonObject();
                options.addProperty("temperature", 0.9);
                options.addProperty("num_predict", 150);
                requestBody.add("options", options);

                URL url = new URL(endpoint + "api/chat");
                HttpURLConnection conn = (HttpURLConnection) url.openConnection();
                conn.setRequestMethod("POST");
                conn.setRequestProperty("Content-Type", "application/json");
                conn.setDoOutput(true);
                conn.setConnectTimeout(5000);
                conn.setReadTimeout(30000);

                try (OutputStream os = conn.getOutputStream()) {
                    os.write(requestBody.toString().getBytes(StandardCharsets.UTF_8));
                }

                int responseCode = conn.getResponseCode();
                if (responseCode != 200) {
                    throw new RuntimeException("Ollama API error: HTTP " + responseCode);
                }

                StringBuilder response = new StringBuilder();
                try (BufferedReader br = new BufferedReader(
                        new InputStreamReader(conn.getInputStream(), StandardCharsets.UTF_8))) {
                    String line;
                    while ((line = br.readLine()) != null) {
                        response.append(line);
                    }
                }

                JsonObject json = JsonParser.parseString(response.toString()).getAsJsonObject();
                return json.getAsJsonObject("message")
                        .get("content").getAsString().trim();

            } catch (Exception e) {
                throw new RuntimeException("Ollama generation failed: " + e.getMessage(), e);
            }
        });
    }
}

