:: ============================================================ :: FPP Obfuscation Script :: :: USAGE: :: 1. Drop fpp.jar into this folder (build\) :: 2. Double-click this file -OR- run it from a terminal :: 3. Obfuscated JAR is written to: build\output\fpp-obfuscated.jar :: :: REQUIREMENTS: :: - JDK 17 installed (ProGuard bundled jar crashes on JDK 25+) :: - libs\proguard\proguard.jar (org.json is bundled inside it) :: :: Override JDK path: :: set JAVA_EXE=C:\path\to\jdk-17\bin\java.exe :: set JDK17_HOME=C:\path\to\jdk-17 :: obfuscate.bat :: ============================================================
:: ── Resolve directories ────────────────────────────────────── set "SCRIPT_DIR=%~dp0" for %%I in ("%SCRIPT_DIR%..") do set "PROJECT_DIR=%%~fI"
set "INPUT_JAR=%SCRIPT_DIR%fpp.jar" set "OUTPUT_DIR=%SCRIPT_DIR%output" set "OUTPUT_JAR=%OUTPUT_DIR%\fpp-obfuscated.jar"
set "PROGUARD_DIR=%PROJECT_DIR%\libs\proguard" set "PROGUARD_CONF=%PROGUARD_DIR%\fpp.conf" set "PROGUARD_JAR=%PROGUARD_DIR%\proguard.jar"
if not defined JAVA_EXE set "JAVA_EXE=C:\Program Files\Java\jdk-17\bin\java.exe" if not defined JDK17_HOME set "JDK17_HOME=C:\Program Files\Java\jdk-17"
:: ── Banner ─────────────────────────────────────────────────── echo. echo ============================================================ echo FakePlayerPlugin ^| ProGuard Obfuscation echo ============================================================ echo. echo Input : %INPUT_JAR% echo Output : %OUTPUT_JAR% echo JDK 17 : %JAVA_EXE% echo.
:: ── Pre-flight checks ──────────────────────────────────────── if not exist "%JAVA_EXE%" ( echo [ERROR] JDK 17 not found: %JAVA_EXE% echo Set JAVA_EXE=^<path^> before running this script. echo. pause & exit /b 1 )
if not exist "%INPUT_JAR%" ( echo [ERROR] Input JAR not found: %INPUT_JAR% echo Place fpp.jar in the build\ folder first. echo. pause & exit /b 1 )
if not exist "%PROGUARD_JAR%" ( echo [ERROR] ProGuard JAR not found: %PROGUARD_JAR% echo Expected: libs\proguard\proguard.jar echo. pause & exit /b 1 )
if not exist "%PROGUARD_CONF%" ( echo [ERROR] ProGuard config not found: %PROGUARD_CONF% echo. pause & exit /b 1 )
if not exist "%JDK17_HOME%\jmods\java.base.jmod" ( echo [ERROR] java.base.jmod not found under: %JDK17_HOME%\jmods\ echo Check JDK17_HOME points to a full JDK 17 installation. echo. pause & exit /b 1 )
:: ── Prepare output directory ───────────────────────────────── if not exist "%OUTPUT_DIR%" mkdir "%OUTPUT_DIR%"
:: Remove stale output from a previous run so ProGuard doesn't complain. if exist "%OUTPUT_JAR%" del /f /q "%OUTPUT_JAR%"
:: ── Run ProGuard ───────────────────────────────────────────── echo [1/3] Running ProGuard (MySQL + SQLite excluded from -injars)... echo.
"%JAVA_EXE%" ^ -cp "%PROGUARD_JAR%" ^ proguard.ProGuard ^ "@%PROGUARD_CONF%" ^ -libraryjars "%JDK17_HOME%\jmods\java.base.jmod(!**.jar;!module-info.class)" ^ -injars "%INPUT_JAR%(!com/mysql/**,!org/sqlite/**)" ^ -outjars "%OUTPUT_JAR%"
if %ERRORLEVEL% neq 0 ( echo. echo [ERROR] ProGuard failed ^(exit code %ERRORLEVEL%^). echo Check the output above for details. echo. pause & exit /b %ERRORLEVEL% )
:: ── Merge MySQL + SQLite back into the obfuscated JAR ──────── :: ProGuard cannot preverify MySQL/SQLite internals without the full JDK :: type hierarchy, so they were excluded from -injars above and must be :: merged back verbatim from the original (already-verified) JAR. echo. echo [2/3] Merging MySQL + SQLite classes back into obfuscated JAR...
set "MERGE_TMP=%TEMP%\fpp_merge_%RANDOM%" mkdir "%MERGE_TMP%"
:: Extract MySQL + SQLite from the original jar into a temp folder. pushd "%MERGE_TMP%" "%JDK17_HOME%\bin\jar.exe" xf "%INPUT_JAR%" popd
if exist "%MERGE_TMP%\com\mysql" ( "%JDK17_HOME%\bin\jar.exe" uf "%OUTPUT_JAR%" -C "%MERGE_TMP%" com/mysql if %ERRORLEVEL% neq 0 ( echo [WARN] Failed to merge MySQL classes — continuing anyway. ) )
if exist "%MERGE_TMP%\org\sqlite" ( "%JDK17_HOME%\bin\jar.exe" uf "%OUTPUT_JAR%" -C "%MERGE_TMP%" org/sqlite if %ERRORLEVEL% neq 0 ( echo [WARN] Failed to merge SQLite classes — continuing anyway. ) )
rmdir /s /q "%MERGE_TMP%"
:: ── Done ───────────────────────────────────────────────────── echo. echo [3/3] Done! echo. echo Output: %OUTPUT_JAR% echo. pause

/**
 * Online stats API endpoint
 * Returns the count of servers and users currently using FPP
 *
 * TODO: Implement real tracking when ready:
 * - Track server heartbeats in a database (MySQL/Redis)
 * - Count active servers (last seen within 5 minutes)
 * - Sum player counts from all active servers
 */

module.exports = async (req, res) => {
  // Set CORS headers (public endpoint)
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Content-Type', 'application/json');

  // Handle OPTIONS for CORS preflight
  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  // Demo data for testing the count-up animation
  // Change to null to show "---"
  res.status(200).json({
    servers: 200,   // Shows "200+" on frontend
    users: 630,     // Shows "630+" on frontend
    timestamp: new Date().toISOString()
  });

  /*
   * Example implementation with database tracking:
   *
   * const db = require('./db-connection');
   *
   * const activeServers = await db.query(`
   *   SELECT COUNT(DISTINCT server_id) as count
   *   FROM server_heartbeats
   *   WHERE last_seen > NOW() - INTERVAL 5 MINUTE
   * `);
   *
   * const totalPlayers = await db.query(`
   *   SELECT SUM(player_count) as total
   *   FROM server_heartbeats
   *   WHERE last_seen > NOW() - INTERVAL 5 MINUTE
   * `);
   *
   * res.status(200).json({
   *   servers: activeServers[0].count || 0,
   *   users: totalPlayers[0].total || 0,
   *   timestamp: new Date().toISOString()
   * });
   */
};

